func (am *AgentManager) latestPromptPackActivationEventRecord(requestID, versionID string) (PromptPackActivationEventRecord, error) {
	var row models.PromptPackActivationEvent
	err := am.db.Where("activation_request_id = ? AND prompt_pack_version_id = ?", requestID, versionID).
		Order("created_at DESC").
		Order("id DESC").
		First(&row).Error
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return PromptPackActivationEventRecord{}, fmt.Errorf("prompt pack activation event not found")
		}
		return PromptPackActivationEventRecord{}, err
	}
	return promptPackActivationEventRecordFromRow(row), nil
}

func (am *AgentManager) markPromptPackActivationRequestActive(row models.PromptPackActivationRequest) (models.PromptPackActivationRequest, error) {
	if row.Status == string(PromptPackActivationActive) {
		return row, nil
	}
	row.Status = string(PromptPackActivationActive)
	row.PromptMutated = false
	if err := am.db.Save(&row).Error; err != nil {
		return row, err
	}
	return row, nil
}

func benchmarkPromptImprovementProposalChecks(proposal PromptImprovementProposal) []PromptProposalBenchmarkResult {
	results := []PromptProposalBenchmarkResult{
		{
			Name:     "approved_human_review",
			Status:   promptProposalCheckStatus(proposal.ReviewState == PromptProposalReviewApproved),
			Summary:  "Proposal must be approved before benchmark-gated adoption can continue.",
			Evidence: string(proposal.ReviewState),
			Required: true,
		},
		{
			Name:     "evidence_present",
			Status:   promptProposalCheckStatus(len(proposal.Evidence) > 0),
			Summary:  "Proposal must cite historical failure evidence.",
			Evidence: strings.Join(limitStrings(proposal.Evidence, 3), "; "),
			Required: true,
		},
		{
			Name:     "benchmark_gate_declared",
			Status:   promptProposalCheckStatus(strings.TrimSpace(proposal.BenchmarkGate) != ""),
			Summary:  "Proposal must declare the benchmark family required before adoption.",
			Evidence: strings.TrimSpace(proposal.BenchmarkGate),
			Required: true,
		},
		{
			Name:     "supported_target_prompt",
			Status:   promptProposalCheckStatus(promptProposalTargetPromptSupported(proposal.TargetPrompt)),
			Summary:  "Proposal target must map to a known prompt surface before adoption can be stored.",
			Evidence: strings.TrimSpace(proposal.TargetPrompt),
			Required: true,
		},
		{
			Name:     "no_automatic_prompt_mutation",
			Status:   "passed",
			Summary:  "Benchmark recording is metadata-only and does not rewrite prompt source.",
			Required: true,
		},
	}
	return results
}

func promptProposalCheckStatus(ok bool) string {
	if ok {
		return "passed"
	}
	return "failed"
}

func promptProposalTargetPromptSupported(target string) bool {
	switch strings.TrimSpace(target) {
	case "war_room_contract_planning",
		"preview_repair",
		"compile_repair",
		"interaction_canary",
		"visual_review",
		"auth_contract",
		"data_contract",
		"general_reliability":
		return true
	default:
		return false
	}
}

func markPatchBundleReviewed(build *Build, bundleID string, status PatchBundleReviewStatus, reason string, applied bool) PatchBundle {
	build.mu.Lock()
	defer build.mu.Unlock()

	now := time.Now().UTC()
	state := ensureBuildOrchestrationStateLocked(build)
	if state == nil {
		return PatchBundle{}
	}

	for i := range state.PatchBundles {
		if strings.TrimSpace(state.PatchBundles[i].ID) != bundleID {
			continue
		}
		state.PatchBundles[i].ReviewStatus = status
		state.PatchBundles[i].ReviewedAt = &now
		message := strings.TrimSpace(reason)
		if message == "" {
			switch status {
			case PatchBundleReviewApproved:
				if applied {
					message = "Approved and applied by user review."
				} else {
					message = "Approved by user review; patch was already reflected in the build output."
				}
			case PatchBundleReviewRejected:
				message = "Rejected by user review."
			}
		}
		state.PatchBundles[i].ReviewMessage = message
		removePatchBundlePendingRevisionLocked(build, state.PatchBundles[i])
		appendSteeringNoteLocked(build, fmt.Sprintf("Patch bundle %s %s by user review.", bundleID, status))
		refreshInteractionAttentionLocked(build)
		build.UpdatedAt = now
		return state.PatchBundles[i]
	}
	return PatchBundle{}
}

func removePatchBundlePendingRevisionLocked(build *Build, bundle PatchBundle) {
	if build == nil || len(build.Interaction.PendingRevisions) == 0 {
		return
	}
	reviewBranch := strings.TrimSpace(bundle.ReviewBranch)
	justification := strings.TrimSpace(bundle.Justification)
	filtered := build.Interaction.PendingRevisions[:0]
	for _, note := range build.Interaction.PendingRevisions {
		trimmed := strings.TrimSpace(note)
		if trimmed == "" {
			continue
		}
		if reviewBranch != "" && strings.Contains(trimmed, reviewBranch) {
			continue
		}
		if justification != "" && strings.Contains(trimmed, justification) {
			continue
		}
		filtered = append(filtered, note)
	}
	build.Interaction.PendingRevisions = filtered
}

func (am *AgentManager) resumeBuildIfReviewComplete(build *Build) {
	if build == nil {
		return
	}
	build.mu.Lock()
	state := ensureBuildOrchestrationStateLocked(build)
	hasPendingPatchReview := false
	if state != nil {
		for _, bundle := range state.PatchBundles {
			if patchBundleReviewPending(bundle) {
				hasPendingPatchReview = true
				break
			}
		}
	}
	status := build.Status
	build.mu.Unlock()

	hasPendingEdits := false
	if am != nil && am.editStore != nil {
		hasPendingEdits = len(am.editStore.GetPendingEdits(build.ID)) > 0
	}
	if status == BuildAwaitingReview && !hasPendingPatchReview && !hasPendingEdits {
		am.resumeBuildAfterReview(build)
	}
}

func (am *AgentManager) bundleFromPatchPlan(buildID string, before []GeneratedFile, plan *generatedFilePatchPlan, justification string) *PatchBundle {
	if plan == nil {
		return nil
	}
	return buildPatchBundleFromFileDiff(buildID, justification, before, plan.files())
}

func (am *AgentManager) buildGeneratedFilePatchPlan(build *Build) ([]GeneratedFile, *generatedFilePatchPlan) {
	files := am.collectGeneratedFiles(build)
	return files, newGeneratedFilePatchPlan(files)
}

func (am *AgentManager) applyDeterministicManifestDependencyRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}
	frontendPkgs, backendPkgs := parseMissingDependenciesByVerificationScope(readinessErrors)
	if len(frontendPkgs) == 0 && len(backendPkgs) == 0 {
		return nil, ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 {
		return nil, ""
	}

	frontendCandidates := []string{
		"frontend/package.json",
		"client/package.json",
		"web/package.json",
		"apps/web/package.json",
		"apps/frontend/package.json",
		"packages/web/package.json",
		"packages/frontend/package.json",
		"package.json",
	}
	backendCandidates := []string{
		"backend/package.json",
		"api/package.json",
		"server/package.json",
		"apps/api/package.json",
		"apps/server/package.json",
		"packages/backend/package.json",
		"packages/api/package.json",
		"package.json",
	}

	type req struct {
		path string
		pkgs []string
		role string
	}
	reqs := make([]req, 0, 2)
	if len(frontendPkgs) > 0 {
		if p := findGeneratedManifestPath(files, frontendCandidates); p != "" {
			reqs = append(reqs, req{path: p, pkgs: frontendPkgs, role: "frontend"})
		}
	}
	if len(backendPkgs) > 0 {
		if p := findGeneratedManifestPath(files, backendCandidates); p != "" {
			mergedIntoExisting := false
			for i := range reqs {
				if strings.EqualFold(reqs[i].path, p) {
					reqs[i].pkgs = append(reqs[i].pkgs, backendPkgs...)
					reqs[i].role = "frontend/backend"
					mergedIntoExisting = true
					break
				}
			}
			if !mergedIntoExisting {
				reqs = append(reqs, req{path: p, pkgs: backendPkgs, role: "backend"})
			}
		}
	}
	if len(reqs) == 0 {
		return nil, ""
	}

	applied := false
	summaries := make([]string, 0, len(reqs))
	for _, r := range reqs {
		content := plan.content(r.path)
		if strings.TrimSpace(content) == "" {
			continue
		}
		pkgs := append([]string(nil), r.pkgs...)
		var manifest previewManifest
		if err := json.Unmarshal([]byte(content), &manifest); err == nil {
			if manifest.Scripts == nil {
				manifest.Scripts = map[string]string{}
			}
			pkgs = missingManifestDependenciesForGeneratedFiles(files, r.path, manifest, pkgs)
		}
		updated, added := patchManifestDependenciesJSON(content, pkgs)
		if len(added) == 0 {
			continue
		}
		if !plan.patchFile(r.path, updated, "json") {
			continue
		}
		applied = true
		summaries = append(summaries, fmt.Sprintf("%s %s (%s)", r.role, r.path, strings.Join(added, ", ")))
	}
	if !applied {
		return nil, ""
	}
	summary := strings.Join(summaries, "; ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "manifest_repair: "+summary), summary
}

func generatedManifestDependencyClosureCandidates() []string {
	return []string{
		"frontend/package.json",
		"client/package.json",
		"web/package.json",
		"apps/web/package.json",
		"apps/frontend/package.json",
		"packages/web/package.json",
		"packages/frontend/package.json",
		"backend/package.json",
		"api/package.json",
		"server/package.json",
		"apps/api/package.json",
		"apps/server/package.json",
		"packages/backend/package.json",
		"packages/api/package.json",
		"package.json",
	}
}

func generatedManifestTypeCompanionDependencies(manifest previewManifest) []string {
	missing := make([]string, 0, 2)
	add := func(pkg string) {
		pkg = canonicalGeneratedDependencyName(pkg)
		if pkg == "" || manifestDeclaresDependency(manifest, pkg) {
			return
		}
		missing = append(missing, pkg)
	}

	// Recharts v2 declaration files reference lodash types. Without @types/lodash,
	// generated Vite/TS builds can pass dependency closure but fail at 97% during
	// preview verification on node_modules/recharts/**/*.d.ts.
	if manifestDeclaresDependency(manifest, "recharts") {
		add("@types/lodash")
	}

	return dedupeStringsPreserveOrder(missing)
}

func (am *AgentManager) ensureGeneratedManifestDependencyClosure(build *Build, files []GeneratedFile) (bool, string) {
	if build == nil || len(files) == 0 {
		return false, ""
	}

	before, plan := am.buildGeneratedFilePatchPlan(build)
	if len(before) == 0 || plan == nil {
		return false, ""
	}

	changed := false
	summaries := make([]string, 0, 2)
	seenManifest := map[string]bool{}
	for _, manifestPath := range generatedManifestDependencyClosureCandidates() {
		manifestPath = sanitizeFilePath(manifestPath)
		if manifestPath == "" || seenManifest[manifestPath] {
			continue
		}
		seenManifest[manifestPath] = true

		content := plan.content(manifestPath)
		if strings.TrimSpace(content) == "" {
			continue
		}
		var manifest previewManifest
		if err := json.Unmarshal([]byte(content), &manifest); err != nil {
			continue
		}

		missing := missingManifestDependenciesForGeneratedFiles(plan.files(), manifestPath, manifest, nil)
		missing = append(missing, generatedManifestTypeCompanionDependencies(manifest)...)
		missing = dedupeStringsPreserveOrder(missing)
		if len(missing) == 0 {
			continue
		}

		updated, added := patchManifestDependenciesJSON(content, missing)
		if len(added) == 0 {
			continue
		}
		if !plan.patchFile(manifestPath, updated, "json") {
			continue
		}
		changed = true
		summaries = append(summaries, fmt.Sprintf("%s (%s)", manifestPath, strings.Join(added, ", ")))
	}

	if !changed {
		return false, ""
	}

	bundle := am.bundleFromPatchPlan(build.ID, before, plan, "pre_validation_dependency_closure: "+strings.Join(summaries, "; "))
	if bundle == nil || !am.applyPatchBundleToBuild(build, bundle) {
		return false, ""
	}

	build.mu.Lock()
	orchestration := ensureBuildOrchestrationStateLocked(build)
	recordPatchBundles := orchestration != nil && orchestration.Flags.EnablePatchBundles
	build.mu.Unlock()
	if recordPatchBundles {
		appendPatchBundle(build, *bundle)
	}

	return true, strings.Join(summaries, "; ")
}

func normalizePreviewSyntaxErrorPath(raw string) string {
	cleaned := strings.TrimSpace(strings.Trim(raw, `"'`))
	if cleaned == "" {
		return ""
	}
	cleaned = strings.TrimPrefix(cleaned, "file://")
	cleaned = strings.TrimPrefix(cleaned, "file:")
	cleaned = strings.ReplaceAll(cleaned, "\\", "/")
	cleaned = strings.TrimPrefix(cleaned, "./")
	if path := sanitizeFilePath(cleaned); path != "" {
		return path
	}

	roots := []string{
		"src/",
		"server/",
		"backend/",
		"frontend/",
		"apps/",
		"packages/",
		"public/",
	}
	best := ""
	for _, root := range roots {
		candidate := ""
		if strings.HasPrefix(cleaned, root) {
			candidate = cleaned
		} else if idx := strings.Index(cleaned, "/"+root); idx != -1 {
			candidate = cleaned[idx+1:]
		}
		if candidate == "" {
			continue
		}
		if path := sanitizeFilePath(candidate); path != "" && (best == "" || len(path) < len(best)) {
			best = path
		}
	}
	return best
}

func parsePreviewSyntaxErrorTargetFiles(errors []string) []string {
	if len(errors) == 0 {
		return nil
	}
	joined := strings.Join(errors, "\n")
	syntaxSignals := []string{
		// TypeScript compiler errors
		"TS1002",
		"TS1005",
		"TS1003",
		"TS1009",
		"TS1128",
		"TS1161",
		// esbuild / Vite transform errors (Case E — previously missed)
		"Transform failed",
		"Unterminated string literal",
		"Unterminated template literal",
		"Unexpected end of file",
		"Unexpected end of input",
		"Unexpected token",
		"Syntax error",
		"ERROR:",
		// Vite-specific
		"[vite] Internal server error",
		"Failed to parse source",
		"Could not resolve",
		// Rollup (used by Vite build)
		"Parsing error",
		"SyntaxError:",
	}
	hasSignal := false
	for _, signal := range syntaxSignals {
		if strings.Contains(joined, signal) {
			hasSignal = true
			break
		}
	}
	lower := strings.ToLower(joined)
	if !hasSignal &&
		!strings.Contains(lower, "ends abruptly") &&
		!strings.Contains(lower, "missing closing brace") &&
		!strings.Contains(lower, "abrupt eof") &&
		!strings.Contains(lower, "unterminated") &&
		!strings.Contains(lower, "unexpected token") {
		return nil
	}

	seen := map[string]bool{}
	paths := make([]string, 0, 4)
	patterns := []*regexp.Regexp{
		// TypeScript compiler: file(line,col): error TSxxxx
		regexp.MustCompile(`(?m)([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx))\(\d+,\d+\): error TS\d+\b`),
		// esbuild: file:line:col: ERROR: message
		regexp.MustCompile(`(?m)(?:^|[\s([])([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx)):\d+:\d+:\s+ERROR:\s+.+`),
		// esbuild/Vite: x [ERROR] message \n\n    file:line:col:
		regexp.MustCompile(`(?m)^\s{2,}([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx)):\d+:\d+:`),
		// Vite internal error: Plugin vite:xxx — file
		regexp.MustCompile(`(?m)Plugin vite:\S+\s+\S.*?([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx)):\d+`),
		// Rollup/Vite: SyntaxError at file:line
		regexp.MustCompile(`(?m)SyntaxError[^(]*\(([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx)):\d+:\d+\)`),
		// Generic: file: <pos>
		regexp.MustCompile(`(?m)file:\s*([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx)):\d+:\d+`),
		// "file ends abruptly" variants
		regexp.MustCompile(`(?i)(?:the file\s+)?([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx))\s+ends abruptly`),
		regexp.MustCompile(`(?i)([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx)).*missing closing brace`),
		regexp.MustCompile(`(?i)([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx)).*abrupt eof`),
		// "Could not resolve" import errors — the importing file needs repair
		regexp.MustCompile(`(?m)Could not resolve[^"]*"[^"]+"\s+from\s+"([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx))"`),
		// Parsing error in file
		regexp.MustCompile(`(?m)Parsing error.*?([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx)):\d+`),
	}
	for _, re := range patterns {
		for _, m := range re.FindAllStringSubmatch(joined, -1) {
			if len(m) != 2 {
				continue
			}
			path := normalizePreviewSyntaxErrorPath(m[1])
			if path == "" || seen[path] {
				continue
			}
			seen[path] = true
			paths = append(paths, path)
		}
	}
	sort.Strings(paths)
	return paths
}

func parsePreviewJSXInTSRepairTargets(errors []string) []string {
	if len(errors) == 0 {
		return nil
	}
	joined := strings.Join(errors, "\n")
	lower := strings.ToLower(joined)
	if !strings.Contains(lower, `expected ">" but found`) {
		return nil
	}

	patterns := []*regexp.Regexp{
		regexp.MustCompile(`(?m)(src/[A-Za-z0-9_./-]+\.(?:ts|js)):\d+:\d+:\s+ERROR:\s+Expected\s+">"\s+but found\s+"[^"]+"`),
		regexp.MustCompile(`(?m)([A-Za-z0-9_./-]+\.(?:ts|js)):\d+:\d+:\s+ERROR:\s+Expected\s+">"\s+but found\s+"[^"]+"`),
	}

	seen := map[string]bool{}
	paths := make([]string, 0, 2)
	for _, pattern := range patterns {
		for _, match := range pattern.FindAllStringSubmatch(joined, -1) {
			if len(match) != 2 {
				continue
			}
			p := sanitizeFilePath(strings.TrimSpace(match[1]))
			if p == "" || seen[p] {
				continue
			}
			seen[p] = true
			paths = append(paths, p)
		}
	}
	sort.Strings(paths)
	return paths
}

type duplicateDeclarationRepairTarget struct {
	Path    string
	Symbols []string
}

func parseDuplicateDeclarationRepairTargets(errors []string) []duplicateDeclarationRepairTarget {
	if len(errors) == 0 {
		return nil
	}

	joined := strings.Join(errors, "\n")
	lower := strings.ToLower(joined)
	if !strings.Contains(lower, "already been declared") &&
		!strings.Contains(lower, "cannot redeclare block-scoped variable") &&
		!strings.Contains(lower, "duplicate identifier") {
		return nil
	}

	patterns := []*regexp.Regexp{
		regexp.MustCompile(`(?m)([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx)):\d+:\d+:\s+ERROR:\s+The symbol "([^"]+)" has already been declared`),
		regexp.MustCompile(`(?m)([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx))\(\d+,\d+\): error TS(?:2300|2451): (?:Duplicate identifier|Cannot redeclare block-scoped variable) ['"]?([^'"\n]+)['"]?`),
	}

	symbolsByPath := make(map[string]map[string]bool)
	for _, pattern := range patterns {
		for _, match := range pattern.FindAllStringSubmatch(joined, -1) {
			if len(match) != 3 {
				continue
			}
			path := normalizePreviewSyntaxErrorPath(match[1])
			symbol := sanitizeGeneratedIdentifier(match[2])
			if path == "" || symbol == "" {
				continue
			}
			pathSymbols := symbolsByPath[path]
			if pathSymbols == nil {
				pathSymbols = make(map[string]bool)
				symbolsByPath[path] = pathSymbols
			}
			pathSymbols[symbol] = true
		}
	}

	if len(symbolsByPath) == 0 {
		return nil
	}

	paths := make([]string, 0, len(symbolsByPath))
	for path := range symbolsByPath {
		paths = append(paths, path)
	}
	sort.Strings(paths)

	targets := make([]duplicateDeclarationRepairTarget, 0, len(paths))
	for _, path := range paths {
		symbolSet := symbolsByPath[path]
		symbols := make([]string, 0, len(symbolSet))
		for symbol := range symbolSet {
			symbols = append(symbols, symbol)
		}
		sort.Strings(symbols)
		targets = append(targets, duplicateDeclarationRepairTarget{
			Path:    path,
			Symbols: symbols,
		})
	}
	return targets
}

func parseTruncatedGeneratedTestRepairTargets(errors []string) []string {
	if len(errors) == 0 {
		return nil
	}
	joined := strings.Join(errors, "\n")
	lower := strings.ToLower(joined)
	if !strings.Contains(lower, "ends abruptly") &&
		!strings.Contains(lower, "missing closing brace") &&
		!strings.Contains(lower, "abrupt eof") &&
		!strings.Contains(lower, "unterminated") {
		return nil
	}

	patterns := []*regexp.Regexp{
		regexp.MustCompile(`(?i)(?:the file\s+)?([A-Za-z0-9_./-]+\.(?:ts|tsx|js|jsx))\s+ends abruptly`),
		regexp.MustCompile(`(?i)truncated source in\s+([A-Za-z0-9_./-]+\.(?:ts|tsx|js|jsx))`),
		regexp.MustCompile(`(?i)([A-Za-z0-9_./-]+\.(?:ts|tsx|js|jsx)).*missing closing brace`),
		regexp.MustCompile(`(?i)([A-Za-z0-9_./-]+\.(?:ts|tsx|js|jsx)).*abrupt eof`),
		regexp.MustCompile(`(?i)([A-Za-z0-9_./-]+\.(?:ts|tsx|js|jsx)).*unterminated`),
	}

	seen := map[string]bool{}
	paths := make([]string, 0, 2)
	for _, pattern := range patterns {
		for _, match := range pattern.FindAllStringSubmatch(joined, -1) {
			if len(match) != 2 {
				continue
			}
			p := sanitizeFilePath(strings.TrimSpace(match[1]))
			if p == "" || !isTestFile(p) || seen[p] {
				continue
			}
			seen[p] = true
			paths = append(paths, p)
		}
	}
	sort.Strings(paths)
	return paths
}

func placeholderGeneratedTestFileContent(path string) string {
	ext := strings.ToLower(filepath.Ext(path))
	if ext == ".ts" || ext == ".tsx" {
		return strings.TrimSpace(`/* Auto-repaired truncated generated verification file. */
const __apexGlobal: any = globalThis;
const __apexDescribe = typeof __apexGlobal.describe === "function" ? __apexGlobal.describe : null;
const __apexTest = typeof __apexGlobal.it === "function"
  ? __apexGlobal.it
  : typeof __apexGlobal.test === "function"
    ? __apexGlobal.test
    : null;
const __apexExpect = typeof __apexGlobal.expect === "function" ? __apexGlobal.expect : null;

if (__apexDescribe && __apexTest) {
  __apexDescribe("generated verification placeholder", () => {
    __apexTest("remains syntactically valid after truncation repair", () => {
      if (__apexExpect) {
        __apexExpect(true).toBe(true);
      }
    });
  });
}
`) + "\n"
	}

	return strings.TrimSpace(`/* Auto-repaired truncated generated verification file. */
const __apexGlobal = globalThis;
const __apexDescribe = typeof __apexGlobal.describe === "function" ? __apexGlobal.describe : null;
const __apexTest = typeof __apexGlobal.it === "function"
  ? __apexGlobal.it
  : typeof __apexGlobal.test === "function"
    ? __apexGlobal.test
    : null;
const __apexExpect = typeof __apexGlobal.expect === "function" ? __apexGlobal.expect : null;

if (__apexDescribe && __apexTest) {
  __apexDescribe("generated verification placeholder", () => {
    __apexTest("remains syntactically valid after truncation repair", () => {
      if (__apexExpect) {
        __apexExpect(true).toBe(true);
      }
    });
  });
}
`) + "\n"
}

func (am *AgentManager) applyDeterministicProviderBlockedTestRepair(build *Build, output *TaskOutput, blockers []string) (bool, string) {
	if output == nil || len(blockers) == 0 {
		return false, ""
	}

	appliedSummaries := make([]string, 0, 2)
	targets := parseTruncatedGeneratedTestRepairTargets(blockers)
	if len(targets) > 0 && len(output.Files) > 0 {
		targetSet := make(map[string]bool, len(targets))
		for _, target := range targets {
			targetSet[strings.ToLower(target)] = true
		}

		applied := make([]string, 0, len(targets))
		presentTargets := make(map[string]bool, len(targets))
		for i := range output.Files {
			path := sanitizeFilePath(strings.TrimSpace(output.Files[i].Path))
			if path == "" || !targetSet[strings.ToLower(path)] {
				continue
			}
			presentTargets[strings.ToLower(path)] = true
			output.Files[i].Content = placeholderGeneratedTestFileContent(path)
			output.Files[i].Size = int64(len(output.Files[i].Content))
			if strings.TrimSpace(output.Files[i].Language) == "" {
				output.Files[i].Language = am.detectLanguage(path)
			}
			applied = append(applied, path)
		}
		if len(applied) > 0 {
			if len(output.TruncatedFiles) > 0 {
				filtered := make([]string, 0, len(output.TruncatedFiles))
				for _, path := range output.TruncatedFiles {
					if !targetSet[strings.ToLower(strings.TrimSpace(path))] {
						filtered = append(filtered, path)
					}
				}
				output.TruncatedFiles = filtered
			}
			sort.Strings(applied)
			appliedSummaries = append(appliedSummaries, "placeholder tests: "+strings.Join(applied, ", "))
		}
		missingTargets := make([]string, 0, len(targets))
		for _, target := range targets {
			if !presentTargets[strings.ToLower(target)] {
				missingTargets = append(missingTargets, target)
			}
		}
		if len(missingTargets) > 0 {
			sort.Strings(missingTargets)
			appliedSummaries = append(appliedSummaries, "cleared stale truncated test blockers: "+strings.Join(missingTargets, ", "))
		}
	}

	if repaired, summary := am.applyDeterministicProviderBlockedTestingManifestRepair(build, output, blockers); repaired {
		appliedSummaries = append(appliedSummaries, summary)
	}
	if repaired, summary := am.applyDeterministicProviderBlockedTSConfigRepair(output, blockers); repaired {
		appliedSummaries = append(appliedSummaries, summary)
	}

	if len(appliedSummaries) == 0 {
		return false, ""
	}

	summary := strings.Join(appliedSummaries, "; ")
	output.Messages = append(output.Messages, "Applied deterministic provider-blocked test repair: "+summary)
	return true, summary
}

func parseProviderBlockedTSConfigTargets(blockers []string) []string {
	if len(blockers) == 0 {
		return nil
	}

	targets := make([]string, 0, 1)
	for _, blocker := range blockers {
		lower := strings.ToLower(blocker)
		if !strings.Contains(lower, "tsconfig") || !strings.Contains(lower, "json") {
			continue
		}
		if strings.Contains(lower, "comments") ||
			strings.Contains(lower, "invalid json syntax") ||
			(strings.Contains(lower, "json syntax") && strings.Contains(lower, "compilation")) {
			targets = append(targets, "tsconfig.json")
		}
	}
	return dedupeStrings(targets)
}

func (am *AgentManager) applyDeterministicProviderBlockedTSConfigRepair(output *TaskOutput, blockers []string) (bool, string) {
	if output == nil || len(output.Files) == 0 || len(blockers) == 0 {
		return false, ""
	}

	targets := parseProviderBlockedTSConfigTargets(blockers)
	if len(targets) == 0 {
		return false, ""
	}

	targetSet := make(map[string]bool, len(targets))
	for _, target := range targets {
		targetSet[strings.ToLower(strings.TrimSpace(target))] = true
	}

	applied := make([]string, 0, len(targets))
	for i := range output.Files {
		path := sanitizeFilePath(strings.TrimSpace(output.Files[i].Path))
		if path == "" || !targetSet[strings.ToLower(path)] {
			continue
		}
		canonical, ok := canonicalizeGeneratedTSConfigJSON(path, output.Files[i].Content)
		if !ok {
			continue
		}
		if canonical != output.Files[i].Content {
			output.Files[i].Content = canonical
		}
		output.Files[i].Size = int64(len(output.Files[i].Content))
		if strings.TrimSpace(output.Files[i].Language) == "" {
			output.Files[i].Language = am.detectLanguage(path)
		}
		applied = append(applied, path)
	}

	if len(applied) == 0 {
		return false, ""
	}

	sort.Strings(applied)
	return true, "canonical tsconfig JSON: " + strings.Join(applied, ", ")
}

func parseProviderBlockedTestingDependencyNames(blockers []string) []string {
	if len(blockers) == 0 {
		return nil
	}

	known := []string{
		"@testing-library/jest-dom",
		"@testing-library/dom",
		"@testing-library/react",
		"@testing-library/user-event",
		"@types/jest",
		"jest-environment-jsdom",
		"identity-obj-proxy",
		"ts-jest",
		"vitest",
		"jest",
		"jsdom",
	}

	found := make([]string, 0, len(known))
	for _, blocker := range blockers {
		lower := strings.ToLower(blocker)
		if !strings.Contains(lower, "package.json") {
			continue
		}
		for _, pkg := range known {
			if strings.Contains(lower, strings.ToLower(pkg)) {
				found = append(found, pkg)
			}
		}
	}

	return dedupeStrings(found)
}

func upsertGeneratedFile(files *[]GeneratedFile, path, content, language string) {
	if files == nil {
		return
	}
	path = sanitizeFilePath(path)
	if path == "" {
		return
	}
	content = normalizeGeneratedFileContent(path, content)
	for i := range *files {
		if sanitizeFilePath((*files)[i].Path) != path {
			continue
		}
		(*files)[i].Path = path
		(*files)[i].Content = content
		(*files)[i].Size = int64(len(content))
		if strings.TrimSpace(language) != "" {
			(*files)[i].Language = language
		}
		return
	}
	*files = append(*files, GeneratedFile{
		Path:     path,
		Content:  content,
		Language: language,
		Size:     int64(len(content)),
	})
}

func (am *AgentManager) applyDeterministicProviderBlockedTestingManifestRepair(build *Build, output *TaskOutput, blockers []string) (bool, string) {
	if am == nil || output == nil {
		return false, ""
	}

	missingPkgs := parseProviderBlockedTestingDependencyNames(blockers)
	if len(missingPkgs) == 0 {
		return false, ""
	}

	currentFiles := output.Files
	if build != nil {
		currentFiles = mergeGeneratedFiles(am.collectGeneratedFiles(build), output.Files)
	}
	if len(currentFiles) == 0 {
		return false, ""
	}

	manifestByPath := make(map[string]string)
	changed := make([]string, 0, 2)
	for _, manifestPath := range generatedManifestCandidates(currentFiles) {
		content := ""
		for _, file := range currentFiles {
			if sanitizeFilePath(file.Path) == manifestPath {
				content = file.Content
				break
			}
		}
		if strings.TrimSpace(content) == "" {
			continue
		}

		var manifest previewManifest
		if err := json.Unmarshal([]byte(content), &manifest); err != nil {
			continue
		}

		prefix := strings.TrimSuffix(filepath.ToSlash(manifestPath), "package.json")
		signals := inspectGeneratedPackageSignals(currentFiles, prefix)
		if !signals.hasNodeTests {
			continue
		}

		pkgs := append([]string(nil), missingPkgs...)
		if signals.usesJestGlobals && !manifestDeclaresDependency(manifest, "jest") {
			pkgs = append(pkgs, "jest")
		}
		if signals.usesTestingLibrary && !manifestDeclaresDependency(manifest, "@testing-library/react") {
			pkgs = append(pkgs, "@testing-library/react")
		}
		if signals.usesTestingLibrary && !manifestDeclaresDependency(manifest, "@testing-library/dom") {
			pkgs = append(pkgs, "@testing-library/dom")
		}
		if signals.usesJestDOM && !manifestDeclaresDependency(manifest, "@testing-library/jest-dom") {
			pkgs = append(pkgs, "@testing-library/jest-dom")
		}
		pkgs = dedupeStrings(pkgs)
		if len(pkgs) == 0 {
			continue
		}

		patched, added := patchManifestDependenciesJSON(content, pkgs)
		if len(added) == 0 {
			continue
		}
		manifestByPath[manifestPath] = patched
		changed = append(changed, fmt.Sprintf("%s (%s)", manifestPath, strings.Join(added, ", ")))
	}

	if len(changed) == 0 {
		return false, ""
	}

	for manifestPath, content := range manifestByPath {
		upsertGeneratedFile(&output.Files, manifestPath, content, "json")
	}
	sort.Strings(changed)
	return true, "manifest deps: " + strings.Join(changed, "; ")
}

type missingLocalModuleRepairTarget struct {
	SourcePath string
	Specifier  string
	TargetPath string
}

func parseMissingLocalModuleRepairTargets(errors []string) []missingLocalModuleRepairTarget {
	if len(errors) == 0 {
		return nil
	}

	re := regexp.MustCompile(`source imports local module "([^"]+)" from "([^"]+)" but generated file "([^"]+)" is missing`)
	tsCannotFindLocalRe := regexp.MustCompile(`(?m)([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx|mjs|cjs))\(\d+,\d+\):\s+error\s+TS2307:\s+Cannot find module ['"]([^'"]+)['"]`)
	seen := map[string]bool{}
	targets := make([]missingLocalModuleRepairTarget, 0)
	addTarget := func(target missingLocalModuleRepairTarget) {
		target.SourcePath = sanitizeFilePath(target.SourcePath)
		target.TargetPath = sanitizeFilePath(target.TargetPath)
		target.Specifier = strings.TrimSpace(target.Specifier)
		if target.SourcePath == "" || target.TargetPath == "" || target.Specifier == "" {
			return
		}
		key := target.SourcePath + "|" + target.Specifier + "|" + target.TargetPath
		if seen[key] {
			return
		}
		seen[key] = true
		targets = append(targets, target)
	}
	for _, msg := range errors {
		matches := re.FindAllStringSubmatch(msg, -1)
		for _, match := range matches {
			if len(match) != 4 {
				continue
			}
			addTarget(missingLocalModuleRepairTarget{
				Specifier:  strings.TrimSpace(match[1]),
				SourcePath: sanitizeFilePath(strings.TrimSpace(match[2])),
				TargetPath: sanitizeFilePath(strings.TrimSpace(match[3])),
			})
		}
		tsMatches := tsCannotFindLocalRe.FindAllStringSubmatch(msg, -1)
		for _, match := range tsMatches {
			if len(match) != 3 {
				continue
			}
			sourcePath := normalizePreviewSyntaxErrorPath(match[1])
			specifier := strings.TrimSpace(match[2])
			if sourcePath == "" || specifier == "" {
				continue
			}
			if !strings.HasPrefix(specifier, ".") && !strings.HasPrefix(specifier, "@/") && !strings.HasPrefix(specifier, "~/") {
				continue
			}
			candidates := localImportResolutionCandidates(sourcePath, specifier)
			if len(candidates) == 0 {
				continue
			}
			addTarget(missingLocalModuleRepairTarget{
				SourcePath: sourcePath,
				Specifier:  specifier,
				TargetPath: candidates[0],
			})
		}
	}
	sort.Slice(targets, func(i, j int) bool {
		if targets[i].TargetPath == targets[j].TargetPath {
			return targets[i].SourcePath < targets[j].SourcePath
		}
		return targets[i].TargetPath < targets[j].TargetPath
	})
	return targets
}

type generatedImportBinding struct {
	DefaultImport string
	NamedImports  []string
}

func parseGeneratedImportBinding(sourceContent string, specifier string) generatedImportBinding {
	specifier = strings.TrimSpace(specifier)
	if strings.TrimSpace(sourceContent) == "" || specifier == "" {
		return generatedImportBinding{}
	}

	pattern := regexp.MustCompile(`(?m)^\s*import\s+(.+?)\s+from\s+['"]` + regexp.QuoteMeta(specifier) + `['"]`)
	match := pattern.FindStringSubmatch(sourceContent)
	if len(match) != 2 {
		return generatedImportBinding{}
	}
	clause := strings.TrimSpace(match[1])
	clause = strings.TrimPrefix(clause, "type ")
	if clause == "" {
		return generatedImportBinding{}
	}

	binding := generatedImportBinding{}
	if strings.Contains(clause, ",") {
		parts := strings.SplitN(clause, ",", 2)
		binding.DefaultImport = strings.TrimSpace(parts[0])
		clause = strings.TrimSpace(parts[1])
	} else if !strings.HasPrefix(clause, "{") && !strings.HasPrefix(clause, "*") {
		binding.DefaultImport = clause
		clause = ""
	}

	if strings.HasPrefix(clause, "{") && strings.Contains(clause, "}") {
		inner := strings.TrimSpace(strings.TrimSuffix(strings.TrimPrefix(clause, "{"), "}"))
		for _, part := range strings.Split(inner, ",") {
			part = strings.TrimSpace(part)
			if part == "" {
				continue
			}
			if strings.Contains(part, " as ") {
				pieces := strings.Split(part, " as ")
				part = strings.TrimSpace(pieces[len(pieces)-1])
			}
			if part != "" {
				binding.NamedImports = append(binding.NamedImports, part)
			}
		}
	}

	binding.NamedImports = dedupeStrings(binding.NamedImports)
	return binding
}

func isLikelyReactComponentName(name string) bool {
	name = strings.TrimSpace(name)
	if name == "" {
		return false
	}
	r := rune(name[0])
	return r >= 'A' && r <= 'Z'
}

func sanitizeGeneratedIdentifier(name string) string {
	name = strings.TrimSpace(name)
	if name == "" {
		return ""
	}
	var b strings.Builder
	for i, r := range name {
		if (r >= 'A' && r <= 'Z') || (r >= 'a' && r <= 'z') || r == '_' || (i > 0 && r >= '0' && r <= '9') {
			b.WriteRune(r)
		}
	}
	return b.String()
}

func placeholderComponentIdentifier(targetPath string, binding generatedImportBinding) string {
	candidates := []string{binding.DefaultImport}
	candidates = append(candidates, binding.NamedImports...)
	for _, candidate := range candidates {
		candidate = sanitizeGeneratedIdentifier(candidate)
		if isLikelyReactComponentName(candidate) {
			return candidate
		}
	}
	base := strings.TrimSuffix(filepath.Base(targetPath), filepath.Ext(targetPath))
	base = sanitizeGeneratedIdentifier(base)
	if base == "" {
		return "GeneratedPlaceholder"
	}
	if !isLikelyReactComponentName(base) {
		return "GeneratedPlaceholder"
	}
	return base
}

func missingLocalModulePlaceholderContent(targetPath string, binding generatedImportBinding) string {
	targetPath = sanitizeFilePath(targetPath)
	ext := strings.ToLower(filepath.Ext(targetPath))
	if ext == ".cjs" {
		return "module.exports = {};\n"
	}
	componentLike := strings.Contains(targetPath, "/components/") ||
		ext == ".tsx" || ext == ".jsx" ||
		isLikelyReactComponentName(binding.DefaultImport)
	for _, name := range binding.NamedImports {
		if isLikelyReactComponentName(name) {
			componentLike = true
			break
		}
	}

	if componentLike {
		componentName := placeholderComponentIdentifier(targetPath, binding)
		label := strings.TrimSuffix(filepath.Base(targetPath), filepath.Ext(targetPath))
		namedImports := make([]string, 0, len(binding.NamedImports))
		componentIsNamedExport := false
		for _, name := range binding.NamedImports {
			name = sanitizeGeneratedIdentifier(name)
			if name == "" {
				continue
			}
			if name == componentName {
				componentIsNamedExport = true
			}
			namedImports = append(namedImports, name)
		}

		var b strings.Builder
		b.WriteString("import React from 'react';\n\n")
		b.WriteString("type PlaceholderProps = Record<string, unknown>;\n\n")
		if componentIsNamedExport {
			b.WriteString(fmt.Sprintf("export const %s: React.FC<PlaceholderProps> = () => (\n", componentName))
		} else {
			b.WriteString(fmt.Sprintf("const %s: React.FC<PlaceholderProps> = () => (\n", componentName))
		}
		b.WriteString("  <div className='rounded-lg border border-dashed border-slate-700/60 bg-slate-900/40 p-4 text-sm text-slate-300'>\n")
		b.WriteString(fmt.Sprintf("    %s placeholder\n", label))
		b.WriteString("  </div>\n")
		b.WriteString(");\n\n")
		for _, name := range namedImports {
			if name == componentName {
				continue
			}
			if isLikelyReactComponentName(name) {
				b.WriteString(fmt.Sprintf("export const %s = %s;\n", name, componentName))
			} else {
				b.WriteString(fmt.Sprintf("export const %s: any = {};\n", name))
			}
		}
		b.WriteString("\n")
		b.WriteString(fmt.Sprintf("export default %s;\n", componentName))
		return b.String()
	}

	var b strings.Builder
	for _, name := range binding.NamedImports {
		name = sanitizeGeneratedIdentifier(name)
		if name == "" {
			continue
		}
		b.WriteString(fmt.Sprintf("export const %s: any = {};\n", name))
	}
	if strings.TrimSpace(binding.DefaultImport) != "" {
		b.WriteString("const defaultExport: any = {};\n")
		b.WriteString("export default defaultExport;\n")
	}
	if b.Len() == 0 {
		b.WriteString("export {};\n")
	}
	return b.String()
}

func missingLocalModuleDeclarationContent(targetPath string, binding generatedImportBinding) string {
	targetPath = sanitizeFilePath(targetPath)
	ext := strings.ToLower(filepath.Ext(targetPath))
	switch ext {
	case ".cjs", ".js":
		var b strings.Builder
		if len(binding.NamedImports) > 0 {
			for _, name := range binding.NamedImports {
				name = sanitizeGeneratedIdentifier(name)
				if name == "" {
					continue
				}
				b.WriteString(fmt.Sprintf("export const %s: any;\n", name))
			}
		}
		b.WriteString("declare const defaultExport: any;\n")
		b.WriteString("export = defaultExport;\n")
		return b.String()
	default:
		return ""
	}
}

func (am *AgentManager) applyDeterministicMissingLocalModuleRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}
	targets := parseMissingLocalModuleRepairTargets(readinessErrors)
	if len(targets) == 0 {
		return nil, ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 {
		return nil, ""
	}

	applied := make([]string, 0, len(targets))
	for _, target := range targets {
		if strings.HasPrefix(target.Specifier, "@/") || strings.HasPrefix(target.Specifier, "~/") {
			srcCandidate := sanitizeFilePath(filepath.ToSlash(filepath.Join("src", strings.TrimPrefix(strings.TrimPrefix(target.Specifier, "@/"),
				"~/"))))
			if strings.TrimSpace(plan.content(srcCandidate)) != "" {
				continue
			}
		}
		if strings.TrimSpace(plan.content(target.TargetPath)) != "" {
			continue
		}
		sourceContent := plan.content(target.SourcePath)
		if !sourceContentImportsSpecifier(sourceContent, target.Specifier) {
			continue
		}
		binding := parseGeneratedImportBinding(sourceContent, target.Specifier)
		content := missingLocalModulePlaceholderContent(target.TargetPath, binding)
		language := am.detectLanguage(target.TargetPath)
		if !plan.createFile(target.TargetPath, content, language) {
			continue
		}
		if declContent := strings.TrimSpace(missingLocalModuleDeclarationContent(target.TargetPath, binding)); declContent != "" {
			declPath := sanitizeFilePath(target.TargetPath + ".d.ts")
			plan.createFile(declPath, declContent, am.detectLanguage(declPath))
		}
		applied = append(applied, fmt.Sprintf("%s (from %s)", target.TargetPath, target.SourcePath))
	}

	if len(applied) == 0 {
		return nil, ""
	}

	summary := "generated placeholder module(s): " + strings.Join(applied, ", ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "missing_local_module_repair: "+summary), summary
}

func repairDoubleSingleQuoteCorruption(path, content string) (string, bool) {
	if strings.TrimSpace(content) == "" || strings.Count(content, "''") < 2 {
		return content, false
	}
	ext := strings.ToLower(filepath.Ext(path))
	switch ext {
	case ".ts", ".tsx", ".js", ".jsx", ".json":
	default:
		return content, false
	}
	// Aggressive repair on targeted syntax-error files only.
	repaired := strings.ReplaceAll(content, "''", "'")
	repaired = normalizeGeneratedFileContent(path, repaired)
	if repaired == content {
		return content, false
	}
	return repaired, true
}

func ensureReactDefaultImport(content string) string {
	if strings.Contains(content, "import React") {
		return content
	}

	namedReactImportRe := regexp.MustCompile(`(?m)^import\s*\{([^}]*)\}\s*from\s*("react"|'react');?\s*$`)
	if loc := namedReactImportRe.FindStringSubmatchIndex(content); loc != nil {
		members := strings.TrimSpace(content[loc[2]:loc[3]])
		quote := content[loc[4]:loc[5]]
		replacement := fmt.Sprintf("import React, { %s } from %s;", members, quote)
		return content[:loc[0]] + replacement + content[loc[1]:]
	}

	namespaceReactImportRe := regexp.MustCompile(`(?m)^import\s*\*\s*as\s*React\s*from\s*("react"|'react');?\s*$`)
	if loc := namespaceReactImportRe.FindStringIndex(content); loc != nil {
		return content
	}

	if strings.Contains(content, `from "react"`) {
		return "import React from \"react\";\n" + content
	}
	return "import React from 'react';\n" + content
}

func repairJSXInNonTSXFile(path, content string) (string, bool) {
	ext := strings.ToLower(filepath.Ext(path))
	if ext != ".ts" && ext != ".js" {
		return content, false
	}
	if !strings.Contains(content, ".Provider") || !strings.Contains(content, "{children}") {
		return content, false
	}

	providerRe := regexp.MustCompile(`(?s)return\s*\(\s*<([A-Za-z0-9_.]+)\.Provider\s+value=\{\{(.*?)\}\}\s*>\s*\{children\}\s*</([A-Za-z0-9_.]+)\.Provider>\s*\);`)
	loc := providerRe.FindStringSubmatchIndex(content)
	if loc == nil || len(loc) < 8 {
		return content, false
	}

	providerName := strings.TrimSpace(content[loc[2]:loc[3]])
	closingProviderName := strings.TrimSpace(content[loc[6]:loc[7]])
	valueExpr := strings.TrimSpace(content[loc[4]:loc[5]])
	if providerName == "" || valueExpr == "" {
		return content, false
	}
	if providerName != closingProviderName {
		return content, false
	}

	replacement := fmt.Sprintf("return React.createElement(%s.Provider, { value: { %s } }, children);", providerName, valueExpr)
	repaired := content[:loc[0]] + replacement + content[loc[1]:]
	repaired = ensureReactDefaultImport(repaired)
	repaired = normalizeGeneratedFileContent(path, repaired)
	if repaired == content {
		return content, false
	}
	return repaired, true
}

func (am *AgentManager) applyDeterministicQuoteSyntaxRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}
	targets := parsePreviewSyntaxErrorTargetFiles(readinessErrors)
	if len(targets) == 0 {
		return nil, ""
	}
	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 {
		return nil, ""
	}

	applied := false
	summaries := make([]string, 0, len(targets))
	for _, target := range targets {
		content := plan.content(target)
		if strings.TrimSpace(content) == "" {
			continue
		}
		repaired, changed := repairDoubleSingleQuoteCorruption(target, content)
		if !changed {
			continue
		}
		if !plan.patchFile(target, repaired, am.detectLanguage(target)) {
			continue
		}
		applied = true
		summaries = append(summaries, target)
	}
	if !applied {
		return nil, ""
	}
	summary := fmt.Sprintf("quote-correction on %s", strings.Join(summaries, ", "))
	return am.bundleFromPatchPlan(build.ID, files, plan, "syntax_repair: "+summary), summary
}

func (am *AgentManager) applyDeterministicTSJSXProviderRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}

	targets := parsePreviewJSXInTSRepairTargets(readinessErrors)
	if len(targets) == 0 {
		return nil, ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 {
		return nil, ""
	}

	applied := make([]string, 0, len(targets))
	for _, target := range targets {
		content := plan.content(target)
		if strings.TrimSpace(content) == "" {
			continue
		}
		repaired, changed := repairJSXInNonTSXFile(target, content)
		if !changed {
			continue
		}
		if !plan.patchFile(target, repaired, am.detectLanguage(target)) {
			continue
		}
		applied = append(applied, target)
	}
	if len(applied) == 0 {
		return nil, ""
	}

	summary := "jsx-in-ts normalization on " + strings.Join(applied, ", ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "ts_jsx_repair: "+summary), summary
}

func parseSequelizeUniqueKeysRepairTargets(errors []string) []string {
	if len(errors) == 0 {
		return nil
	}
	re := regexp.MustCompile(`(?m)([^\s(:\n]+)\(\d+,\d+\): error TS2353: Object literal may only specify known properties, and 'uniqueKeys' does not exist`)
	seen := map[string]bool{}
	targets := make([]string, 0)
	for _, msg := range errors {
		for _, match := range re.FindAllStringSubmatch(msg, -1) {
			if len(match) != 2 {
				continue
			}
			path := sanitizeFilePath(strings.TrimSpace(match[1]))
			if path == "" || seen[strings.ToLower(path)] {
				continue
			}
			seen[strings.ToLower(path)] = true
			targets = append(targets, path)
		}
	}
	sort.Strings(targets)
	return targets
}

func parseSequelizeIndexesRepairTargets(errors []string) []string {
	if len(errors) == 0 {
		return nil
	}
	re := regexp.MustCompile(`(?m)([^\s(:\n]+)\(\d+,\d+\): error TS2353: Object literal may only specify known properties, and 'indexes' does not exist in type 'InitOptions<`)
	seen := map[string]bool{}
	targets := make([]string, 0)
	for _, msg := range errors {
		for _, match := range re.FindAllStringSubmatch(msg, -1) {
			if len(match) != 2 {
				continue
			}
			path := sanitizeFilePath(strings.TrimSpace(match[1]))
			if path == "" || seen[strings.ToLower(path)] {
				continue
			}
			seen[strings.ToLower(path)] = true
			targets = append(targets, path)
		}
	}
	sort.Strings(targets)
	return targets
}

func stripSequelizeUniqueKeysOptions(content string) (string, bool) {
	if !strings.Contains(content, "uniqueKeys:") {
		return content, false
	}

	lines := strings.Split(content, "\n")
	out := make([]string, 0, len(lines))
	changed := false

	for i := 0; i < len(lines); i++ {
		line := lines[i]
		if !strings.Contains(line, "uniqueKeys:") {
			out = append(out, line)
			continue
		}

		braceDepth := strings.Count(line, "{") - strings.Count(line, "}")
		changed = true
		for i+1 < len(lines) {
			i++
			next := lines[i]
			braceDepth += strings.Count(next, "{") - strings.Count(next, "}")
			if braceDepth <= 0 {
				break
			}
		}
	}

	if !changed {
		return content, false
	}
	return strings.Join(out, "\n"), true
}

func stripSequelizeIndexesOptions(content string) (string, bool) {
	if !strings.Contains(content, "indexes:") {
		return content, false
	}

	lines := strings.Split(content, "\n")
	out := make([]string, 0, len(lines))
	changed := false

	for i := 0; i < len(lines); i++ {
		line := lines[i]
		if !strings.Contains(line, "indexes:") {
			out = append(out, line)
			continue
		}

		bracketDepth := strings.Count(line, "[") - strings.Count(line, "]")
		changed = true
		if bracketDepth <= 0 {
			continue
		}
		for i+1 < len(lines) {
			i++
			next := lines[i]
			bracketDepth += strings.Count(next, "[") - strings.Count(next, "]")
			if bracketDepth <= 0 {
				break
			}
		}
	}

	if !changed {
		return content, false
	}
	return strings.Join(out, "\n"), true
}

func (am *AgentManager) applyDeterministicSequelizeUniqueKeysRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}

	targets := parseSequelizeUniqueKeysRepairTargets(readinessErrors)
	if len(targets) == 0 {
		return nil, ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 {
		return nil, ""
	}

	applied := make([]string, 0, len(targets))
	for _, target := range targets {
		content := plan.content(target)
		if strings.TrimSpace(content) == "" {
			continue
		}
		repaired, changed := stripSequelizeUniqueKeysOptions(content)
		if !changed {
			continue
		}
		if !plan.patchFile(target, repaired, am.detectLanguage(target)) {
			continue
		}
		applied = append(applied, target)
	}
	if len(applied) == 0 {
		return nil, ""
	}

	summary := "sequelize uniqueKeys removal on " + strings.Join(applied, ", ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "sequelize_unique_keys_repair: "+summary), summary
}

