type staleImportValidationTarget struct {
	SourcePath string
	Specifier  string
}

type exportMismatchRepairTarget struct {
	ImporterPath      string
	ExporterPath      string
	Specifier         string
	ExportName        string
	PreferNamedImport bool
}

type externalDefaultImportRepairTarget struct {
	ImporterPath string
	PackageName  string
}

type missingKnownImportRepairTarget struct {
	Path   string
	Symbol string
	Module string
}

func parseStaleImportValidationTargets(errors []string) []staleImportValidationTarget {
	if len(errors) == 0 {
		return nil
	}

	patterns := []*regexp.Regexp{
		regexp.MustCompile(`(?m)([^\s(:\n]+)\(\d+,\d+\): error TS2305: Module ['"]([^'"]+)['"] has no exported member`),
		regexp.MustCompile(`(?m)([^\s(:\n]+)\(\d+,\d+\): error TS2307: Cannot find module ['"]([^'"]+)['"]`),
	}

	seen := map[string]bool{}
	targets := make([]staleImportValidationTarget, 0)
	for _, msg := range errors {
		for _, pattern := range patterns {
			for _, match := range pattern.FindAllStringSubmatch(msg, -1) {
				if len(match) != 3 {
					continue
				}
				sourcePath := sanitizeFilePath(strings.TrimSpace(match[1]))
				specifier := strings.TrimSpace(match[2])
				if sourcePath == "" || specifier == "" {
					continue
				}
				key := strings.ToLower(sourcePath + "::" + specifier)
				if seen[key] {
					continue
				}
				seen[key] = true
				targets = append(targets, staleImportValidationTarget{
					SourcePath: sourcePath,
					Specifier:  specifier,
				})
			}
		}
	}

	sort.Slice(targets, func(i, j int) bool {
		if targets[i].SourcePath == targets[j].SourcePath {
			return targets[i].Specifier < targets[j].Specifier
		}
		return targets[i].SourcePath < targets[j].SourcePath
	})
	return targets
}

func sourceContentImportsSpecifier(content, specifier string) bool {
	content = strings.TrimSpace(content)
	specifier = strings.TrimSpace(specifier)
	if content == "" || specifier == "" {
		return false
	}

	needles := []string{
		fmt.Sprintf("from '%s'", specifier),
		fmt.Sprintf(`from "%s"`, specifier),
		fmt.Sprintf("require('%s')", specifier),
		fmt.Sprintf(`require("%s")`, specifier),
		fmt.Sprintf("import('%s')", specifier),
		fmt.Sprintf(`import("%s")`, specifier),
	}
	for _, needle := range needles {
		if strings.Contains(content, needle) {
			return true
		}
	}
	return false
}

func (am *AgentManager) clearStaleImportValidationError(build *Build, readinessErrors []string) string {
	if build == nil || len(readinessErrors) == 0 {
		return ""
	}

	targets := parseStaleImportValidationTargets(readinessErrors)
	if len(targets) == 0 {
		return ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 || plan == nil {
		return ""
	}

	cleared := make([]string, 0, len(targets))
	for _, target := range targets {
		sourceContent := plan.content(target.SourcePath)
		if strings.TrimSpace(sourceContent) == "" {
			continue
		}
		if sourceContentImportsSpecifier(sourceContent, target.Specifier) {
			continue
		}
		cleared = append(cleared, fmt.Sprintf("%s -> %s", target.SourcePath, target.Specifier))
	}
	if len(cleared) == 0 {
		return ""
	}

	sort.Strings(cleared)
	return "stale import validation on " + strings.Join(cleared, ", ")
}

func readinessErrorsContainPostCSSConfigFailure(errors []string) bool {
	for _, msg := range errors {
		lower := strings.ToLower(msg)
		if strings.Contains(lower, "failed to load postcss config") ||
			strings.Contains(lower, "postcss config") && (strings.Contains(lower, "unexpected token") || strings.Contains(lower, "module is not defined")) {
			return true
		}
	}
	return false
}

func manifestContentUsesESModulePackage(content string) bool {
	if strings.TrimSpace(content) == "" {
		return false
	}
	var manifest previewManifest
	if err := json.Unmarshal([]byte(content), &manifest); err != nil {
		return false
	}
	return strings.EqualFold(strings.TrimSpace(manifest.Type), "module")
}

func configContentUsesESMSyntax(content string) bool {
	return regexp.MustCompile(`(?m)^\s*import\s+`).MatchString(content) ||
		regexp.MustCompile(`(?m)^\s*export\s+default\b`).MatchString(content)
}

func configContentUsesCommonJSSyntax(content string) bool {
	return regexp.MustCompile(`(?m)^\s*(?:const|let|var)\s+\w+\s*=\s*require\(`).MatchString(content) ||
		regexp.MustCompile(`(?m)^\s*module\.exports\s*=`).MatchString(content)
}

func configPathRequiresESMSyntax(path string, packageUsesESM bool) bool {
	switch strings.ToLower(filepath.Ext(sanitizeFilePath(path))) {
	case ".mjs", ".ts":
		return true
	case ".cjs":
		return false
	default:
		return packageUsesESM
	}
}

func configSyntaxConflictsWithModuleMode(path, content string, packageUsesESM bool) bool {
	if strings.TrimSpace(content) == "" {
		return false
	}
	requiresESM := configPathRequiresESMSyntax(path, packageUsesESM)
	usesESM := configContentUsesESMSyntax(content)
	usesCJS := configContentUsesCommonJSSyntax(content)
	if usesESM && usesCJS {
		return true
	}
	if requiresESM {
		return usesCJS
	}
	return usesESM
}

func generatedPostCSSConfigSatisfied(files []GeneratedFile, plan *generatedFilePatchPlan, packageUsesESM bool) bool {
	for _, f := range files {
		p := filepath.ToSlash(strings.TrimSpace(f.Path))
		if p != "postcss.config.js" && p != "postcss.config.cjs" && p != "postcss.config.mjs" {
			continue
		}
		content := plan.content(p)
		return strings.Contains(content, "tailwindcss") &&
			strings.Contains(content, "autoprefixer") &&
			!configSyntaxConflictsWithModuleMode(p, content, packageUsesESM)
	}
	return false
}

func generatedTailwindConfigSatisfied(files []GeneratedFile, plan *generatedFilePatchPlan, packageUsesESM bool) bool {
	for _, f := range files {
		p := filepath.ToSlash(strings.TrimSpace(f.Path))
		if p != "tailwind.config.js" && p != "tailwind.config.cjs" && p != "tailwind.config.mjs" && p != "tailwind.config.ts" {
			continue
		}
		content := plan.content(p)
		return strings.TrimSpace(content) != "" && !configSyntaxConflictsWithModuleMode(p, content, packageUsesESM)
	}
	return true
}

func (am *AgentManager) clearStaleDependencyValidationError(build *Build, readinessErrors []string) string {
	if build == nil || len(readinessErrors) == 0 {
		return ""
	}

	frontendPkgs, backendPkgs := parseMissingDependenciesByVerificationScope(readinessErrors)
	frontendPkgs = dedupeStrings(append(frontendPkgs, parseMissingTypePackagesFromBuildErrors(readinessErrors)...))
	postCSSFailure := readinessErrorsContainPostCSSConfigFailure(readinessErrors)
	if len(frontendPkgs) == 0 && len(backendPkgs) == 0 && !postCSSFailure {
		return ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 || plan == nil {
		return ""
	}

	manifestContent := func(candidates []string) (string, string) {
		path := findGeneratedManifestPath(files, candidates)
		if path == "" {
			return "", ""
		}
		return path, plan.content(path)
	}
	allDeclared := func(content string, pkgs []string) bool {
		if strings.TrimSpace(content) == "" || len(pkgs) == 0 {
			return false
		}
		var manifest previewManifest
		if err := json.Unmarshal([]byte(content), &manifest); err != nil {
			return false
		}
		for _, pkg := range pkgs {
			if !manifestDeclaresDependency(manifest, pkg) {
				return false
			}
		}
		return true
	}

	cleared := make([]string, 0, 2)
	frontendPath := ""
	frontendContent := ""
	if len(frontendPkgs) > 0 {
		path, content := manifestContent([]string{
			"frontend/package.json",
			"client/package.json",
			"web/package.json",
			"apps/web/package.json",
			"apps/frontend/package.json",
			"packages/web/package.json",
			"packages/frontend/package.json",
			"package.json",
		})
		if !allDeclared(content, frontendPkgs) {
			return ""
		}
		frontendPath, frontendContent = path, content
		cleared = append(cleared, fmt.Sprintf("frontend %s has %s", path, strings.Join(frontendPkgs, ", ")))
	}
	if postCSSFailure {
		if frontendPath == "" {
			frontendPath, frontendContent = manifestContent([]string{
				"frontend/package.json",
				"client/package.json",
				"web/package.json",
				"apps/web/package.json",
				"apps/frontend/package.json",
				"packages/web/package.json",
				"packages/frontend/package.json",
				"package.json",
			})
		}
		if !allDeclared(frontendContent, []string{"postcss", "tailwindcss", "autoprefixer"}) {
			return ""
		}
		packageUsesESM := manifestContentUsesESModulePackage(frontendContent)
		if !generatedPostCSSConfigSatisfied(files, plan, packageUsesESM) || !generatedTailwindConfigSatisfied(files, plan, packageUsesESM) {
			return ""
		}
		cleared = append(cleared, fmt.Sprintf("frontend %s has compatible PostCSS/Tailwind config", frontendPath))
	}
	if len(backendPkgs) > 0 {
		path, content := manifestContent([]string{
			"backend/package.json",
			"api/package.json",
			"server/package.json",
			"apps/api/package.json",
			"apps/server/package.json",
			"packages/backend/package.json",
			"packages/api/package.json",
			"package.json",
		})
		if !allDeclared(content, backendPkgs) {
			return ""
		}
		cleared = append(cleared, fmt.Sprintf("backend %s has %s", path, strings.Join(backendPkgs, ", ")))
	}
	if len(cleared) == 0 {
		return ""
	}

	sort.Strings(cleared)
	return "stale dependency validation on " + strings.Join(cleared, "; ")
}

func (am *AgentManager) clearStaleLocalModuleValidationError(build *Build, readinessErrors []string) string {
	if build == nil || len(readinessErrors) == 0 {
		return ""
	}

	targets := parseMissingLocalModuleRepairTargets(readinessErrors)
	if len(targets) == 0 {
		return ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 || plan == nil {
		return ""
	}

	cleared := make([]string, 0, len(targets))
	for _, target := range targets {
		sourceContent := plan.content(target.SourcePath)
		if strings.TrimSpace(sourceContent) != "" && sourceContentImportsSpecifier(sourceContent, target.Specifier) && strings.TrimSpace(plan.content(target.TargetPath)) == "" {
			return ""
		}
		cleared = append(cleared, fmt.Sprintf("%s -> %s", target.SourcePath, target.TargetPath))
	}
	if len(cleared) == 0 {
		return ""
	}

	sort.Strings(cleared)
	return "stale local-module validation on " + strings.Join(cleared, ", ")
}

func parseExportMismatchRepairTargets(errors []string) []exportMismatchRepairTarget {
	if len(errors) == 0 {
		return nil
	}

	patterns := []*regexp.Regexp{
		regexp.MustCompile(`(?m)RollupError:\s+["']([^"']+)["'] is not exported by ["']([^"']+)["'], imported by ["']([^"']+)["']`),
		regexp.MustCompile(`(?m)([^\s(:\n]+)\(\d+,\d+\): error TS(?:2305|2614): Module ['"]"?([^'"]+)"?['"] has no exported member ['"]([^'"]+)['"]`),
		regexp.MustCompile(`(?m)([^\s(:\n]+)\(\d+,\d+\): error TS2613: Module ['"](.+?)['"] has no default export\.[^\n]*import\s+\{\s*([A-Za-z_][A-Za-z0-9_]*)\s*\}\s+from`),
		regexp.MustCompile(`(?m)([^\s(:\n]+)\(\d+,\d+\): error TS1192: Module ['"](.+?)['"] has no default export\.`),
	}

	seen := map[string]bool{}
	targets := make([]exportMismatchRepairTarget, 0)
	for _, msg := range errors {
		for idx, pattern := range patterns {
			for _, match := range pattern.FindAllStringSubmatch(msg, -1) {
				var target exportMismatchRepairTarget
				switch idx {
				case 0:
					if len(match) != 4 {
						continue
					}
					target = exportMismatchRepairTarget{
						ExportName:   strings.TrimSpace(match[1]),
						ExporterPath: sanitizeFilePath(strings.TrimSpace(match[2])),
						ImporterPath: sanitizeFilePath(strings.TrimSpace(match[3])),
					}
				case 1:
					if len(match) != 4 {
						continue
					}
					target = exportMismatchRepairTarget{
						ImporterPath: sanitizeFilePath(strings.TrimSpace(match[1])),
						Specifier:    strings.TrimSpace(match[2]),
						ExportName:   strings.TrimSpace(match[3]),
					}
				case 2:
					if len(match) != 4 {
						continue
					}
					target = exportMismatchRepairTarget{
						ImporterPath:      sanitizeFilePath(strings.TrimSpace(match[1])),
						ExporterPath:      normalizePreviewSyntaxErrorPath(match[2]),
						ExportName:        strings.TrimSpace(match[3]),
						PreferNamedImport: true,
					}
				case 3:
					if len(match) != 3 {
						continue
					}
					target = exportMismatchRepairTarget{
						ImporterPath:      sanitizeFilePath(strings.TrimSpace(match[1])),
						ExporterPath:      normalizePreviewSyntaxErrorPath(match[2]),
						PreferNamedImport: true,
					}
				}
				if target.ImporterPath == "" || (!target.PreferNamedImport && target.ExportName == "") {
					continue
				}
				key := strings.ToLower(target.ImporterPath + "::" + target.ExporterPath + "::" + target.Specifier + "::" + target.ExportName)
				if seen[key] {
					continue
				}
				seen[key] = true
				targets = append(targets, target)
			}
		}
	}

	sort.Slice(targets, func(i, j int) bool {
		if targets[i].ImporterPath == targets[j].ImporterPath {
			if targets[i].ExporterPath == targets[j].ExporterPath {
				return targets[i].ExportName < targets[j].ExportName
			}
			return targets[i].ExporterPath < targets[j].ExporterPath
		}
		return targets[i].ImporterPath < targets[j].ImporterPath
	})
	return targets
}

func resolveGeneratedErrorPathCandidate(path string, existing map[string]bool) string {
	path = strings.TrimSuffix(sanitizeFilePath(path), "/")
	if path == "" {
		return ""
	}
	candidates := []string{
		path,
		path + ".tsx",
		path + ".ts",
		path + ".jsx",
		path + ".js",
		filepath.ToSlash(filepath.Join(path, "index.tsx")),
		filepath.ToSlash(filepath.Join(path, "index.ts")),
		filepath.ToSlash(filepath.Join(path, "index.jsx")),
		filepath.ToSlash(filepath.Join(path, "index.js")),
	}
	for _, candidate := range candidates {
		if existing[strings.ToLower(candidate)] {
			return candidate
		}
	}
	return ""
}

func generatedFileExportsNamedSymbol(content, name string) bool {
	content = strings.TrimSpace(content)
	name = sanitizeGeneratedIdentifier(name)
	if content == "" || name == "" {
		return false
	}

	patterns := []*regexp.Regexp{
		regexp.MustCompile(`(?m)\bexport\s+(?:const|function|class|let|var|type|interface|enum)\s+` + regexp.QuoteMeta(name) + `\b`),
		regexp.MustCompile(`(?m)\bexport\s*\{[^}]*\b` + regexp.QuoteMeta(name) + `\b[^}]*\}`),
	}
	for _, pattern := range patterns {
		if pattern.MatchString(content) {
			return true
		}
	}
	return false
}

func defaultExportIdentifier(content string) string {
	patterns := []*regexp.Regexp{
		regexp.MustCompile(`(?m)export\s+default\s+function\s+([A-Za-z_][A-Za-z0-9_]*)\b`),
		regexp.MustCompile(`(?m)export\s+default\s+class\s+([A-Za-z_][A-Za-z0-9_]*)\b`),
		regexp.MustCompile(`(?m)export\s+default\s+([A-Za-z_][A-Za-z0-9_]*)\s*;`),
	}
	for _, pattern := range patterns {
		matches := pattern.FindStringSubmatch(content)
		if len(matches) == 2 {
			return sanitizeGeneratedIdentifier(matches[1])
		}
	}
	return ""
}

func resolveExportMismatchTargetPath(importerPath, specifier string, existing map[string]bool) string {
	importerPath = sanitizeFilePath(importerPath)
	specifier = strings.TrimSpace(specifier)
	if importerPath == "" || specifier == "" {
		return ""
	}
	for _, candidate := range localImportResolutionCandidates(importerPath, specifier) {
		sanitized := sanitizeFilePath(candidate)
		if sanitized != "" && existing[strings.ToLower(sanitized)] {
			return sanitized
		}
	}
	return ""
}

func rewriteNamedImportToDefaultImport(importerPath, content, exporterPath, exportName string) (string, bool) {
	importerPath = sanitizeFilePath(importerPath)
	exporterPath = sanitizeFilePath(exporterPath)
	exportName = strings.TrimSpace(exportName)
	if importerPath == "" || exporterPath == "" || exportName == "" || strings.TrimSpace(content) == "" {
		return content, false
	}

	importRe := regexp.MustCompile(`(?m)^(\s*import\s+)(.+?)(\s+from\s+['"]([^'"]+)['"]\s*;?\s*)$`)
	matches := importRe.FindAllStringSubmatchIndex(content, -1)
	for _, match := range matches {
		if len(match) < 10 {
			continue
		}
		clause := content[match[4]:match[5]]
		specifier := strings.TrimSpace(content[match[8]:match[9]])
		resolved := resolveExportMismatchTargetPath(importerPath, specifier, map[string]bool{strings.ToLower(exporterPath): true})
		if !strings.EqualFold(resolved, exporterPath) {
			continue
		}

		trimmedClause := strings.TrimSpace(strings.TrimPrefix(strings.TrimSpace(clause), "type "))
		defaultImport := ""
		namedSection := ""
		switch {
		case strings.Contains(trimmedClause, "{"):
			parts := strings.SplitN(trimmedClause, "{", 2)
			defaultImport = strings.TrimSpace(strings.TrimSuffix(parts[0], ","))
			namedSection = strings.TrimSpace(parts[1])
			namedSection = strings.TrimSuffix(namedSection, "}")
		default:
			continue
		}

		namedParts := strings.Split(namedSection, ",")
		rewrittenParts := make([]string, 0, len(namedParts))
		replacementDefault := defaultImport
		changed := false
		for _, part := range namedParts {
			part = strings.TrimSpace(part)
			if part == "" {
				continue
			}
			sourceName := part
			localName := part
			if strings.Contains(part, " as ") {
				pieces := strings.SplitN(part, " as ", 2)
				sourceName = strings.TrimSpace(pieces[0])
				localName = strings.TrimSpace(pieces[1])
			}
			if sourceName == exportName {
				if replacementDefault != "" {
					return content, false
				}
				replacementDefault = localName
				changed = true
				continue
			}
			rewrittenParts = append(rewrittenParts, part)
		}
		if !changed || strings.TrimSpace(replacementDefault) == "" {
			continue
		}

		newClause := replacementDefault
		if len(rewrittenParts) > 0 {
			newClause += ", { " + strings.Join(rewrittenParts, ", ") + " }"
		}
		replacement := content[match[2]:match[3]] + newClause + content[match[6]:match[7]]
		return content[:match[0]] + replacement + content[match[1]:], true
	}

	return content, false
}

func rewriteDefaultImportToNamedImport(importerPath, content, exporterPath, exportName, exporterContent string) (string, bool) {
	importerPath = sanitizeFilePath(importerPath)
	exporterPath = sanitizeFilePath(exporterPath)
	exportName = sanitizeGeneratedIdentifier(exportName)
	if importerPath == "" || exporterPath == "" || strings.TrimSpace(content) == "" || strings.TrimSpace(exporterContent) == "" {
		return content, false
	}

	importRe := regexp.MustCompile(`(?m)^(\s*import\s+)(.+?)(\s+from\s+['"]([^'"]+)['"]\s*;?\s*)$`)
	matches := importRe.FindAllStringSubmatchIndex(content, -1)
	for _, match := range matches {
		if len(match) < 10 {
			continue
		}
		clause := content[match[4]:match[5]]
		specifier := strings.TrimSpace(content[match[8]:match[9]])
		resolved := resolveExportMismatchTargetPath(importerPath, specifier, map[string]bool{strings.ToLower(exporterPath): true})
		if !strings.EqualFold(resolved, exporterPath) {
			continue
		}

		trimmedClause := strings.TrimSpace(clause)
		if strings.HasPrefix(trimmedClause, "type ") || strings.HasPrefix(trimmedClause, "{") || strings.HasPrefix(trimmedClause, "*") {
			continue
		}

		defaultImport := trimmedClause
		namedSection := ""
		if strings.Contains(trimmedClause, "{") {
			parts := strings.SplitN(trimmedClause, "{", 2)
			defaultImport = strings.TrimSpace(strings.TrimSuffix(parts[0], ","))
			namedSection = strings.TrimSpace(strings.TrimSuffix(parts[1], "}"))
		}
		defaultImport = sanitizeGeneratedIdentifier(defaultImport)
		if defaultImport == "" {
			continue
		}

		namedExport := exportName
		if namedExport == "" {
			namedExport = defaultImport
		}
		if !generatedFileExportsNamedSymbol(exporterContent, namedExport) {
			continue
		}

		namedParts := make([]string, 0, 2)
		if namedExport == defaultImport {
			namedParts = append(namedParts, namedExport)
		} else {
			namedParts = append(namedParts, namedExport+" as "+defaultImport)
		}
		if namedSection != "" {
			for _, part := range strings.Split(namedSection, ",") {
				part = strings.TrimSpace(part)
				if part != "" {
					namedParts = append(namedParts, part)
				}
			}
		}

		replacement := content[match[2]:match[3]] + "{ " + strings.Join(namedParts, ", ") + " }" + content[match[6]:match[7]]
		return content[:match[0]] + replacement + content[match[1]:], true
	}

	return content, false
}

func addNamedAliasForDefaultExport(content, exportName string) (string, bool) {
	exportName = sanitizeGeneratedIdentifier(exportName)
	if exportName == "" || strings.TrimSpace(content) == "" || generatedFileExportsNamedSymbol(content, exportName) {
		return content, false
	}

	defaultIdent := defaultExportIdentifier(content)
	if defaultIdent == "" {
		return content, false
	}

	trimmed := strings.TrimRight(content, " \n\t")
	repaired := trimmed + "\nexport { " + defaultIdent + " as " + exportName + " };\n"
	return repaired, true
}

type shadcnUIExportRequirement struct {
	TargetPath string
	Module     string
	Names      map[string]bool
}

func parseGeneratedImportNamedSourceNames(sourceContent string, specifier string) []string {
	specifier = strings.TrimSpace(specifier)
	if strings.TrimSpace(sourceContent) == "" || specifier == "" {
		return nil
	}

	pattern := regexp.MustCompile(`(?ms)^\s*import\s+(.+?)\s+from\s+['"]` + regexp.QuoteMeta(specifier) + `['"]`)
	match := pattern.FindStringSubmatch(sourceContent)
	if len(match) != 2 {
		return nil
	}
	clause := strings.TrimSpace(match[1])
	if strings.HasPrefix(clause, "type ") {
		return nil
	}
	if !strings.Contains(clause, "{") || !strings.Contains(clause, "}") {
		return nil
	}
	inner := strings.TrimSpace(strings.TrimSuffix(strings.TrimPrefix(strings.SplitN(clause, "{", 2)[1], "{"), "}"))
	names := make([]string, 0)
	for _, part := range strings.Split(inner, ",") {
		part = strings.TrimSpace(part)
		if part == "" {
			continue
		}
		if strings.HasPrefix(part, "type ") {
			continue
		}
		if strings.Contains(part, " as ") {
			pieces := regexp.MustCompile(`\s+as\s+`).Split(part, 2)
			part = strings.TrimSpace(pieces[0])
		}
		if name := sanitizeGeneratedIdentifier(part); name != "" {
			names = append(names, name)
		}
	}
	return dedupeStringsPreserveOrder(names)
}

func localImportResolutionCandidatesWithAliasPrefix(importerPath, spec string) []string {
	candidates := localImportResolutionCandidates(importerPath, spec)
	if !(strings.HasPrefix(strings.TrimSpace(spec), "@/") || strings.HasPrefix(strings.TrimSpace(spec), "~/")) {
		return candidates
	}
	importerPath = sanitizeFilePath(importerPath)
	idx := strings.Index(importerPath, "/src/")
	if idx < 0 {
		return candidates
	}
	prefix := importerPath[:idx+1]
	prefixed := make([]string, 0, len(candidates)*2)
	for _, candidate := range candidates {
		candidate = sanitizeFilePath(candidate)
		if candidate == "" {
			continue
		}
		prefixed = append(prefixed, prefix+candidate)
	}
	prefixed = append(prefixed, candidates...)
	return dedupeStringsPreserveOrder(prefixed)
}

func shadcnUIModuleFromPath(path string) string {
	path = sanitizeFilePath(path)
	if path == "" {
		return ""
	}
	marker := "/components/ui/"
	idx := strings.Index(path, marker)
	if idx < 0 {
		if strings.HasPrefix(path, "src/components/ui/") {
			idx = len("src") - 1
		} else {
			return ""
		}
	}
	segment := path[idx+len(marker):]
	if segment == "" {
		return ""
	}
	segment = strings.TrimSuffix(segment, filepath.Ext(segment))
	segment = strings.TrimSuffix(segment, "/index")
	if strings.Contains(segment, "/") {
		parts := strings.Split(segment, "/")
		segment = parts[0]
	}
	return strings.ToLower(sanitizeFilePath(segment))
}

func collectShadcnUIExportRequirements(files []GeneratedFile) map[string]*shadcnUIExportRequirement {
	if len(files) == 0 {
		return nil
	}
	existing := make(map[string]string, len(files))
	for _, file := range files {
		path := sanitizeFilePath(file.Path)
		if path != "" {
			existing[strings.ToLower(path)] = path
		}
	}
	requirements := map[string]*shadcnUIExportRequirement{}
	for _, file := range files {
		importerPath := sanitizeFilePath(file.Path)
		if importerPath == "" || strings.TrimSpace(file.Content) == "" {
			continue
		}
		switch strings.ToLower(filepath.Ext(importerPath)) {
		case ".js", ".jsx", ".ts", ".tsx":
		default:
			continue
		}
		for _, match := range generatedImportPathPattern.FindAllStringSubmatch(file.Content, -1) {
			if len(match) != 2 {
				continue
			}
			spec := strings.TrimSpace(match[1])
			if !strings.Contains(spec, "components/ui/") {
				continue
			}
			names := parseGeneratedImportNamedSourceNames(file.Content, spec)
			if len(names) == 0 {
				continue
			}
			targetPath := ""
			candidates := localImportResolutionCandidatesWithAliasPrefix(importerPath, spec)
			for _, candidate := range candidates {
				if existingPath, ok := existing[strings.ToLower(sanitizeFilePath(candidate))]; ok {
					targetPath = existingPath
					break
				}
			}
			if targetPath == "" {
				for _, candidate := range candidates {
					candidate = sanitizeFilePath(candidate)
					if strings.Contains(candidate, "/components/ui/") && strings.HasSuffix(strings.ToLower(candidate), ".tsx") {
						targetPath = candidate
						break
					}
				}
			}
			if targetPath == "" {
				continue
			}
			module := shadcnUIModuleFromPath(targetPath)
			if module == "" {
				continue
			}
			req := requirements[targetPath]
			if req == nil {
				req = &shadcnUIExportRequirement{
					TargetPath: targetPath,
					Module:     module,
					Names:      map[string]bool{},
				}
				requirements[targetPath] = req
			}
			for _, name := range names {
				req.Names[name] = true
			}
		}
	}
	return requirements
}

func shadcnPascalName(slug string) string {
	parts := regexp.MustCompile(`[^A-Za-z0-9]+`).Split(slug, -1)
	var b strings.Builder
	for _, part := range parts {
		part = strings.TrimSpace(part)
		if part == "" {
			continue
		}
		b.WriteString(strings.ToUpper(part[:1]))
		if len(part) > 1 {
			b.WriteString(part[1:])
		}
	}
	if b.Len() == 0 {
		return "Primitive"
	}
	return sanitizeGeneratedIdentifier(b.String())
}

func shadcnKnownExports(module string) []string {
	switch module {
	case "badge":
		return []string{"Badge", "badgeVariants"}
	case "button":
		return []string{"Button", "buttonVariants"}
	case "card":
		return []string{"Card", "CardHeader", "CardFooter", "CardTitle", "CardDescription", "CardContent"}
	case "input":
		return []string{"Input"}
	case "label":
		return []string{"Label"}
	case "textarea":
		return []string{"Textarea"}
	case "select":
		return []string{"Select", "SelectGroup", "SelectValue", "SelectTrigger", "SelectContent", "SelectLabel", "SelectItem", "SelectSeparator"}
	case "dialog":
		return []string{"Dialog", "DialogTrigger", "DialogPortal", "DialogOverlay", "DialogContent", "DialogHeader", "DialogFooter", "DialogTitle", "DialogDescription", "DialogClose"}
	case "tabs":
		return []string{"Tabs", "TabsList", "TabsTrigger", "TabsContent"}
	case "table":
		return []string{"Table", "TableHeader", "TableBody", "TableFooter", "TableHead", "TableRow", "TableCell", "TableCaption"}
	case "avatar":
		return []string{"Avatar", "AvatarImage", "AvatarFallback"}
	case "separator":
		return []string{"Separator"}
	case "checkbox":
		return []string{"Checkbox"}
	case "switch":
		return []string{"Switch"}
	case "progress":
		return []string{"Progress"}
	case "sheet":
		return []string{"Sheet", "SheetTrigger", "SheetClose", "SheetContent", "SheetHeader", "SheetFooter", "SheetTitle", "SheetDescription"}
	default:
		return []string{shadcnPascalName(module)}
	}
}

func shadcnUIFallbackModuleContent(module string, importedNames []string) string {
	names := dedupeStringsPreserveOrder(append(shadcnKnownExports(module), importedNames...))
	mainName := shadcnPascalName(module)
	for _, name := range names {
		if isLikelyReactComponentName(name) {
			mainName = name
			break
		}
	}

	var b strings.Builder
	b.WriteString("import * as React from 'react';\n\n")
	b.WriteString("function cx(...classes: Array<string | false | null | undefined>) {\n")
	b.WriteString("  return classes.filter(Boolean).join(' ');\n")
	b.WriteString("}\n\n")
	b.WriteString("type PrimitiveProps = React.HTMLAttributes<HTMLDivElement> & {\n")
	b.WriteString("  asChild?: boolean;\n  variant?: string;\n  size?: string;\n  value?: string;\n  placeholder?: string;\n  checked?: boolean;\n  onValueChange?: (value: string) => void;\n  onCheckedChange?: (checked: boolean) => void;\n};\n\n")
	b.WriteString("function Primitive({ className = \"\", children, ...props }: PrimitiveProps) {\n")
	b.WriteString("  const { asChild: _asChild, variant: _variant, size: _size, value: _value, placeholder: _placeholder, checked: _checked, onValueChange: _onValueChange, onCheckedChange: _onCheckedChange, ...rest } = props;\n")
	b.WriteString("  return <div className={cx('rounded-xl border border-slate-700/70 bg-slate-900/70 text-slate-100 shadow-sm', className)} {...rest}>{children}</div>;\n")
	b.WriteString("}\n\n")

	writeComponent := func(name, element, propsType, baseClass string) {
		name = sanitizeGeneratedIdentifier(name)
		if name == "" {
			return
		}
		b.WriteString(fmt.Sprintf("export function %s({ className = \"\", children, ...props }: %s) {\n", name, propsType))
		if propsType == "PrimitiveProps" {
			b.WriteString("  return <Primitive className={cx('" + baseClass + "', className)} {...props}>{children}</Primitive>;\n")
		} else {
			b.WriteString(fmt.Sprintf("  return <%s className={cx('%s', className)} {...props}>{children}</%s>;\n", element, baseClass, element))
		}
		b.WriteString("}\n\n")
	}

	written := map[string]bool{}
	writeNamed := func(name string) {
		name = sanitizeGeneratedIdentifier(name)
		if name == "" || written[name] {
			return
		}
		written[name] = true
		switch name {
		case "Badge":
			b.WriteString("export function Badge({ className = \"\", children, ...props }: React.HTMLAttributes<HTMLSpanElement> & { variant?: string }) {\n")
			b.WriteString("  const { variant: _variant, ...rest } = props;\n")
			b.WriteString("  return <span className={cx('inline-flex items-center rounded-full border border-cyan-400/30 bg-cyan-400/10 px-2.5 py-0.5 text-xs font-semibold text-cyan-100', className)} {...rest}>{children}</span>;\n")
			b.WriteString("}\n\n")
		case "badgeVariants", "buttonVariants":
			b.WriteString(fmt.Sprintf("export function %s(..._args: unknown[]) {\n  return \"\";\n}\n\n", name))
		case "Button":
			b.WriteString("export function Button({ className = \"\", children, type = 'button', ...props }: React.ButtonHTMLAttributes<HTMLButtonElement> & { variant?: string; size?: string; asChild?: boolean }) {\n")
			b.WriteString("  const { variant: _variant, size: _size, asChild: _asChild, ...rest } = props;\n")
			b.WriteString("  return <button type={type} className={cx('inline-flex items-center justify-center rounded-xl bg-cyan-400 px-4 py-2 text-sm font-semibold text-slate-950 shadow-lg shadow-cyan-400/20 transition hover:bg-cyan-300 disabled:cursor-not-allowed disabled:opacity-60', className)} {...rest}>{children}</button>;\n")
			b.WriteString("}\n\n")
		case "Input":
			b.WriteString("export function Input({ className = \"\", ...props }: React.InputHTMLAttributes<HTMLInputElement>) {\n")
			b.WriteString("  return <input className={cx('h-10 w-full rounded-xl border border-slate-700 bg-slate-950/70 px-3 py-2 text-sm text-slate-100 outline-none transition placeholder:text-slate-500 focus:border-cyan-300 focus:ring-2 focus:ring-cyan-400/20', className)} {...props} />;\n")
			b.WriteString("}\n\n")
		case "Label":
			b.WriteString("export function Label({ className = \"\", children, ...props }: React.LabelHTMLAttributes<HTMLLabelElement>) {\n")
			b.WriteString("  return <label className={cx('text-sm font-medium text-slate-200', className)} {...props}>{children}</label>;\n")
			b.WriteString("}\n\n")
		case "Textarea":
			b.WriteString("export function Textarea({ className = \"\", ...props }: React.TextareaHTMLAttributes<HTMLTextAreaElement>) {\n")
			b.WriteString("  return <textarea className={cx('min-h-24 w-full rounded-xl border border-slate-700 bg-slate-950/70 px-3 py-2 text-sm text-slate-100 outline-none transition placeholder:text-slate-500 focus:border-cyan-300 focus:ring-2 focus:ring-cyan-400/20', className)} {...props} />;\n")
			b.WriteString("}\n\n")
		case "Card":
			writeComponent(name, "div", "React.HTMLAttributes<HTMLDivElement>", "rounded-2xl border border-slate-800 bg-slate-950/70 shadow-xl shadow-black/20")
		case "CardHeader", "CardFooter", "CardContent", "DialogHeader", "DialogFooter", "SheetHeader", "SheetFooter":
			writeComponent(name, "div", "React.HTMLAttributes<HTMLDivElement>", "space-y-2 p-5")
		case "CardTitle", "DialogTitle", "SheetTitle":
			writeComponent(name, "h3", "React.HTMLAttributes<HTMLHeadingElement>", "text-lg font-semibold text-slate-50")
		case "CardDescription", "DialogDescription", "SheetDescription":
			writeComponent(name, "p", "React.HTMLAttributes<HTMLParagraphElement>", "text-sm text-slate-400")
		case "Table":
			writeComponent(name, "table", "React.TableHTMLAttributes<HTMLTableElement>", "w-full caption-bottom text-sm")
		case "TableHeader":
			writeComponent(name, "thead", "React.HTMLAttributes<HTMLTableSectionElement>", "border-b border-slate-800")
		case "TableBody":
			writeComponent(name, "tbody", "React.HTMLAttributes<HTMLTableSectionElement>", "")
		case "TableFooter":
			writeComponent(name, "tfoot", "React.HTMLAttributes<HTMLTableSectionElement>", "border-t border-slate-800")
		case "TableRow":
			writeComponent(name, "tr", "React.HTMLAttributes<HTMLTableRowElement>", "border-b border-slate-800 transition hover:bg-slate-900/60")
		case "TableHead":
			writeComponent(name, "th", "React.ThHTMLAttributes<HTMLTableCellElement>", "h-10 px-3 text-left align-middle font-medium text-slate-400")
		case "TableCell":
			writeComponent(name, "td", "React.TdHTMLAttributes<HTMLTableCellElement>", "p-3 align-middle text-slate-200")
		case "TableCaption":
			writeComponent(name, "caption", "React.HTMLAttributes<HTMLTableCaptionElement>", "mt-4 text-sm text-slate-500")
		case "Checkbox", "Switch":
			b.WriteString(fmt.Sprintf("export function %s({ className = \"\", checked, onCheckedChange, ...props }: React.ButtonHTMLAttributes<HTMLButtonElement> & { checked?: boolean; onCheckedChange?: (checked: boolean) => void }) {\n", name))
			b.WriteString("  return <button type=\"button\" aria-pressed={checked} className={cx('h-5 w-9 rounded-full border border-cyan-400/40 bg-slate-900 text-cyan-200', className)} onClick={() => onCheckedChange?.(!checked)} {...props} />;\n")
			b.WriteString("}\n\n")
		case "Progress":
			b.WriteString("export function Progress({ className = \"\", value = 0, ...props }: React.HTMLAttributes<HTMLDivElement> & { value?: number }) {\n")
			b.WriteString("  return <div className={cx('h-2 overflow-hidden rounded-full bg-slate-800', className)} {...props}><div className='h-full bg-cyan-400' style={{ width: `${Math.max(0, Math.min(100, value))}%` }} /></div>;\n")
			b.WriteString("}\n\n")
		default:
			if strings.HasSuffix(name, "Props") {
				b.WriteString(fmt.Sprintf("export type %s = PrimitiveProps;\n\n", name))
			} else {
				writeComponent(name, "div", "PrimitiveProps", "p-2")
			}
		}
	}

	for _, name := range names {
		writeNamed(name)
	}
	if !written[mainName] {
		writeNamed(mainName)
	}
	if isLikelyReactComponentName(mainName) {
		b.WriteString(fmt.Sprintf("export default %s;\n", mainName))
	}
	return b.String()
}

func normalizeShadcnUIExportsInPatchPlan(files []GeneratedFile, plan *generatedFilePatchPlan) (bool, string) {
	requirements := collectShadcnUIExportRequirements(files)
	if len(requirements) == 0 || plan == nil {
		return false, ""
	}

	targets := make([]string, 0, len(requirements))
	for target := range requirements {
		targets = append(targets, target)
	}
	sort.Strings(targets)

	changed := false
	summaries := make([]string, 0, len(targets))
	for _, targetPath := range targets {
		req := requirements[targetPath]
		if req == nil || len(req.Names) == 0 {
			continue
		}
		names := make([]string, 0, len(req.Names))
		for name := range req.Names {
			names = append(names, name)
		}
		sort.Strings(names)
		content := plan.content(targetPath)
		allPresent := strings.TrimSpace(content) != ""
		for _, name := range names {
			if !generatedFileExportsNamedSymbol(content, name) {
				allPresent = false
				break
			}
		}
		if allPresent {
			continue
		}
		repaired := shadcnUIFallbackModuleContent(req.Module, names)
		language := "typescript"
		if strings.HasSuffix(strings.ToLower(targetPath), ".jsx") || strings.HasSuffix(strings.ToLower(targetPath), ".js") {
			language = "javascript"
		}
		applied := false
		if strings.TrimSpace(content) == "" {
			applied = plan.createFile(targetPath, repaired, language)
		} else {
			applied = plan.patchFile(targetPath, repaired, language)
		}
		if !applied {
			continue
		}
		changed = true
		summaries = append(summaries, fmt.Sprintf("%s exports %s", targetPath, strings.Join(names, ", ")))
	}
	if !changed {
		return false, ""
	}
	return true, "shadcn ui exports: " + strings.Join(summaries, "; ")
}

func readinessSuggestsShadcnUIExportRepair(readinessErrors []string) bool {
	for _, err := range readinessErrors {
		lower := strings.ToLower(err)
		if strings.Contains(lower, "components/ui/") && (strings.Contains(lower, "has no exported member") || strings.Contains(lower, "is not exported") || strings.Contains(lower, "has no default export")) {
			return true
		}
	}
	return false
}

func (am *AgentManager) applyDeterministicShadcnUIExportRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 || !readinessSuggestsShadcnUIExportRepair(readinessErrors) {
		return nil, ""
	}
	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 || plan == nil {
		return nil, ""
	}
	if changed, summary := normalizeShadcnUIExportsInPatchPlan(files, plan); changed {
		return am.bundleFromPatchPlan(build.ID, files, plan, "shadcn_ui_export_repair: "+summary), summary
	}
	return nil, ""
}

func (am *AgentManager) applyDeterministicExportMismatchRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}

	targets := parseExportMismatchRepairTargets(readinessErrors)
	if len(targets) == 0 {
		return nil, ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 {
		return nil, ""
	}

	existing := make(map[string]bool, len(files))
	for _, file := range files {
		path := sanitizeFilePath(file.Path)
		if path != "" {
			existing[strings.ToLower(path)] = true
		}
	}

	applied := make([]string, 0, len(targets))
	for _, target := range targets {
		exporterPath := sanitizeFilePath(target.ExporterPath)
		if exporterPath != "" && !existing[strings.ToLower(exporterPath)] {
			exporterPath = resolveGeneratedErrorPathCandidate(exporterPath, existing)
		}
		if exporterPath == "" && target.Specifier != "" {
			exporterPath = resolveExportMismatchTargetPath(target.ImporterPath, target.Specifier, existing)
		}
		if exporterPath == "" {
			continue
		}

		importerContent := plan.content(target.ImporterPath)
		exporterContent := plan.content(exporterPath)
		if target.PreferNamedImport && strings.TrimSpace(importerContent) != "" && strings.TrimSpace(exporterContent) != "" {
			if repaired, changed := rewriteDefaultImportToNamedImport(target.ImporterPath, importerContent, exporterPath, target.ExportName, exporterContent); changed {
				if plan.patchFile(target.ImporterPath, repaired, am.detectLanguage(target.ImporterPath)) {
					applied = append(applied, fmt.Sprintf("%s imports named export %s from %s", target.ImporterPath, firstNonEmptyString(target.ExportName, "matching default import"), exporterPath))
					continue
				}
			}
		}
		if strings.TrimSpace(importerContent) != "" {
			if repaired, changed := rewriteNamedImportToDefaultImport(target.ImporterPath, importerContent, exporterPath, target.ExportName); changed {
				if plan.patchFile(target.ImporterPath, repaired, am.detectLanguage(target.ImporterPath)) {
					applied = append(applied, fmt.Sprintf("%s imports %s from %s as default", target.ImporterPath, target.ExportName, exporterPath))
					continue
				}
			}
		}

		if strings.TrimSpace(exporterContent) == "" {
			continue
		}
		if repaired, changed := addNamedAliasForDefaultExport(exporterContent, target.ExportName); changed {
			if plan.patchFile(exporterPath, repaired, am.detectLanguage(exporterPath)) {
				applied = append(applied, fmt.Sprintf("%s re-exports default as %s", exporterPath, target.ExportName))
			}
		}
	}

	if len(applied) == 0 {
		return nil, ""
	}

	summary := "export mismatch repair: " + strings.Join(applied, ", ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "export_mismatch_repair: "+summary), summary
}

func knownMissingIdentifierModule(symbol string) string {
	switch strings.TrimSpace(symbol) {
	case "BrowserRouter", "Routes", "Route", "Navigate", "Outlet", "Link", "NavLink",
		"useNavigate", "useLocation", "useParams", "useSearchParams":
		return "react-router-dom"
	case "toast", "Toaster":
		return "sonner"
	case "DragDropContext", "Droppable", "Draggable":
		return "react-beautiful-dnd"
	case "ResponsiveContainer", "LineChart", "Line", "AreaChart", "Area", "BarChart", "Bar",
		"XAxis", "YAxis", "CartesianGrid", "Tooltip", "PieChart", "Pie", "Cell":
		return "recharts"
	default:
		return ""
	}
}

func parseMissingKnownImportRepairTargets(errors []string) []missingKnownImportRepairTarget {
	if len(errors) == 0 {
		return nil
	}

	re := regexp.MustCompile(`(?m)([^\s(:\n]+)\(\d+,\d+\): error TS(?:2304|2552): Cannot find name ['"]?([A-Za-z_][A-Za-z0-9_]*)['"]?`)
	seen := map[string]bool{}
	targets := make([]missingKnownImportRepairTarget, 0)
	for _, msg := range errors {
		for _, match := range re.FindAllStringSubmatch(msg, -1) {
			if len(match) != 3 {
				continue
			}
			path := sanitizeFilePath(strings.TrimSpace(match[1]))
			symbol := sanitizeGeneratedIdentifier(match[2])
			module := knownMissingIdentifierModule(symbol)
			if path == "" || symbol == "" || module == "" {
				continue
			}
			key := strings.ToLower(path + "::" + symbol + "::" + module)
			if seen[key] {
				continue
			}
			seen[key] = true
			targets = append(targets, missingKnownImportRepairTarget{
				Path:   path,
				Symbol: symbol,
				Module: module,
			})
		}
	}
	sort.Slice(targets, func(i, j int) bool {
		if targets[i].Path == targets[j].Path {
			return targets[i].Symbol < targets[j].Symbol
		}
		return targets[i].Path < targets[j].Path
	})
	return targets
}

func namedImportAlreadyPresent(content, module, symbol string) bool {
	importRe := regexp.MustCompile(`(?ms)import\s*\{([^}]*)\}\s*from\s*['"]` + regexp.QuoteMeta(module) + `['"]`)
	for _, match := range importRe.FindAllStringSubmatch(content, -1) {
		if len(match) != 2 {
			continue
		}
		for _, raw := range strings.Split(match[1], ",") {
			item := strings.TrimSpace(strings.TrimPrefix(strings.TrimSpace(raw), "type "))
			if item == "" {
				continue
			}
			parts := regexp.MustCompile(`\s+as\s+`).Split(item, 2)
			imported := strings.TrimSpace(parts[0])
			local := imported
			if len(parts) == 2 {
				local = strings.TrimSpace(parts[1])
			}
			if imported == symbol || local == symbol {
				return true
			}
		}
	}
	return false
}

func addNamedImportForMissingSymbol(content, module, symbol string) (string, bool) {
	if strings.TrimSpace(content) == "" || module == "" || symbol == "" {
		return content, false
	}
	if namedImportAlreadyPresent(content, module, symbol) {
		return content, false
	}

	importRe := regexp.MustCompile(`(?ms)import\s*\{([^}]*)\}\s*from\s*['"]` + regexp.QuoteMeta(module) + `['"]\s*;?`)
	if loc := importRe.FindStringSubmatchIndex(content); loc != nil && len(loc) >= 4 {
		inside := strings.TrimSpace(content[loc[2]:loc[3]])
		if inside == "" {
			inside = symbol
		} else {
			inside = inside + ", " + symbol
		}
		replacement := "import { " + inside + " } from " + strconv.Quote(module) + ";"
		return content[:loc[0]] + replacement + content[loc[1]:], true
	}

	sideEffectRe := regexp.MustCompile(`(?m)^\s*import\s+['"][^'"]+['"]\s*;?\s*$`)
	importLineRe := regexp.MustCompile(`(?m)^\s*import\s+.*?;\s*$`)
	insertAt := 0
	for _, loc := range importLineRe.FindAllStringIndex(content, -1) {
		if loc[1] > insertAt {
			insertAt = loc[1]
		}
	}
	for _, loc := range sideEffectRe.FindAllStringIndex(content, -1) {
		if loc[1] > insertAt {
			insertAt = loc[1]
		}
	}
	newImport := "import { " + symbol + " } from " + strconv.Quote(module) + ";\n"
	if insertAt > 0 {
		return content[:insertAt] + "\n" + newImport + content[insertAt:], true
	}
	return newImport + content, true
}

func (am *AgentManager) applyDeterministicMissingKnownImportRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}

	targets := parseMissingKnownImportRepairTargets(readinessErrors)
	if len(targets) == 0 {
		return nil, ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 || plan == nil {
		return nil, ""
	}

	applied := make([]string, 0, len(targets))
	for _, target := range targets {
		content := plan.content(target.Path)
		if strings.TrimSpace(content) == "" {
			continue
		}
		updated, changed := addNamedImportForMissingSymbol(content, target.Module, target.Symbol)
		if !changed {
			continue
		}
		if plan.patchFile(target.Path, updated, am.detectLanguage(target.Path)) {
			applied = append(applied, fmt.Sprintf("%s imports %s from %s", target.Path, target.Symbol, target.Module))
		}
	}
	if len(applied) == 0 {
		return nil, ""
	}

	sort.Strings(applied)
	summary := "missing known import repair: " + strings.Join(applied, ", ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "missing_known_import_repair: "+summary), summary
}

func isExternalGeneratedModuleSpecifier(specifier string) bool {
	specifier = strings.TrimSpace(specifier)
	if specifier == "" {
		return false
	}
	if strings.HasPrefix(specifier, ".") || strings.HasPrefix(specifier, "/") {
		return false
	}
	if strings.HasPrefix(specifier, "@/") || strings.HasPrefix(specifier, "~/") {
		return false
	}
	return true
}

