func rewriteInvalidNamedImportsFromExternalModule(content, module string, replacements map[string]string) (string, []string) {
	if strings.TrimSpace(content) == "" || strings.TrimSpace(module) == "" || len(replacements) == 0 {
		return content, nil
	}

	importRe := regexp.MustCompile(`(?ms)import\s*\{([^}]*)\}\s*from\s*['"]` + regexp.QuoteMeta(module) + `['"]\s*;?`)
	rewrites := make([]string, 0)
	updated := importRe.ReplaceAllStringFunc(content, func(match string) string {
		parts := importRe.FindStringSubmatch(match)
		if len(parts) != 2 {
			return match
		}

		specifiers := strings.Split(parts[1], ",")
		rewritten := make([]string, 0, len(specifiers))
		changed := false
		for _, raw := range specifiers {
			item := strings.TrimSpace(raw)
			if item == "" {
				continue
			}
			typePrefix := ""
			if strings.HasPrefix(item, "type ") {
				typePrefix = "type "
				item = strings.TrimSpace(strings.TrimPrefix(item, "type "))
			}

			sourceName := item
			localName := ""
			if fields := regexp.MustCompile(`\s+as\s+`).Split(item, 2); len(fields) == 2 {
				sourceName = strings.TrimSpace(fields[0])
				localName = strings.TrimSpace(fields[1])
			}
			if replacement, ok := replacements[sourceName]; ok && replacement != "" && typePrefix == "" {
				if localName == "" {
					localName = sourceName
				}
				if replacement == localName {
					rewritten = append(rewritten, replacement)
				} else {
					rewritten = append(rewritten, replacement+" as "+localName)
				}
				rewrites = append(rewrites, sourceName+"->"+replacement)
				changed = true
				continue
			}

			rewritten = append(rewritten, strings.TrimSpace(raw))
		}
		if !changed {
			return match
		}
		return "import { " + strings.Join(rewritten, ", ") + " } from " + strconv.Quote(module) + ";"
	})
	if updated == content {
		return content, nil
	}
	return updated, dedupeStrings(rewrites)
}

func packageNameFromNodeModulesPath(modulePath string) string {
	normalized := filepath.ToSlash(strings.Trim(modulePath, `"' `))
	lower := strings.ToLower(normalized)
	if idx := strings.Index(lower, "/node_modules/.vite/deps/"); idx >= 0 {
		rest := normalized[idx+len("/node_modules/.vite/deps/"):]
		rest = strings.TrimSuffix(rest, filepath.Ext(rest))
		rest = strings.Trim(rest, "/")
		if strings.Contains(rest, "__") {
			rest = strings.Split(rest, "__")[0]
		}
		if strings.HasPrefix(rest, "@") {
			parts := strings.Split(rest, "_")
			if len(parts) >= 2 {
				return parts[0] + "/" + parts[1]
			}
		}
		if rest != "" && !strings.HasPrefix(rest, ".") {
			return strings.Split(rest, "_")[0]
		}
	}
	marker := "node_modules/"
	idx := strings.Index(lower, marker)
	if idx < 0 {
		return ""
	}
	rest := strings.Trim(normalized[idx+len(marker):], "/")
	if rest == "" {
		return ""
	}
	parts := strings.Split(rest, "/")
	if len(parts) == 0 || parts[0] == "" {
		return ""
	}
	if strings.HasPrefix(parts[0], "@") && len(parts) >= 2 {
		return parts[0] + "/" + parts[1]
	}
	return parts[0]
}

func parseExternalDefaultImportRepairTargets(errors []string) []externalDefaultImportRepairTarget {
	if len(errors) == 0 {
		return nil
	}
	re := regexp.MustCompile(`(?m)([^\s(:\n]+)\(\d+,\d+\): error TS1192: Module ['"](.+?)['"] has no default export\.`)
	seen := map[string]bool{}
	targets := make([]externalDefaultImportRepairTarget, 0)
	for _, msg := range errors {
		for _, match := range re.FindAllStringSubmatch(msg, -1) {
			if len(match) != 3 {
				continue
			}
			importerPath := sanitizeFilePath(strings.TrimSpace(match[1]))
			packageName := packageNameFromNodeModulesPath(match[2])
			if importerPath == "" || packageName == "" {
				continue
			}
			key := strings.ToLower(importerPath + "::" + packageName)
			if seen[key] {
				continue
			}
			seen[key] = true
			targets = append(targets, externalDefaultImportRepairTarget{
				ImporterPath: importerPath,
				PackageName:  packageName,
			})
		}
	}
	sort.Slice(targets, func(i, j int) bool {
		if targets[i].ImporterPath == targets[j].ImporterPath {
			return targets[i].PackageName < targets[j].PackageName
		}
		return targets[i].ImporterPath < targets[j].ImporterPath
	})
	return targets
}

func namedExportForExternalDefaultImport(packageName, localName string) string {
	localName = sanitizeGeneratedIdentifier(localName)
	switch strings.TrimSpace(packageName) {
	case "zustand":
		return "create"
	case "lucide-react":
		return localName
	case "framer-motion":
		return "motion"
	case "sonner":
		if localName == "toast" || localName == "Toaster" {
			return localName
		}
	}
	return ""
}

func rewriteExternalDefaultImportToNamedImport(content, packageName string) (string, bool) {
	packageName = strings.TrimSpace(packageName)
	if strings.TrimSpace(content) == "" || packageName == "" {
		return content, false
	}
	importRe := regexp.MustCompile(`(?m)^(\s*import\s+)([A-Za-z_$][A-Za-z0-9_$]*)(\s*,\s*\{([^}]*)\})?(\s+from\s+['"]` + regexp.QuoteMeta(packageName) + `['"]\s*;?\s*)$`)
	matches := importRe.FindAllStringSubmatchIndex(content, -1)
	for _, match := range matches {
		if len(match) < 12 {
			continue
		}
		localName := content[match[4]:match[5]]
		namedExport := namedExportForExternalDefaultImport(packageName, localName)
		if namedExport == "" {
			continue
		}
		namedParts := make([]string, 0, 4)
		if namedExport == localName {
			namedParts = append(namedParts, namedExport)
		} else {
			namedParts = append(namedParts, namedExport+" as "+localName)
		}
		if len(match) >= 10 && match[8] >= 0 && match[9] >= 0 {
			for _, part := range strings.Split(content[match[8]:match[9]], ",") {
				part = strings.TrimSpace(part)
				if part == "" || strings.EqualFold(part, namedExport) || strings.Contains(part, namedExport+" as ") {
					continue
				}
				namedParts = append(namedParts, part)
			}
		}
		replacement := content[match[2]:match[3]] + "{ " + strings.Join(namedParts, ", ") + " }" + content[match[10]:match[11]]
		return content[:match[0]] + replacement + content[match[1]:], true
	}
	return content, false
}

func (am *AgentManager) applyDeterministicExternalDefaultImportRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}
	targets := parseExternalDefaultImportRepairTargets(readinessErrors)
	if len(targets) == 0 {
		return nil, ""
	}
	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 || plan == nil {
		return nil, ""
	}
	applied := make([]string, 0, len(targets))
	for _, target := range targets {
		content := plan.content(target.ImporterPath)
		if strings.TrimSpace(content) == "" {
			continue
		}
		updated, changed := rewriteExternalDefaultImportToNamedImport(content, target.PackageName)
		if !changed {
			continue
		}
		if plan.patchFile(target.ImporterPath, updated, am.detectLanguage(target.ImporterPath)) {
			applied = append(applied, fmt.Sprintf("%s rewrote default import from %s to named import", target.ImporterPath, target.PackageName))
		}
	}
	if len(applied) == 0 {
		return nil, ""
	}
	sort.Strings(applied)
	summary := "external default import repair: " + strings.Join(applied, "; ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "external_default_import_repair: "+summary), summary
}

func (am *AgentManager) applyDeterministicExternalImportExportRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}

	targets := parseExportMismatchRepairTargets(readinessErrors)
	if len(targets) == 0 {
		return nil, ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 || plan == nil {
		return nil, ""
	}

	replacementsByFileModule := map[string]map[string]string{}
	for _, target := range targets {
		module := strings.TrimSpace(target.Specifier)
		if !isExternalGeneratedModuleSpecifier(module) || target.ExportName == "" {
			continue
		}

		replacement := ""
		switch module {
		case "lucide-react":
			replacement = lucideReactKnownReplacement(target.ExportName)
		default:
			continue
		}
		if replacement == "" || replacement == target.ExportName {
			continue
		}

		key := sanitizeFilePath(target.ImporterPath) + "\x00" + module
		if replacementsByFileModule[key] == nil {
			replacementsByFileModule[key] = map[string]string{}
		}
		replacementsByFileModule[key][target.ExportName] = replacement
	}
	if len(replacementsByFileModule) == 0 {
		return nil, ""
	}

	applied := make([]string, 0, len(replacementsByFileModule))
	for key, replacements := range replacementsByFileModule {
		parts := strings.SplitN(key, "\x00", 2)
		if len(parts) != 2 || parts[0] == "" || parts[1] == "" {
			continue
		}
		path, module := parts[0], parts[1]
		content := plan.content(path)
		if strings.TrimSpace(content) == "" {
			continue
		}
		updated, rewrites := rewriteInvalidNamedImportsFromExternalModule(content, module, replacements)
		if len(rewrites) == 0 || updated == content {
			continue
		}
		if plan.patchFile(path, updated, am.detectLanguage(path)) {
			sort.Strings(rewrites)
			applied = append(applied, fmt.Sprintf("%s %s: %s", path, module, strings.Join(rewrites, ", ")))
		}
	}
	if len(applied) == 0 {
		return nil, ""
	}

	sort.Strings(applied)
	summary := "external import/export repair: " + strings.Join(applied, "; ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "external_import_export_repair: "+summary), summary
}

func parseSequelizeConstructorRepairTargets(errors []string) []string {
	if len(errors) == 0 {
		return nil
	}
	re := regexp.MustCompile(`(?m)([^\s(:\n]+)\(\d+,\d+\): error TS2769: No overload matches this call\.`)
	seen := map[string]bool{}
	targets := make([]string, 0)
	for _, msg := range errors {
		if !strings.Contains(msg, "Sequelize") {
			continue
		}
		for _, match := range re.FindAllStringSubmatch(msg, -1) {
			if len(match) != 2 {
				continue
			}
			path := sanitizeFilePath(strings.TrimSpace(match[1]))
			if path == "" || seen[strings.ToLower(path)] {
				continue
			}
			seen[strings.ToLower(path)] = true
			targets = append(targets, path)
		}
	}
	sort.Strings(targets)
	return targets
}

func parseSequelizeTypescriptTableRepairTargets(errors []string) []string {
	if len(errors) == 0 {
		return nil
	}
	re := regexp.MustCompile(`(?m)([^\s(:\n]+)\(\d+,\d+\): error TS2769: No overload matches this call\.`)
	seen := map[string]bool{}
	targets := make([]string, 0)
	for _, msg := range errors {
		if !strings.Contains(msg, "TableOptions<Model<any, any>>") {
			continue
		}
		for _, match := range re.FindAllStringSubmatch(msg, -1) {
			if len(match) != 2 {
				continue
			}
			path := sanitizeFilePath(strings.TrimSpace(match[1]))
			if path == "" || seen[strings.ToLower(path)] {
				continue
			}
			seen[strings.ToLower(path)] = true
			targets = append(targets, path)
		}
	}
	sort.Strings(targets)
	return targets
}

func rewriteSequelizeConstructorToObjectForm(content string) (string, bool) {
	if repaired, changed := rewriteSequelizeTypescriptConstructorToURLForm(content); changed {
		return repaired, true
	}
	if !strings.Contains(content, "new Sequelize(") || !strings.Contains(content, "models:") {
		return content, false
	}

	re := regexp.MustCompile(`(?s)export const sequelize = new Sequelize\(\s*database\s*,\s*username\s*,\s*password\s*,\s*\{(.*?)\}\s*\);`)
	matches := re.FindStringSubmatch(content)
	if len(matches) != 2 {
		return content, false
	}
	optionsBody := strings.TrimSpace(matches[1])
	replacement := "export const sequelize = new Sequelize({\n  database,\n  username,\n  password,\n" + indentMultiline(optionsBody, "  ") + "\n});"
	return re.ReplaceAllString(content, replacement), true
}

func detectDatabaseURLIdentifier(content string) string {
	re := regexp.MustCompile(`(?m)^\s*const\s+([A-Za-z_][A-Za-z0-9_]*)\s*=\s*process\.env\.DATABASE_URL\b`)
	matches := re.FindStringSubmatch(content)
	if len(matches) != 2 {
		return ""
	}
	return strings.TrimSpace(matches[1])
}

func stripSequelizeCredentialOptionLines(body string) string {
	lines := strings.Split(body, "\n")
	filtered := make([]string, 0, len(lines))
	for _, line := range lines {
		trimmed := strings.TrimSpace(line)
		switch {
		case strings.HasPrefix(trimmed, "database:"),
			strings.HasPrefix(trimmed, "username:"),
			strings.HasPrefix(trimmed, "password:"),
			strings.HasPrefix(trimmed, "host:"),
			strings.HasPrefix(trimmed, "port:"):
			continue
		default:
			filtered = append(filtered, line)
		}
	}
	return strings.TrimSpace(strings.Join(filtered, "\n"))
}

func rewriteSequelizeTypescriptConstructorToURLForm(content string) (string, bool) {
	if !strings.Contains(content, "sequelize-typescript") || !strings.Contains(content, "new Sequelize(") {
		return content, false
	}
	databaseURLIdentifier := detectDatabaseURLIdentifier(content)
	if databaseURLIdentifier == "" {
		return content, false
	}

	prefix := `((?:export\s+)?const\s+sequelize\s*=\s*new Sequelize)`
	fourArg := regexp.MustCompile(`(?s)` + prefix + `\(\s*database\s*,\s*username\s*,\s*password\s*,\s*\{(.*?)\}\s*\);`)
	if matches := fourArg.FindStringSubmatch(content); len(matches) == 3 {
		optionsBody := strings.TrimSpace(matches[2])
		replacement := matches[1] + "(" + databaseURLIdentifier + ", {\n" + indentMultiline(optionsBody, "  ") + "\n});"
		return fourArg.ReplaceAllString(content, replacement), true
	}

	objectForm := regexp.MustCompile(`(?s)` + prefix + `\(\s*\{(.*?)\}\s*\);`)
	matches := objectForm.FindStringSubmatch(content)
	if len(matches) != 3 {
		return content, false
	}
	optionsBody := stripSequelizeCredentialOptionLines(matches[2])
	if optionsBody == strings.TrimSpace(matches[2]) {
		return content, false
	}
	replacement := matches[1] + "(" + databaseURLIdentifier + ", {\n" + indentMultiline(optionsBody, "  ") + "\n});"
	return objectForm.ReplaceAllString(content, replacement), true
}

func rewriteSequelizeTypescriptRuntimeImport(content string) (string, bool) {
	if !strings.Contains(content, "new Sequelize(") || strings.Contains(content, "models:") {
		return content, false
	}

	replacements := []struct {
		old string
		new string
	}{
		{"import { Sequelize } from 'sequelize-typescript';", "import { Sequelize } from 'sequelize';"},
		{`import { Sequelize } from "sequelize-typescript";`, `import { Sequelize } from "sequelize";`},
	}
	for _, replacement := range replacements {
		if strings.Contains(content, replacement.old) {
			return strings.Replace(content, replacement.old, replacement.new, 1), true
		}
	}

	return content, false
}

func stripSequelizeTableIndexes(content string) (string, bool) {
	if !strings.Contains(content, "@Table({") || !strings.Contains(content, "indexes:") {
		return content, false
	}
	lines := strings.Split(content, "\n")
	filtered := make([]string, 0, len(lines))
	skipping := false
	bracketDepth := 0
	changed := false
	for _, line := range lines {
		trimmed := strings.TrimSpace(line)
		if !skipping && strings.HasPrefix(trimmed, "indexes:") {
			skipping = true
			bracketDepth = strings.Count(line, "[") - strings.Count(line, "]")
			changed = true
			if bracketDepth <= 0 {
				skipping = false
			}
			continue
		}
		if skipping {
			bracketDepth += strings.Count(line, "[")
			bracketDepth -= strings.Count(line, "]")
			if bracketDepth <= 0 {
				skipping = false
			}
			continue
		}
		filtered = append(filtered, line)
	}
	if !changed {
		return content, false
	}
	return strings.Join(filtered, "\n"), true
}

func indentMultiline(content string, prefix string) string {
	lines := strings.Split(content, "\n")
	for i, line := range lines {
		trimmed := strings.TrimRight(line, " \t")
		if strings.TrimSpace(trimmed) == "" {
			lines[i] = ""
			continue
		}
		lines[i] = prefix + strings.TrimLeft(trimmed, " \t")
	}
	return strings.Join(lines, "\n")
}

func (am *AgentManager) applyDeterministicSequelizeConstructorRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}

	targets := parseSequelizeConstructorRepairTargets(readinessErrors)
	if len(targets) == 0 {
		return nil, ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 {
		return nil, ""
	}

	applied := make([]string, 0, len(targets))
	for _, target := range targets {
		content := plan.content(target)
		if strings.TrimSpace(content) == "" {
			continue
		}
		repaired, changed := rewriteSequelizeConstructorToObjectForm(content)
		if !changed {
			repaired, changed = rewriteSequelizeTypescriptRuntimeImport(content)
		}
		if !changed {
			continue
		}
		if !plan.patchFile(target, repaired, am.detectLanguage(target)) {
			continue
		}
		applied = append(applied, target)
	}
	if len(applied) == 0 {
		return nil, ""
	}

	summary := "sequelize constructor normalization on " + strings.Join(applied, ", ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "sequelize_constructor_repair: "+summary), summary
}

