func (am *AgentManager) applyDeterministicBrokenGeneratedTestRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}

	compilerOutput := strings.Join(readinessErrors, "\n")
	targets := ExtractBrokenTestPaths(compilerOutput)
	if len(targets) == 0 {
		return nil, ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 {
		return nil, ""
	}

	contents := make(map[string]string, len(targets))
	for _, target := range targets {
		contents[target] = plan.content(target)
	}
	repairs := RepairAll(compilerOutput, contents)
	applied := make([]string, 0, len(repairs))
	for _, repair := range repairs {
		repairedContent := repair.RepairedContent
		strategy := string(repair.Strategy)
		if shouldForceGeneratedTestPlaceholderRepair(repair.FilePath, compilerOutput) {
			repairedContent = placeholderGeneratedTestFileContent(repair.FilePath)
			strategy = string(StrategyPlaceholder)
		}
		if strings.TrimSpace(repairedContent) == "" {
			continue
		}
		if !plan.patchFile(repair.FilePath, repairedContent, am.detectLanguage(repair.FilePath)) {
			continue
		}
		applied = append(applied, fmt.Sprintf("%s (%s)", repair.FilePath, strategy))
	}
	if len(applied) == 0 {
		return nil, ""
	}

	summary := "generated test placeholder repair: " + strings.Join(applied, ", ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "generated_test_repair: "+summary), summary
}

func shouldForceGeneratedTestPlaceholderRepair(path string, compilerOutput string) bool {
	path = strings.ToLower(filepath.ToSlash(strings.TrimSpace(path)))
	if path == "" {
		return false
	}

	// Backend/server-side generated tests are non-critical to preview viability.
	// When they are broken, the safest deterministic path is a framework-free
	// placeholder instead of preserving brittle imports and route assumptions.
	if strings.HasPrefix(path, "server/") || strings.Contains(path, "/server/") ||
		strings.HasPrefix(path, "backend/") || strings.Contains(path, "/backend/") {
		return true
	}

	lowerOutput := strings.ToLower(compilerOutput)
	if !strings.Contains(lowerOutput, path) {
		return false
	}

	backendTestMarkers := []string{
		"supertest",
		`has no exported member 'apirouter'`,
		`has no exported member "apirouter"`,
		"cannot find name 'describe'",
		"cannot find name 'it'",
		"cannot find name 'expect'",
		"cannot find name 'beforeeach'",
	}
	for _, marker := range backendTestMarkers {
		if strings.Contains(lowerOutput, marker) {
			return true
		}
	}

	return false
}

func parseMissingTypePackagesFromBuildErrors(errors []string) []string {
	if len(errors) == 0 {
		return nil
	}
	re := regexp.MustCompile(`TS7016: Could not find a declaration file for module '([^']+)'`)
	seen := map[string]bool{}
	pkgs := make([]string, 0)
	for _, msg := range errors {
		matches := re.FindAllStringSubmatch(msg, -1)
		for _, m := range matches {
			if len(m) != 2 {
				continue
			}
			mod := strings.TrimSpace(m[1])
			if mod == "" {
				continue
			}
			typePkg := typePackageForModule(mod)
			if typePkg == "" || seen[typePkg] {
				continue
			}
			seen[typePkg] = true
			pkgs = append(pkgs, typePkg)
		}
	}
	sort.Strings(pkgs)
	return pkgs
}

func parseImplicitAnyParameterTargets(errors []string, parameter string) []string {
	if len(errors) == 0 || strings.TrimSpace(parameter) == "" {
		return nil
	}
	re := regexp.MustCompile(fmt.Sprintf(`([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx))\(\d+,\d+\): error TS7006: Parameter '%s' implicitly has an 'any' type\.`, regexp.QuoteMeta(parameter)))
	seen := map[string]bool{}
	paths := make([]string, 0, 2)
	for _, msg := range errors {
		for _, match := range re.FindAllStringSubmatch(msg, -1) {
			if len(match) != 2 {
				continue
			}
			path := normalizePreviewSyntaxErrorPath(match[1])
			if path == "" || seen[path] {
				continue
			}
			seen[path] = true
			paths = append(paths, path)
		}
	}
	sort.Strings(paths)
	return paths
}

type implicitAnyParameterRepairTarget struct {
	Path      string
	Line      int
	Column    int
	Parameter string
}

func parseImplicitAnyParameterRepairTargets(errors []string) []implicitAnyParameterRepairTarget {
	if len(errors) == 0 {
		return nil
	}
	re := regexp.MustCompile(`([A-Za-z0-9_./\\:-]+\.(?:ts|tsx|js|jsx))\((\d+),(\d+)\): error TS7006: Parameter '([^']+)' implicitly has an 'any' type\.`)
	seen := map[string]bool{}
	targets := make([]implicitAnyParameterRepairTarget, 0, 2)
	for _, msg := range errors {
		for _, match := range re.FindAllStringSubmatch(msg, -1) {
			if len(match) != 5 {
				continue
			}
			path := normalizePreviewSyntaxErrorPath(match[1])
			param := strings.TrimSpace(match[4])
			if path == "" || param == "" {
				continue
			}
			line, _ := strconv.Atoi(match[2])
			column, _ := strconv.Atoi(match[3])
			key := fmt.Sprintf("%s:%d:%d:%s", path, line, column, param)
			if seen[key] {
				continue
			}
			seen[key] = true
			targets = append(targets, implicitAnyParameterRepairTarget{
				Path:      path,
				Line:      line,
				Column:    column,
				Parameter: param,
			})
		}
	}
	sort.Slice(targets, func(i, j int) bool {
		if targets[i].Path != targets[j].Path {
			return targets[i].Path < targets[j].Path
		}
		if targets[i].Line != targets[j].Line {
			return targets[i].Line < targets[j].Line
		}
		if targets[i].Column != targets[j].Column {
			return targets[i].Column < targets[j].Column
		}
		return targets[i].Parameter < targets[j].Parameter
	})
	return targets
}

func typePackageForModule(module string) string {
	module = strings.TrimSpace(module)
	if module == "" {
		return ""
	}
	switch module {
	case "express", "cors", "jsonwebtoken", "body-parser", "bcrypt", "uuid", "pg", "lodash", "lodash-es":
		return "@types/" + module
	case "react", "react/jsx-runtime":
		return "@types/react"
	case "react-dom", "react-dom/client":
		return "@types/react-dom"
	}
	// Skip modules that commonly bundle types or don't map cleanly.
	if strings.HasPrefix(module, "@") {
		return ""
	}
	return ""
}

var generatedErrorEventCallbackPattern = regexp.MustCompile(`(\.on\(\s*['"]error['"]\s*,\s*\()([A-Za-z_][A-Za-z0-9_]*)(\)\s*=>)`)

func annotateGeneratedErrorEventCallbackParameter(path, content string) (string, bool) {
	if strings.TrimSpace(content) == "" {
		return content, false
	}
	normalizedPath := strings.ToLower(strings.TrimSpace(filepath.ToSlash(path)))
	if !strings.HasSuffix(normalizedPath, "/db/index.ts") &&
		!strings.HasSuffix(normalizedPath, "/db/index.tsx") &&
		!strings.HasSuffix(normalizedPath, "/db/index.js") &&
		!strings.HasSuffix(normalizedPath, "/db/index.jsx") &&
		!strings.HasSuffix(normalizedPath, "db/index.ts") &&
		!strings.HasSuffix(normalizedPath, "db/index.js") {
		return content, false
	}

	updated := generatedErrorEventCallbackPattern.ReplaceAllString(content, `${1}${2}: Error${3}`)
	if updated == content {
		return content, false
	}
	return updated, true
}

func inferImplicitAnyParameterType(parameter string) string {
	normalized := strings.ToLower(strings.TrimSpace(parameter))
	switch {
	case normalized == "err" || normalized == "error":
		return "Error"
	case normalized == "index" || normalized == "idx" || normalized == "i":
		return "number"
	case normalized == "event" || normalized == "evt":
		return "Event"
	case normalized == "e":
		return "React.ChangeEvent<HTMLInputElement>"
	case normalized == "key" || normalized == "slug" || normalized == "status" || normalized == "name" || normalized == "title":
		return "string"
	case strings.HasSuffix(normalized, "id") || strings.Contains(normalized, "id"):
		return "string"
	default:
		// Explicit any is intentionally used only as a last-resort repair for
		// noImplicitAny callback parameters. It preserves runtime behavior and
		// prevents the verifier from falling into expensive LLM rewrite loops.
		return "any"
	}
}

func annotateImplicitAnyArrowParameterLine(line string, target implicitAnyParameterRepairTarget) (string, bool) {
	param := strings.TrimSpace(target.Parameter)
	if param == "" || strings.Contains(param, ":") {
		return line, false
	}
	typ := inferImplicitAnyParameterType(param)
	updated := line
	changed := false

	parenthesized := regexp.MustCompile(`\(([^()]*)\)\s*=>`)
	updated = parenthesized.ReplaceAllStringFunc(updated, func(match string) string {
		open := strings.Index(match, "(")
		close := strings.LastIndex(match, ")")
		if open == -1 || close == -1 || close <= open {
			return match
		}
		paramList := match[open+1 : close]
		parts := strings.Split(paramList, ",")
		localChanged := false
		for i, part := range parts {
			trimmed := strings.TrimSpace(part)
			if trimmed != param || strings.Contains(trimmed, ":") || strings.Contains(trimmed, "{") || strings.Contains(trimmed, "[") {
				continue
			}
			prefix := part[:len(part)-len(strings.TrimLeft(part, " \t"))]
			suffix := part[len(strings.TrimRight(part, " \t")):]
			parts[i] = prefix + param + ": " + typ + suffix
			localChanged = true
		}
		if !localChanged {
			return match
		}
		changed = true
		return "(" + strings.Join(parts, ",") + ")" + match[close+1:]
	})

	if changed {
		return updated, true
	}

	unparenthesized := regexp.MustCompile(`\b` + regexp.QuoteMeta(param) + `\s*=>`)
	updated = unparenthesized.ReplaceAllString(updated, "("+param+": "+typ+") =>")
	if updated != line {
		return updated, true
	}

	return line, false
}

func annotateImplicitAnyArrowParameter(content string, target implicitAnyParameterRepairTarget) (string, bool) {
	if strings.TrimSpace(content) == "" || strings.TrimSpace(target.Parameter) == "" {
		return content, false
	}
	lines := strings.Split(content, "\n")
	if len(lines) == 0 {
		return content, false
	}

	candidates := make([]int, 0, 5)
	if target.Line > 0 && target.Line <= len(lines) {
		start := target.Line - 3
		if start < 0 {
			start = 0
		}
		end := target.Line + 2
		if end > len(lines) {
			end = len(lines)
		}
		for i := start; i < end; i++ {
			candidates = append(candidates, i)
		}
	} else {
		for i := range lines {
			candidates = append(candidates, i)
		}
	}

	changed := false
	for _, idx := range candidates {
		updated, lineChanged := annotateImplicitAnyArrowParameterLine(lines[idx], target)
		if !lineChanged {
			continue
		}
		lines[idx] = updated
		changed = true
		break
	}
	if !changed {
		return content, false
	}
	return strings.Join(lines, "\n"), true
}

func requiresViteEnvTypeDeclarationRepair(files []GeneratedFile, errors []string) bool {
	if len(files) == 0 || len(errors) == 0 {
		return false
	}

	hasImportMetaTypeError := false
	for _, msg := range errors {
		lower := strings.ToLower(strings.TrimSpace(msg))
		if strings.Contains(lower, "property 'env' does not exist on type 'importmeta'") ||
			strings.Contains(lower, "cannot find name 'importmetaenv'") ||
			(strings.Contains(lower, "importmetaenv") && strings.Contains(msg, "VITE_")) {
			hasImportMetaTypeError = true
			break
		}
	}
	if !hasImportMetaTypeError {
		return false
	}

	for _, file := range files {
		lowerPath := strings.ToLower(strings.TrimSpace(file.Path))
		if strings.Contains(lowerPath, "vite.config") || strings.Contains(file.Content, "import.meta.env") {
			return true
		}
	}
	return false
}

func viteEnvDeclarationPathFromManifest(manifestPath string) string {
	sanitized := sanitizeFilePath(manifestPath)
	if sanitized == "" {
		return ""
	}
	prefix := strings.TrimSuffix(filepath.ToSlash(sanitized), "package.json")
	return filepath.ToSlash(filepath.Join(prefix, "src", "vite-env.d.ts"))
}

func viteEnvDeclarationContent() string {
	return `/// <reference types="vite/client" />

interface ImportMetaEnv {
  readonly [key: string]: string | boolean | undefined
  readonly VITE_API_URL?: string
  readonly VITE_API_BASE_URL?: string
  readonly VITE_WS_URL?: string
}

interface ImportMeta {
  readonly env: ImportMetaEnv
}
`
}

func (am *AgentManager) ensureGeneratedViteEnvDeclaration(plan *generatedFilePatchPlan, manifestPath string) (bool, string) {
	targetPath := viteEnvDeclarationPathFromManifest(manifestPath)
	if targetPath == "" {
		return false, ""
	}

	content := viteEnvDeclarationContent()
	if strings.TrimSpace(plan.content(targetPath)) != "" {
		if strings.TrimSpace(plan.content(targetPath)) == strings.TrimSpace(content) {
			return false, ""
		}
		if plan.patchFile(targetPath, content, "typescript") {
			return true, targetPath
		}
		return false, ""
	}

	if plan.createFile(targetPath, content, "typescript") {
		return true, targetPath
	}
	return false, ""
}

func generatedFrontendPackageUsesESModule(files []GeneratedFile, plan *generatedFilePatchPlan) bool {
	if plan == nil {
		return false
	}
	manifestPath := findGeneratedManifestPath(files, []string{
		"frontend/package.json",
		"client/package.json",
		"web/package.json",
		"apps/web/package.json",
		"apps/frontend/package.json",
		"packages/web/package.json",
		"packages/frontend/package.json",
		"package.json",
	})
	if manifestPath == "" {
		return false
	}
	return manifestContentUsesESModulePackage(plan.content(manifestPath))
}

func generatedFilesFrontendPackageUsesESModule(files []GeneratedFile) bool {
	manifestPath := findGeneratedManifestPath(files, []string{
		"frontend/package.json",
		"client/package.json",
		"web/package.json",
		"apps/web/package.json",
		"apps/frontend/package.json",
		"packages/web/package.json",
		"packages/frontend/package.json",
		"package.json",
	})
	if manifestPath == "" {
		return false
	}
	for _, file := range files {
		if strings.EqualFold(strings.TrimSpace(file.Path), manifestPath) {
			return manifestContentUsesESModulePackage(file.Content)
		}
	}
	return false
}

// ensureGeneratedTailwindConfig inspects generated files and repairs the three
// files that Tailwind CSS v3 requires: tailwind.config.js, postcss.config.js,
// and src/index.css (the @tailwind directives). Returns the number of files
// created or patched and a short summary string.
//
// It also removes @tailwindcss/vite from package.json when present (that is the
// Tailwind v4 Vite plugin — it is incompatible with the tailwind.config.js
// approach we use for v3).
func ensureGeneratedTailwindConfig(plan *generatedFilePatchPlan, files []GeneratedFile) (int, string) {
	// Detect whether this build uses Tailwind at all.
	usesTailwind := false
	hasTailwindPkg := false
	for _, f := range files {
		p := filepath.ToSlash(strings.TrimSpace(f.Path))
		if (p == "package.json" || strings.HasSuffix(p, "/package.json")) &&
			strings.Contains(f.Content, `"tailwindcss"`) {
			hasTailwindPkg = true
			usesTailwind = true
		}
		// Quick class-name heuristic: common Tailwind utility prefixes in JSX files.
		if (strings.HasSuffix(p, ".tsx") || strings.HasSuffix(p, ".jsx")) &&
			(strings.Contains(f.Content, `className="`) || strings.Contains(f.Content, "className={")) {
			usesTailwind = true
		}
	}
	if !usesTailwind {
		return 0, ""
	}

	repaired := 0
	var parts []string

	// ── 1. tailwind.config.js ────────────────────────────────────────────────
	twPath := ""
	for _, f := range files {
		p := filepath.ToSlash(strings.TrimSpace(f.Path))
		if p == "tailwind.config.js" || p == "tailwind.config.ts" || p == "tailwind.config.cjs" {
			twPath = p
			break
		}
	}

	if twPath == "" {
		// Missing entirely — create it.
		packageUsesESM := generatedFrontendPackageUsesESModule(files, plan)
		canonical := syntheticFrontendTailwindConfigForPath("tailwind.config.js", packageUsesESM)
		if plan.createFile("tailwind.config.js", canonical, "javascript") {
			repaired++
			parts = append(parts, "created tailwind.config.js")
		}
		twPath = "tailwind.config.js"
	} else {
		packageUsesESM := generatedFrontendPackageUsesESModule(files, plan)
		canonical := syntheticFrontendTailwindConfigForPath(twPath, packageUsesESM)
		existing := plan.content(twPath)
		// Fix empty content array or missing content field.
		needsRewrite := false
		if strings.Contains(existing, "content: []") || strings.Contains(existing, "content:[]") {
			needsRewrite = true
		}
		if !strings.Contains(existing, "index.html") || !strings.Contains(existing, "src/**") {
			needsRewrite = true
		}
		// Fix v4 setup: @import "tailwindcss" or @tailwindcss/vite plugin reference.
		if strings.Contains(existing, "@tailwindcss/vite") || strings.Contains(existing, `@import "tailwindcss"`) || strings.Contains(existing, `@import 'tailwindcss'`) {
			needsRewrite = true
		}
		if configSyntaxConflictsWithModuleMode(twPath, existing, packageUsesESM) {
			needsRewrite = true
		}
		if needsRewrite {
			if plan.patchFile(twPath, canonical, "javascript") {
				repaired++
				parts = append(parts, "fixed tailwind.config.js content paths")
			}
		}
	}

	// ── 2. postcss.config.js ─────────────────────────────────────────────────
	hasPostCSS := false
	packageUsesESM := generatedFrontendPackageUsesESModule(files, plan)
	for _, f := range files {
		p := filepath.ToSlash(strings.TrimSpace(f.Path))
		if p == "postcss.config.js" || p == "postcss.config.cjs" || p == "postcss.config.mjs" {
			hasPostCSS = true
			content := plan.content(p)
			// Check it actually has the Tailwind plugins and uses syntax Node can load for this package.
			if !strings.Contains(content, "tailwindcss") ||
				!strings.Contains(content, "autoprefixer") ||
				configSyntaxConflictsWithModuleMode(p, content, packageUsesESM) {
				if plan.patchFile(p, syntheticFrontendPostCSSConfigForPath(p, packageUsesESM), "javascript") {
					repaired++
					parts = append(parts, "fixed postcss.config.js plugins")
				}
			}
			break
		}
	}
	if !hasPostCSS {
		if plan.createFile("postcss.config.js", syntheticFrontendPostCSSConfigForPath("postcss.config.js", packageUsesESM), "javascript") {
			repaired++
			parts = append(parts, "created postcss.config.js")
		}
	}

	// ── 3. src/index.css ─────────────────────────────────────────────────────
	cssPath := ""
	for _, f := range files {
		p := filepath.ToSlash(strings.TrimSpace(f.Path))
		if p == "src/index.css" || p == "src/globals.css" || p == "src/main.css" || p == "src/styles.css" {
			cssPath = p
			break
		}
	}

	twDirectives := "@tailwind base;\n@tailwind components;\n@tailwind utilities;"
	if cssPath == "" {
		if plan.createFile("src/index.css", syntheticFrontendIndexCSS(), "css") {
			repaired++
			parts = append(parts, "created src/index.css with @tailwind directives")
		}
	} else {
		existing := plan.content(cssPath)
		if !strings.Contains(existing, "@tailwind base") && !strings.Contains(existing, `@import "tailwindcss"`) && !strings.Contains(existing, `@import 'tailwindcss'`) {
			patched := twDirectives + "\n\n" + existing
			if plan.patchFile(cssPath, patched, "css") {
				repaired++
				parts = append(parts, "prepended @tailwind directives to "+cssPath)
			}
		} else if strings.Contains(existing, `@import "tailwindcss"`) || strings.Contains(existing, `@import 'tailwindcss'`) {
			// v4 single-import syntax — convert to v3 directives.
			lines := strings.Split(existing, "\n")
			filtered := make([]string, 0, len(lines))
			for _, l := range lines {
				trimmed := strings.TrimSpace(l)
				if trimmed == `@import "tailwindcss";` || trimmed == `@import 'tailwindcss';` {
					continue
				}
				filtered = append(filtered, l)
			}
			patched := twDirectives + "\n\n" + strings.TrimSpace(strings.Join(filtered, "\n"))
			if plan.patchFile(cssPath, patched, "css") {
				repaired++
				parts = append(parts, "converted v4 @import to v3 directives in "+cssPath)
			}
		}
	}

	// ── 4. Remove @tailwindcss/vite from package.json ────────────────────────
	if hasTailwindPkg {
		for _, f := range files {
			p := filepath.ToSlash(strings.TrimSpace(f.Path))
			if p != "package.json" && !strings.HasSuffix(p, "/package.json") {
				continue
			}
			content := plan.content(p)
			if !strings.Contains(content, "@tailwindcss/vite") {
				break
			}
			// Remove the @tailwindcss/vite line from the JSON source.
			cleaned := removeJSONDependencyLine(content, "@tailwindcss/vite")
			if cleaned != content {
				if plan.patchFile(p, cleaned, "json") {
					repaired++
					parts = append(parts, "removed @tailwindcss/vite from "+p+" (v4 plugin incompatible with v3 setup)")
				}
			}
			break
		}
	}

	if repaired == 0 {
		return 0, ""
	}
	return repaired, strings.Join(parts, "; ")
}

// removeJSONDependencyLine removes a specific package entry from a JSON dependency
// string without parsing it, to handle malformed JSON gracefully.
func removeJSONDependencyLine(content, pkg string) string {
	lines := strings.Split(content, "\n")
	result := make([]string, 0, len(lines))
	pkgQuoted := `"` + pkg + `"`
	for i, line := range lines {
		if strings.Contains(line, pkgQuoted) {
			// Remove the line and fix any trailing comma on the previous non-empty line.
			if i > 0 && len(result) > 0 {
				prev := result[len(result)-1]
				if strings.HasSuffix(strings.TrimSpace(prev), ",") {
					// Check if the next non-empty line starts a closing brace/bracket.
					nextIdx := i + 1
					for nextIdx < len(lines) && strings.TrimSpace(lines[nextIdx]) == "" {
						nextIdx++
					}
					if nextIdx < len(lines) {
						nextTrimmed := strings.TrimSpace(lines[nextIdx])
						if strings.HasPrefix(nextTrimmed, "}") || strings.HasPrefix(nextTrimmed, "]") {
							result[len(result)-1] = strings.TrimRight(prev, ",") + strings.TrimRight(prev[len(strings.TrimRight(prev, ",")):], ",")
							result[len(result)-1] = strings.Replace(prev, strings.TrimSpace(prev), strings.TrimRight(strings.TrimSpace(prev), ","), 1)
						}
					}
				}
			}
			continue
		}
		result = append(result, line)
	}
	return strings.Join(result, "\n")
}

func (am *AgentManager) applyDeterministicTypeDeclarationRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}
	typePkgs := parseMissingTypePackagesFromBuildErrors(readinessErrors)
	implicitAnyTargets := parseImplicitAnyParameterTargets(readinessErrors, "err")
	implicitAnyParameterTargets := parseImplicitAnyParameterRepairTargets(readinessErrors)
	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 {
		return nil, ""
	}
	needsViteEnvDeclaration := requiresViteEnvTypeDeclarationRepair(files, readinessErrors)
	if len(typePkgs) == 0 && !needsViteEnvDeclaration && len(implicitAnyTargets) == 0 && len(implicitAnyParameterTargets) == 0 {
		return nil, ""
	}

	candidates := []string{
		"frontend/package.json",
		"client/package.json",
		"web/package.json",
		"apps/web/package.json",
		"apps/frontend/package.json",
		"packages/web/package.json",
		"packages/frontend/package.json",
		"backend/package.json",
		"api/package.json",
		"server/package.json",
		"apps/api/package.json",
		"packages/backend/package.json",
		"package.json",
	}
	manifestPath := findGeneratedManifestPath(files, candidates)
	if manifestPath == "" {
		return nil, ""
	}

	applied := make([]string, 0, 2)
	if len(typePkgs) > 0 {
		current := plan.content(manifestPath)
		if strings.TrimSpace(current) != "" {
			updated, added := patchManifestDependenciesJSON(current, typePkgs)
			if len(added) > 0 && plan.patchFile(manifestPath, updated, "json") {
				applied = append(applied, fmt.Sprintf("%s (%s)", manifestPath, strings.Join(added, ", ")))
			}
		}
	}
	if needsViteEnvDeclaration {
		if repaired, summary := am.ensureGeneratedViteEnvDeclaration(plan, manifestPath); repaired {
			applied = append(applied, summary)
		}
	}
	for _, target := range implicitAnyTargets {
		current := plan.content(target)
		if strings.TrimSpace(current) == "" {
			continue
		}
		updated, changed := annotateGeneratedErrorEventCallbackParameter(target, current)
		if !changed {
			continue
		}
		if plan.patchFile(target, updated, am.detectLanguage(target)) {
			applied = append(applied, fmt.Sprintf("%s (typed error callback)", target))
		}
	}
	for _, target := range implicitAnyParameterTargets {
		current := plan.content(target.Path)
		if strings.TrimSpace(current) == "" {
			continue
		}
		updated, changed := annotateImplicitAnyArrowParameter(current, target)
		if !changed {
			continue
		}
		if plan.patchFile(target.Path, updated, am.detectLanguage(target.Path)) {
			applied = append(applied, fmt.Sprintf("%s (typed %s callback parameter)", target.Path, target.Parameter))
		}
	}

	if len(applied) == 0 {
		return nil, ""
	}
	summary := strings.Join(applied, "; ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "type_package_repair: "+summary), summary
}

func parseMissingDependencyNamesFromIssues(issues []string) []string {
	if len(issues) == 0 {
		return nil
	}
	reMissing := regexp.MustCompile(`does not declare dependency "([^"]+)"`)
	reTSMissing := regexp.MustCompile(`Cannot find module ['"]([^'"]+)['"]`)
	seen := map[string]bool{}
	pkgs := make([]string, 0, len(issues))
	for _, issue := range issues {
		matches := reMissing.FindAllStringSubmatch(strings.TrimSpace(issue), -1)
		for _, match := range matches {
			if len(match) != 2 {
				continue
			}
			pkg := canonicalGeneratedDependencyName(match[1])
			if pkg == "" || seen[pkg] {
				continue
			}
			seen[pkg] = true
			pkgs = append(pkgs, pkg)
		}
		matches = reTSMissing.FindAllStringSubmatch(strings.TrimSpace(issue), -1)
		for _, match := range matches {
			if len(match) != 2 {
				continue
			}
			pkg := packageNameFromImportPath(match[1])
			if pkg == "" || seen[pkg] {
				continue
			}
			seen[pkg] = true
			pkgs = append(pkgs, pkg)
		}
	}
	sort.Strings(pkgs)
	return pkgs
}

func buildScriptUsesTypeScriptCompiler(manifest previewManifest) bool {
	return strings.Contains(strings.ToLower(strings.TrimSpace(manifest.Scripts["build"])), "tsc")
}

func manifestUsesVite(manifest previewManifest) bool {
	for _, name := range []string{"build", "dev", "preview"} {
		if strings.Contains(strings.ToLower(strings.TrimSpace(manifest.Scripts[name])), "vite") {
			return true
		}
	}
	return manifestDeclaresDependency(manifest, "vite")
}

func manifestUsesVitest(manifest previewManifest) bool {
	script := strings.ToLower(strings.TrimSpace(manifest.Scripts["test"]))
	return strings.Contains(script, "vitest") || manifestDeclaresDependency(manifest, "vitest")
}

func manifestUsesJest(manifest previewManifest) bool {
	script := strings.ToLower(strings.TrimSpace(manifest.Scripts["test"]))
	return strings.Contains(script, "jest") || manifestDeclaresDependency(manifest, "jest")
}

type generatedPackageSignals struct {
	hasImportMetaEnv              bool
	hasNodeTests                  bool
	usesTestingLibrary            bool
	usesJestDOM                   bool
	usesJestGlobals               bool
	usesVitestConfigImport        bool
	usesPostCSSConfig             bool
	usesPostCSSConfigTailwind     bool
	usesPostCSSConfigAutoprefixer bool
}

func inspectGeneratedPackageSignals(files []GeneratedFile, prefix string) generatedPackageSignals {
	signals := generatedPackageSignals{}
	prefixLower := strings.ToLower(prefix)
	for _, file := range files {
		path := strings.ToLower(filepath.ToSlash(strings.TrimPrefix(strings.TrimSpace(file.Path), "./")))
		if path == "" {
			continue
		}
		if prefixLower != "" {
			if !strings.HasPrefix(path, prefixLower) {
				continue
			}
			path = strings.TrimPrefix(path, prefixLower)
			path = strings.TrimPrefix(path, "/")
		}
		if path == "" {
			continue
		}
		ext := strings.ToLower(filepath.Ext(path))
		contentLower := strings.ToLower(file.Content)
		if path == "postcss.config.js" || path == "postcss.config.cjs" || path == "postcss.config.mjs" || path == "postcss.config.ts" {
			signals.usesPostCSSConfig = true
			if strings.Contains(contentLower, "tailwindcss") {
				signals.usesPostCSSConfigTailwind = true
			}
			if strings.Contains(contentLower, "autoprefixer") {
				signals.usesPostCSSConfigAutoprefixer = true
			}
		}
		switch ext {
		case ".js", ".jsx", ".ts", ".tsx":
		default:
			continue
		}
		if strings.Contains(file.Content, "import.meta.env") {
			signals.hasImportMetaEnv = true
		}
		if strings.Contains(path, "/__tests__/") || strings.Contains(path, "/tests/") || strings.Contains(path, ".test.") || strings.Contains(path, ".spec.") {
			signals.hasNodeTests = true
		}
		if strings.Contains(contentLower, "@testing-library/react") {
			signals.usesTestingLibrary = true
		}
		if strings.Contains(contentLower, "@testing-library/jest-dom") {
			signals.usesJestDOM = true
		}
		if strings.Contains(contentLower, "@jest/globals") {
			signals.usesJestGlobals = true
		}
		if strings.Contains(contentLower, "vitest/config") {
			signals.usesVitestConfigImport = true
		}
	}
	return signals
}

func patchManifestScriptsJSON(content string, additions map[string]string) (string, []string) {
	if strings.TrimSpace(content) == "" || len(additions) == 0 {
		return content, nil
	}

	var manifest map[string]any
	if err := json.Unmarshal([]byte(content), &manifest); err != nil {
		return content, nil
	}
	if manifest == nil {
		return content, nil
	}

	scripts, _ := manifest["scripts"].(map[string]any)
	if scripts == nil {
		scripts = map[string]any{}
		manifest["scripts"] = scripts
	}

	added := make([]string, 0, len(additions))
	for name, value := range additions {
		name = strings.TrimSpace(name)
		value = strings.TrimSpace(value)
		if name == "" || value == "" {
			continue
		}
		if existing, ok := scripts[name].(string); ok && strings.TrimSpace(existing) != "" {
			continue
		}
		scripts[name] = value
		added = append(added, fmt.Sprintf("%s -> %s", name, value))
	}
	if len(added) == 0 {
		return content, nil
	}

	updated, err := json.MarshalIndent(manifest, "", "  ")
	if err != nil {
		return content, nil
	}
	sort.Strings(added)
	return string(updated), added
}

func patchManifestDependencyVersionsJSON(content string, pkgs []string) (string, []string) {
	if strings.TrimSpace(content) == "" || len(pkgs) == 0 {
		return content, nil
	}

	var manifest map[string]any
	if err := json.Unmarshal([]byte(content), &manifest); err != nil {
		return content, nil
	}
	if manifest == nil {
		return content, nil
	}

	changed := make([]string, 0, len(pkgs))
	for _, sectionName := range []string{"dependencies", "devDependencies"} {
		section, _ := manifest[sectionName].(map[string]any)
		if section == nil {
			continue
		}
		for _, pkg := range pkgs {
			pkg = canonicalGeneratedDependencyName(pkg)
			if pkg == "" {
				continue
			}
			existing, ok := section[pkg]
			if !ok {
				continue
			}
			hint := dependencyVersionHint(pkg)
			if hint == "" || hint == "*" {
				continue
			}
			existingString, _ := existing.(string)
			if strings.TrimSpace(existingString) == hint {
				continue
			}
			section[pkg] = hint
			changed = append(changed, fmt.Sprintf("%s: %s -> %s", sectionName, pkg, hint))
		}
	}

	if len(changed) == 0 {
		return content, nil
	}

	updated, err := json.MarshalIndent(manifest, "", "  ")
	if err != nil {
		return content, nil
	}
	sort.Strings(changed)
	return string(updated), changed
}

func parseInvalidDependencyVersionsFromInstallErrors(errors []string) []string {
	if len(errors) == 0 {
		return nil
	}
	const prefix = "No matching version found for "
	seen := map[string]bool{}
	pkgs := make([]string, 0, len(errors))
	for _, msg := range errors {
		for _, line := range strings.Split(msg, "\n") {
			idx := strings.Index(line, prefix)
			if idx == -1 {
				continue
			}
			rest := strings.TrimSpace(line[idx+len(prefix):])
			if rest == "" {
				continue
			}
			if dot := strings.Index(rest, "."); dot != -1 {
				rest = rest[:dot]
			}
			at := strings.LastIndex(rest, "@")
			if at <= 0 {
				continue
			}
			pkg := canonicalGeneratedDependencyName(strings.TrimSpace(rest[:at]))
			if pkg == "" || seen[pkg] {
				continue
			}
			if dependencyVersionHint(pkg) == "*" {
				continue
			}
			seen[pkg] = true
			pkgs = append(pkgs, pkg)
		}
	}
	sort.Strings(pkgs)
	return pkgs
}

func (am *AgentManager) applyDeterministicInvalidDependencyVersionRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}
	pkgs := parseInvalidDependencyVersionsFromInstallErrors(readinessErrors)
	if len(pkgs) == 0 {
		return nil, ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 {
		return nil, ""
	}

	manifestPaths := generatedManifestCandidates(files)
	if len(manifestPaths) == 0 {
		return nil, ""
	}

	applied := make([]string, 0, len(manifestPaths))
	for _, manifestPath := range manifestPaths {
		content := plan.content(manifestPath)
		if strings.TrimSpace(content) == "" {
			continue
		}
		updated, changed := patchManifestDependencyVersionsJSON(content, pkgs)
		if len(changed) == 0 {
			continue
		}
		if !plan.patchFile(manifestPath, updated, "json") {
			continue
		}
		applied = append(applied, fmt.Sprintf("%s (%s)", manifestPath, strings.Join(changed, ", ")))
	}

	if len(applied) == 0 {
		return nil, ""
	}
	summary := strings.Join(applied, "; ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "manifest_version_repair: "+summary), summary
}

func rewriteManifestScriptsJSON(content string, replacements map[string]string) (string, []string) {
	if strings.TrimSpace(content) == "" || len(replacements) == 0 {
		return content, nil
	}

	var manifest map[string]any
	if err := json.Unmarshal([]byte(content), &manifest); err != nil {
		return content, nil
	}
	if manifest == nil {
		return content, nil
	}

	scripts, _ := manifest["scripts"].(map[string]any)
	if scripts == nil {
		scripts = map[string]any{}
		manifest["scripts"] = scripts
	}

	changed := make([]string, 0, len(replacements))
	for name, value := range replacements {
		name = strings.TrimSpace(name)
		value = strings.TrimSpace(value)
		if name == "" || value == "" {
			continue
		}
		existing, _ := scripts[name].(string)
		if strings.TrimSpace(existing) == value {
			continue
		}
		scripts[name] = value
		changed = append(changed, fmt.Sprintf("%s -> %s", name, value))
	}
	if len(changed) == 0 {
		return content, nil
	}

	updated, err := json.MarshalIndent(manifest, "", "  ")
	if err != nil {
		return content, nil
	}
	sort.Strings(changed)
	return string(updated), changed
}

func generatedTSConfigPathFromManifest(manifestPath string) string {
	sanitized := sanitizeFilePath(manifestPath)
	if sanitized == "" {
		return ""
	}
	prefix := strings.TrimSuffix(filepath.ToSlash(sanitized), "package.json")
	return filepath.ToSlash(filepath.Join(prefix, "tsconfig.json"))
}

func minimalTypeScriptConfigContent(manifest previewManifest, manifestPath string) string {
	frontendLike := manifestUsesVite(manifest) ||
		manifestDeclaresDependency(manifest, "react") ||
		manifestDeclaresDependency(manifest, "react-dom") ||
		manifestDeclaresDependency(manifest, "next") ||
		strings.Contains(strings.ToLower(manifestPath), "frontend/")

	if frontendLike {
		return `{
  "compilerOptions": {
    "target": "ES2020",
    "useDefineForClassFields": true,
    "lib": ["ES2020", "DOM", "DOM.Iterable"],
    "strict": true,
    "module": "ESNext",
    "moduleResolution": "Bundler",
    "jsx": "react-jsx",
    "resolveJsonModule": true,
    "isolatedModules": true,
    "noEmit": true
  },
  "include": ["src"]
}
`
	}

	return `{
  "compilerOptions": {
    "target": "ES2020",
    "module": "CommonJS",
    "moduleResolution": "Node",
    "rootDir": "src",
    "outDir": "dist",
    "esModuleInterop": true,
    "strict": true,
    "skipLibCheck": true
  },
  "include": ["src"]
}
`
}

func (am *AgentManager) ensureGeneratedTypeScriptConfig(plan *generatedFilePatchPlan, manifestPath string, manifest previewManifest) (bool, string) {
	targetPath := generatedTSConfigPathFromManifest(manifestPath)
	if targetPath == "" || !buildScriptUsesTypeScriptCompiler(manifest) {
		return false, ""
	}
	if strings.TrimSpace(plan.content(targetPath)) != "" {
		return false, ""
	}
	content := minimalTypeScriptConfigContent(manifest, manifestPath)
	if !plan.createFile(targetPath, content, "json") {
		return false, ""
	}
	return true, targetPath
}

func generatedPathAliasesInUse(files []GeneratedFile, prefix string) []string {
	if len(files) == 0 {
		return nil
	}

	aliases := make([]string, 0, 2)
	seen := map[string]bool{}
	prefixLower := strings.ToLower(prefix)
	for _, f := range files {
		path := filepath.ToSlash(strings.TrimPrefix(strings.TrimSpace(f.Path), "./"))
		if path == "" || strings.TrimSpace(f.Content) == "" {
			continue
		}
		if prefixLower != "" && !strings.HasPrefix(strings.ToLower(path), prefixLower) {
			continue
		}
		switch strings.ToLower(filepath.Ext(path)) {
		case ".js", ".jsx", ".ts", ".tsx", ".mjs", ".cjs":
		default:
			continue
		}

		for _, match := range generatedImportPathPattern.FindAllStringSubmatch(f.Content, -1) {
			if len(match) != 2 {
				continue
			}
			spec := strings.TrimSpace(match[1])
			alias := ""
			switch {
			case strings.HasPrefix(spec, "@/"):
				alias = "@"
			case strings.HasPrefix(spec, "~/"):
				alias = "~"
			}
			if alias == "" || seen[alias] {
				continue
			}
			seen[alias] = true
			aliases = append(aliases, alias)
		}
	}

	sort.Strings(aliases)
	return aliases
}

func generatedViteConfigPathFromManifest(manifestPath string) string {
	prefix := strings.TrimSuffix(filepath.ToSlash(sanitizeFilePath(manifestPath)), "package.json")
	for _, candidate := range []string{"vite.config.ts", "vite.config.js", "vite.config.mjs", "vite.config.cjs"} {
		return sanitizeFilePath(prefix + candidate)
	}
	return ""
}

func viteConfigDeclaresSrcAlias(content, alias string) bool {
	content = strings.TrimSpace(content)
	alias = strings.TrimSpace(alias)
	if content == "" || alias == "" {
		return false
	}
	pattern := regexp.MustCompile(`(?s)['"]` + regexp.QuoteMeta(alias) + `['"]\s*:\s*(?:path\.resolve\(\s*__dirname\s*,\s*['"]\./src['"]\s*\)|['"](?:\./)?src['"])`)
	return pattern.MatchString(content)
}

func insertAfterLastImportBlock(content, insertion string) string {
	importRe := regexp.MustCompile(`(?m)^import .*?$`)
	matches := importRe.FindAllStringIndex(content, -1)
	if len(matches) == 0 {
		return insertion + "\n" + content
	}
	last := matches[len(matches)-1]
	return content[:last[1]] + "\n" + insertion + content[last[1]:]
}

func patchViteConfigWithSrcAliases(content string, aliases []string) (string, bool) {
	aliases = dedupeStrings(aliases)
	if len(aliases) == 0 {
		return content, false
	}

	trimmed := strings.TrimSpace(content)
	if trimmed == "" {
		return syntheticFrontendViteConfig(0), true
	}

	missing := make([]string, 0, len(aliases))
	for _, alias := range aliases {
		if !viteConfigDeclaresSrcAlias(content, alias) {
			missing = append(missing, alias)
		}
	}
	if len(missing) == 0 {
		return content, false
	}

	updated := content
	changed := false
	if !strings.Contains(updated, `from "path"`) && !strings.Contains(updated, `from 'path'`) {
		updated = insertAfterLastImportBlock(updated, `import path from "path";`)
		changed = true
	}

	aliasEntries := make([]string, 0, len(missing))
	for _, alias := range missing {
		aliasEntries = append(aliasEntries, fmt.Sprintf(`"%s": path.resolve(__dirname, "./src")`, alias))
	}
	entryBlock := strings.Join(aliasEntries, ",\n      ")

	if loc := regexp.MustCompile(`(?s)alias\s*:\s*{`).FindStringIndex(updated); loc != nil {
		updated = updated[:loc[1]] + "\n      " + entryBlock + "," + updated[loc[1]:]
		return updated, true
	}
	if loc := regexp.MustCompile(`(?s)resolve\s*:\s*{`).FindStringIndex(updated); loc != nil {
		updated = updated[:loc[1]] + "\n    alias: {\n      " + entryBlock + ",\n    }," + updated[loc[1]:]
		return updated, true
	}
	if loc := regexp.MustCompile(`defineConfig\s*\(\s*{`).FindStringIndex(updated); loc != nil {
		updated = updated[:loc[1]] + "\n  resolve: {\n    alias: {\n      " + entryBlock + ",\n    },\n  }," + updated[loc[1]:]
		return updated, true
	}
	if loc := regexp.MustCompile(`export\s+default\s*{`).FindStringIndex(updated); loc != nil {
		updated = updated[:loc[1]] + "\n  resolve: {\n    alias: {\n      " + entryBlock + ",\n    },\n  }," + updated[loc[1]:]
		return updated, true
	}

	return updated, changed
}

func patchTSConfigWithSrcAliases(content string, aliases []string) (string, bool) {
	aliases = dedupeStrings(aliases)
	if len(aliases) == 0 || strings.TrimSpace(content) == "" {
		return content, false
	}

	var doc map[string]any
	if err := json.Unmarshal([]byte(content), &doc); err != nil {
		return content, false
	}

	compilerOptions, _ := doc["compilerOptions"].(map[string]any)
	if compilerOptions == nil {
		compilerOptions = map[string]any{}
		doc["compilerOptions"] = compilerOptions
	}

	changed := false
	if strings.TrimSpace(jsonStringValue(compilerOptions["baseUrl"])) == "" {
		compilerOptions["baseUrl"] = "."
		changed = true
	}

	paths, _ := compilerOptions["paths"].(map[string]any)
	if paths == nil {
		paths = map[string]any{}
		compilerOptions["paths"] = paths
	}

	for _, alias := range aliases {
		key := alias + "/*"
		existing, _ := paths[key].([]any)
		if len(existing) == 1 {
			if candidate, ok := existing[0].(string); ok && strings.TrimSpace(candidate) == "src/*" {
				continue
			}
		}
		paths[key] = []any{"src/*"}
		changed = true
	}
	if !changed {
		return content, false
	}

	updated, err := json.MarshalIndent(doc, "", "  ")
	if err != nil {
		return content, false
	}
	return string(updated) + "\n", true
}

func jsonStringValue(value any) string {
	text, _ := value.(string)
	return text
}

func (am *AgentManager) ensureGeneratedFrontendPathAliases(plan *generatedFilePatchPlan, files []GeneratedFile, manifestPath string, manifest previewManifest) (bool, string) {
	aliases := generatedPathAliasesInUse(files, strings.TrimSuffix(filepath.ToSlash(manifestPath), "package.json"))
	if len(aliases) == 0 {
		return false, ""
	}

	summaryParts := make([]string, 0, 2)
	viteConfigPath := generatedViteConfigPathFromManifest(manifestPath)
	if manifestUsesVite(manifest) {
		viteContent := plan.content(viteConfigPath)
		updatedVite, changed := patchViteConfigWithSrcAliases(viteContent, aliases)
		if changed {
			if strings.TrimSpace(viteContent) == "" {
				if plan.createFile(viteConfigPath, updatedVite, "typescript") {
					summaryParts = append(summaryParts, viteConfigPath)
				}
			} else if plan.patchFile(viteConfigPath, updatedVite, "typescript") {
				summaryParts = append(summaryParts, viteConfigPath)
			}
		}
	}

	tsconfigPath := generatedTSConfigPathFromManifest(manifestPath)
	tsconfigContent := plan.content(tsconfigPath)
	if strings.TrimSpace(tsconfigContent) == "" && buildScriptUsesTypeScriptCompiler(manifest) {
		tsconfigContent = minimalTypeScriptConfigContent(manifest, manifestPath)
		if strings.TrimSpace(tsconfigContent) != "" {
			plan.createFile(tsconfigPath, tsconfigContent, "json")
		}
	}
	if strings.TrimSpace(tsconfigContent) != "" {
		if updatedTSConfig, changed := patchTSConfigWithSrcAliases(plan.content(tsconfigPath), aliases); changed {
			if plan.patchFile(tsconfigPath, updatedTSConfig, "json") {
				summaryParts = append(summaryParts, tsconfigPath)
			}
		}
	}

	if len(summaryParts) == 0 {
		return false, ""
	}
	return true, strings.Join(summaryParts, "; ")
}

func generatedServerTSConfigContent() string {
	return `{
  "compilerOptions": {
    "target": "ES2020",
    "module": "NodeNext",
    "moduleResolution": "NodeNext",
    "rootDir": ".",
    "outDir": "../dist/server",
    "esModuleInterop": true,
    "resolveJsonModule": true,
    "strict": true,
    "skipLibCheck": true,
    "types": ["node"]
  },
  "include": ["./**/*.ts"],
  "exclude": ["../src", "../node_modules", "../dist", "../tests", "../**/*.test.ts", "../**/*.spec.ts"]
}
`
}

func generatedFilesContainServerTypeScript(files []GeneratedFile) bool {
	for _, file := range files {
		path := sanitizeFilePath(file.Path)
		if path == "" {
			continue
		}
		if !strings.HasPrefix(path, "server/") {
			continue
		}
		ext := strings.ToLower(filepath.Ext(path))
		if ext == ".ts" || ext == ".tsx" {
			return true
		}
	}
	return false
}

func (am *AgentManager) ensureGeneratedRootBackendTSConfig(plan *generatedFilePatchPlan, files []GeneratedFile, manifestPath string, manifest previewManifest) (bool, string) {
	if sanitizeFilePath(manifestPath) != "package.json" || !generatedFilesContainServerTypeScript(files) {
		return false, ""
	}

	buildServer := strings.TrimSpace(manifest.Scripts["build:server"])
	buildAll := strings.TrimSpace(manifest.Scripts["build"])
	usesRootTSConfig := (strings.Contains(buildServer, "tsc") && strings.Contains(buildServer, "tsconfig.json") && !strings.Contains(buildServer, "server/tsconfig.json")) ||
		(strings.Contains(buildAll, "tsc") && strings.Contains(buildAll, "tsconfig.json") && !strings.Contains(buildAll, "server/tsconfig.json"))
	if !usesRootTSConfig {
		return false, ""
	}

	rootTSConfig := strings.TrimSpace(plan.content("tsconfig.json"))
	if rootTSConfig == "" {
		return false, ""
	}
	rootTSConfigLower := strings.ToLower(rootTSConfig)
	if !strings.Contains(rootTSConfigLower, `"moduleresolution": "bundler"`) || !strings.Contains(rootTSConfigLower, `"server"`) {
		return false, ""
	}

	summaryParts := make([]string, 0, 2)
	if strings.TrimSpace(plan.content("server/tsconfig.json")) == "" {
		if !plan.createFile("server/tsconfig.json", generatedServerTSConfigContent(), "json") {
			return false, ""
		}
		summaryParts = append(summaryParts, "server/tsconfig.json")
	}

	replacements := map[string]string{}
	if strings.Contains(buildServer, "tsconfig.json") && !strings.Contains(buildServer, "server/tsconfig.json") {
		replacements["build:server"] = "tsc -p server/tsconfig.json"
	}
	if strings.TrimSpace(buildServer) == "" && strings.Contains(buildAll, "tsc") && strings.Contains(buildAll, "tsconfig.json") && !strings.Contains(buildAll, "server/tsconfig.json") {
		replacements["build"] = strings.Replace(buildAll, "tsconfig.json", "server/tsconfig.json", 1)
	}
	if len(replacements) > 0 {
		updatedManifest, changed := rewriteManifestScriptsJSON(plan.content(manifestPath), replacements)
		if len(changed) > 0 {
			if !plan.patchFile(manifestPath, updatedManifest, "json") {
				return false, ""
			}
			summaryParts = append(summaryParts, strings.Join(changed, ", "))
		}
	}

	if len(summaryParts) == 0 {
		return false, ""
	}
	return true, strings.Join(summaryParts, "; ")
}

func generatedManifestCandidates(files []GeneratedFile) []string {
	if len(files) == 0 {
		return nil
	}
	candidates := []string{
		"frontend/package.json",
		"client/package.json",
		"web/package.json",
		"apps/web/package.json",
		"apps/frontend/package.json",
		"packages/web/package.json",
		"packages/frontend/package.json",
		"backend/package.json",
		"api/package.json",
		"server/package.json",
		"apps/api/package.json",
		"apps/server/package.json",
		"packages/backend/package.json",
		"packages/api/package.json",
		"package.json",
	}
	existing := map[string]bool{}
	for _, file := range files {
		existing[sanitizeFilePath(file.Path)] = true
	}
	out := make([]string, 0, len(candidates))
	seen := map[string]bool{}
	for _, candidate := range candidates {
		candidate = sanitizeFilePath(candidate)
		if candidate == "" || seen[candidate] || !existing[candidate] {
			continue
		}
		seen[candidate] = true
		out = append(out, candidate)
	}
	return out
}

func (am *AgentManager) applyDeterministicPreValidationNormalization(build *Build) bool {
	if build == nil {
		return false
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 {
		return false
	}

	manifestPaths := generatedManifestCandidates(files)
	if len(manifestPaths) == 0 {
		return false
	}

	summaries := make([]string, 0, len(manifestPaths))
	for _, manifestPath := range manifestPaths {
		content := plan.content(manifestPath)
		if strings.TrimSpace(content) == "" {
			continue
		}

		var manifest previewManifest
		if err := json.Unmarshal([]byte(content), &manifest); err != nil {
			continue
		}
		if manifest.Scripts == nil {
			manifest.Scripts = map[string]string{}
		}

		prefix := strings.TrimSuffix(filepath.ToSlash(manifestPath), "package.json")
		signals := inspectGeneratedPackageSignals(files, prefix)
		manifestChanged := false
		manifestChanges := make([]string, 0, 4)
		missingPkgs := parseMissingDependencyNamesFromIssues(append(
			validatePreviewManifestToolingDependencies(manifest),
			validateGeneratedImportDependencies(files, prefix, manifest)...,
		))
		missingPkgs = appendGeneratedPackageSignalDependencies(missingPkgs, manifest, signals)
		missingPkgs = dedupeStrings(missingPkgs)

		updatedContent := content
		if patched, renamed := normalizeManifestDependencyEntriesJSON(updatedContent); len(renamed) > 0 {
			updatedContent = patched
			manifestChanged = true
			manifestChanges = append(manifestChanges, renamed...)
			if err := json.Unmarshal([]byte(updatedContent), &manifest); err == nil && manifest.Scripts == nil {
				manifest.Scripts = map[string]string{}
			}
			missingPkgs = parseMissingDependencyNamesFromIssues(append(
				validatePreviewManifestToolingDependencies(manifest),
				validateGeneratedImportDependencies(files, prefix, manifest)...,
			))
			missingPkgs = appendGeneratedPackageSignalDependencies(missingPkgs, manifest, signals)
			missingPkgs = dedupeStrings(missingPkgs)
		}

		if len(missingPkgs) > 0 {
			if patched, added := patchManifestDependenciesJSON(updatedContent, missingPkgs); len(added) > 0 {
				updatedContent = patched
				manifestChanged = true
				manifestChanges = append(manifestChanges, "deps: "+strings.Join(added, ", "))
			}
		}
		if manifestUsesVite(manifest) {
			if patched, added := patchManifestScriptsJSON(updatedContent, map[string]string{"preview": "vite preview"}); len(added) > 0 {
				updatedContent = patched
				manifestChanged = true
				manifestChanges = append(manifestChanges, "scripts: "+strings.Join(added, ", "))
			}
		}
		if manifestChanged {
			if !plan.patchFile(manifestPath, updatedContent, "json") {
				continue
			}
			summaries = append(summaries, fmt.Sprintf("%s (%s)", manifestPath, strings.Join(manifestChanges, "; ")))
			if err := json.Unmarshal([]byte(updatedContent), &manifest); err == nil && manifest.Scripts == nil {
				manifest.Scripts = map[string]string{}
			}
		}
		if repaired, summary := am.ensureGeneratedBackendRuntimeScripts(plan, files, manifestPath, manifest); repaired {
			summaries = append(summaries, summary)
			if err := json.Unmarshal([]byte(plan.content(manifestPath)), &manifest); err == nil && manifest.Scripts == nil {
				manifest.Scripts = map[string]string{}
			}
		}

		if signals.hasImportMetaEnv && manifestUsesVite(manifest) {
			if repaired, summary := am.ensureGeneratedViteEnvDeclaration(plan, manifestPath); repaired {
				summaries = append(summaries, summary)
			}
		}
		if repaired, summary := am.ensureGeneratedRootBackendTSConfig(plan, files, manifestPath, manifest); repaired {
			summaries = append(summaries, summary)
			if err := json.Unmarshal([]byte(plan.content(manifestPath)), &manifest); err == nil && manifest.Scripts == nil {
				manifest.Scripts = map[string]string{}
			}
		}
		if repaired, summary := am.ensureGeneratedTypeScriptConfig(plan, manifestPath, manifest); repaired {
			summaries = append(summaries, summary)
		}
		if repaired, summary := am.ensureGeneratedFrontendPathAliases(plan, files, manifestPath, manifest); repaired {
			summaries = append(summaries, summary)
		}
		if repaired, summary := am.ensureGeneratedNodeNextImportExtensions(plan, files, manifestPath); repaired {
			summaries = append(summaries, summary)
		}
	}

	// Tailwind CSS v3 config repair — runs for every build that uses Tailwind,
	// regardless of whether a manifest path was found.
	if _, twSummary := ensureGeneratedTailwindConfig(plan, files); twSummary != "" {
		summaries = append(summaries, twSummary)
	}
	if repaired, summary := normalizeShadcnUIExportsInPatchPlan(plan.files(), plan); repaired {
		summaries = append(summaries, summary)
	}

	if len(summaries) == 0 {
		return false
	}

	summary := strings.Join(dedupeStrings(summaries), "; ")
	bundle := am.bundleFromPatchPlan(build.ID, files, plan, "pre_validation_normalization: "+summary)
	if bundle == nil || !am.applyPatchBundleToBuild(build, bundle) {
		return false
	}

	build.mu.Lock()
	orchestration := ensureBuildOrchestrationStateLocked(build)
	recordPatchBundles := orchestration != nil && orchestration.Flags.EnablePatchBundles
	build.mu.Unlock()
	if recordPatchBundles {
		appendPatchBundle(build, *bundle)
	}

	log.Printf("Build %s: applied deterministic pre-validation normalization (%s)", build.ID, summary)
	return true
}

// applyDeterministicMixedCodeRepair strips server-framework imports (Express, etc.) from
// frontend React component files (.tsx/.jsx). These lines are always wrong in a React file.
func (am *AgentManager) applyDeterministicMixedCodeRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}
	hasMixed := false
	for _, e := range readinessErrors {
		if strings.Contains(e, "mixes frontend") {
			hasMixed = true
			break
		}
	}
	if !hasMixed {
		return nil, ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 {
		return nil, ""
	}

	// Patterns that are never valid in a React .tsx/.jsx file
	backendImportTokens := []string{
		"from 'express'", `from "express"`,
		"require('express')", `require("express")`,
		"from 'fastapi'", `from "fastapi"`,
		"from 'http'", // node:http listen — not axios-style
		"require('http')", `require("http")`,
		"from 'fs'", `from "fs"`,
		"require('fs')", `require("fs")`,
		"from 'path'", `from "path"`,
		"require('path')", `require("path")`,
	}

	applied := false
	var summaries []string
	for _, f := range files {
		ext := strings.ToLower(filepath.Ext(f.Path))
		if ext != ".tsx" && ext != ".jsx" {
			continue
		}
		contentLower := strings.ToLower(f.Content)
		hasBackend := false
		for _, tok := range backendImportTokens {
			if strings.Contains(contentLower, strings.ToLower(tok)) {
				hasBackend = true
				break
			}
		}
		if !hasBackend {
			continue
		}
		// Strip actual backend import statements from frontend files.
		// Skip comment lines — they may reference backend concepts for documentation purposes.
		lines := strings.Split(f.Content, "\n")
		cleaned := lines[:0]
		removed := 0
		for _, line := range lines {
			trimmed := strings.TrimSpace(line)
			// Never strip comment lines — only real import/require statements.
			isComment := strings.HasPrefix(trimmed, "//") || strings.HasPrefix(trimmed, "/*") || strings.HasPrefix(trimmed, "*")
			if isComment {
				cleaned = append(cleaned, line)
				continue
			}
			lineLower := strings.ToLower(trimmed)
			drop := false
			for _, tok := range backendImportTokens {
				if strings.Contains(lineLower, strings.ToLower(tok)) {
					drop = true
					break
				}
			}
			if drop {
				removed++
			} else {
				cleaned = append(cleaned, line)
			}
		}
		if removed == 0 {
			continue
		}
		if !plan.patchFile(f.Path, strings.Join(cleaned, "\n"), am.detectLanguage(f.Path)) {
			continue
		}
		applied = true
		summaries = append(summaries, fmt.Sprintf("%s (removed %d backend import line(s))", f.Path, removed))
	}
	if !applied {
		return nil, ""
	}
	summary := strings.Join(summaries, "; ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "mixed_code_repair: "+summary), summary
}

// applyDeterministicMissingManifestRepair creates missing project manifest files
// (package.json, go.mod, requirements.txt) by scanning the generated source files.
func (am *AgentManager) applyDeterministicMissingManifestRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil || len(readinessErrors) == 0 {
		return nil, ""
	}

	// Check if any error is about a missing manifest.
	hasMissingManifest := false
	for _, e := range readinessErrors {
		if strings.Contains(e, "missing_manifest:") {
			hasMissingManifest = true
			break
		}
	}
	if !hasMissingManifest {
		return nil, ""
	}

	files, plan := am.buildGeneratedFilePatchPlan(build)
	if len(files) == 0 {
		return nil, ""
	}

	// Known package versions for package.json generation.
	knownVersions := map[string]string{
		"express": "^4.18.2", "cors": "^2.8.5", "helmet": "^7.1.0",
		"morgan": "^1.10.0", "body-parser": "^1.20.2", "jsonwebtoken": "^9.0.2",
		"bcryptjs": "^2.4.3", "pg": "^8.11.3", "mongoose": "^8.0.3",
		"zod": "^3.22.4", "axios": "^1.6.2", "dotenv": "^16.3.1",
		"uuid": "^9.0.1", "multer": "^1.4.5-lts.1", "express-validator": "^7.0.1",
		"cookie-parser": "^1.4.6", "socket.io": "^4.6.2",
		"react": "^18.2.0", "react-dom": "^18.2.0", "react-router-dom": "^6.20.1",
		"@tanstack/react-query": "^5.13.4", "next": "^14.0.4",
		"typescript": "^5.3.3", "ts-node": "^10.9.2", "ts-node-dev": "^2.0.0",
		"vite": "^5.0.10", "@vitejs/plugin-react": "^4.2.1",
		"@types/express": "^4.17.21", "@types/node": "^20.10.6",
		"@types/cors": "^2.8.17", "@types/jsonwebtoken": "^9.0.5",
		"@types/bcryptjs": "^2.4.6", "@types/pg": "^8.10.9",
		"@types/morgan": "^1.9.9", "@types/uuid": "^9.0.7",
		"@types/multer": "^1.4.11", "@types/cookie-parser": "^1.4.6",
		"@types/react": "^18.2.45", "@types/react-dom": "^18.2.18",
	}

	// Node built-in modules to skip when scanning imports.
	nodeBuiltins := map[string]bool{
		"fs": true, "path": true, "http": true, "https": true, "os": true,
		"crypto": true, "url": true, "util": true, "events": true, "stream": true,
		"buffer": true, "net": true, "child_process": true, "cluster": true,
		"querystring": true, "readline": true, "zlib": true, "assert": true,
		"process": true, "console": true, "timers": true, "module": true,
	}

	importRe := regexp.MustCompile(`(?m)(?:import\s+(?:type\s+)?(?:[^'";\n]+\s+from\s+)?|require\s*\(\s*)['"]([^'"]+)['"]`)

	var repairSummaries []string

	// --- package.json repair ---
	needsPackageJSON := false
	for _, e := range readinessErrors {
		if strings.Contains(e, "missing_manifest: package.json") {
			needsPackageJSON = true
			break
		}
	}
	if needsPackageJSON {
		deps := map[string]string{}
		devDeps := map[string]string{}
		hasExpress := false
		hasReact := false
		hasNext := false

		for _, f := range files {
			ext := strings.ToLower(filepath.Ext(f.Path))
			if ext != ".ts" && ext != ".tsx" && ext != ".js" && ext != ".jsx" {
				continue
			}
			for _, m := range importRe.FindAllStringSubmatch(f.Content, -1) {
				spec := m[1]
				pkg := packageNameFromImportPath(spec)
				if pkg == "" || nodeBuiltins[pkg] {
					continue
				}
				switch pkg {
				case "express", "express.js":
					hasExpress = true
				case "react":
					hasReact = true
				case "next":
					hasNext = true
				}
				ver := knownVersions[pkg]
				if ver == "" {
					ver = "*"
				}
				if strings.HasPrefix(pkg, "@types/") || pkg == "typescript" || pkg == "vite" ||
					strings.HasPrefix(pkg, "@vitejs/") || pkg == "ts-node" || pkg == "ts-node-dev" {
					devDeps[pkg] = ver
				} else {
					deps[pkg] = ver
				}
			}
		}

		// Always include typescript toolchain in devDeps for TS projects.
		devDeps["typescript"] = knownVersions["typescript"]
		if !hasNext {
			devDeps["@types/node"] = knownVersions["@types/node"]
		}

		// Determine scripts based on project type.
		scripts := map[string]string{}
		if hasNext {
			scripts["dev"] = "next dev"
			scripts["build"] = "next build"
			scripts["start"] = "next start"
		} else if hasExpress {
			scripts["start"] = "ts-node src/server.ts"
			scripts["dev"] = "ts-node-dev --respawn src/server.ts"
			scripts["build"] = "tsc"
		} else if hasReact {
			scripts["dev"] = "vite"
			scripts["build"] = "tsc && vite build"
			scripts["start"] = "vite preview"
		} else {
			scripts["start"] = "ts-node src/index.ts"
			scripts["dev"] = "ts-node-dev --respawn src/index.ts"
			scripts["build"] = "tsc"
		}

		manifest := map[string]any{
			"name":            "app",
			"version":         "1.0.0",
			"private":         true,
			"scripts":         scripts,
			"dependencies":    deps,
			"devDependencies": devDeps,
		}
		content, err := json.MarshalIndent(manifest, "", "  ")
		if err == nil {
			if plan.createFile("package.json", string(content), "json") {
				repairSummaries = append(repairSummaries, "Created missing package.json by scanning TypeScript imports")
			}
		}
	}

	// --- go.mod repair ---
	needsGoMod := false
	for _, e := range readinessErrors {
		if strings.Contains(e, "missing_manifest: go.mod") {
			needsGoMod = true
			break
		}
	}
	if needsGoMod {
		goImportRe := regexp.MustCompile(`(?m)^\s*"(([a-z0-9\-]+\.)+[a-z]{2,}/[^"]+)"`)
		thirdPartyPkgs := map[string]bool{}
		for _, f := range files {
			if strings.ToLower(filepath.Ext(f.Path)) != ".go" {
				continue
			}
			for _, m := range goImportRe.FindAllStringSubmatch(f.Content, -1) {
				pkg := m[1]
				// Skip stdlib (no dots before first /) and test packages.
				if !strings.Contains(strings.Split(pkg, "/")[0], ".") {
					continue
				}
				thirdPartyPkgs[pkg] = true
			}
		}
		var sb strings.Builder
		sb.WriteString("module app\n\ngo 1.23\n")
		if len(thirdPartyPkgs) > 0 {
			sb.WriteString("\nrequire (\n")
			for pkg := range thirdPartyPkgs {
				sb.WriteString(fmt.Sprintf("\t%s v0.0.0\n", pkg))
			}
			sb.WriteString(")\n")
		}
		if plan.createFile("go.mod", sb.String(), "go") {
			repairSummaries = append(repairSummaries, "Created missing go.mod by scanning Go imports")
		}
	}

	// --- requirements.txt repair ---
	needsReqs := false
	for _, e := range readinessErrors {
		if strings.Contains(e, "missing_manifest: requirements.txt") {
			needsReqs = true
			break
		}
	}
	if needsReqs {
		pyVersions := map[string]string{
			"fastapi": "fastapi>=0.104.1", "uvicorn": "uvicorn[standard]>=0.24.0",
			"sqlalchemy": "sqlalchemy>=2.0.23", "alembic": "alembic>=1.13.0",
			"pydantic": "pydantic>=2.5.3", "psycopg2": "psycopg2-binary>=2.9.9",
			"python_jose":      "python-jose[cryptography]>=3.3.0",
			"passlib":          "passlib[bcrypt]>=1.7.4",
			"python_multipart": "python-multipart>=0.0.6",
			"aiofiles":         "aiofiles>=23.2.1",
			"httpx":            "httpx>=0.26.0",
			"requests":         "requests>=2.31.0",
			"flask":            "flask>=3.0.0",
			"django":           "django>=5.0",
			"pymongo":          "pymongo>=4.6.1",
			"redis":            "redis>=5.0.1",
			"celery":           "celery>=5.3.6",
			"boto3":            "boto3>=1.34.0",
			"pandas":           "pandas>=2.1.4",
			"numpy":            "numpy>=1.26.2",
			"pytest":           "pytest>=7.4.3",
		}
		pyImportRe := regexp.MustCompile(`(?m)^(?:import|from)\s+([a-zA-Z0-9_]+)`)
		pkgSet := map[string]bool{}
		for _, f := range files {
			if strings.ToLower(filepath.Ext(f.Path)) != ".py" {
				continue
			}
			for _, m := range pyImportRe.FindAllStringSubmatch(f.Content, -1) {
				mod := strings.ToLower(m[1])
				// Skip stdlib-ish modules.
				stdlibMods := map[string]bool{
					"os": true, "sys": true, "json": true, "re": true, "typing": true,
					"datetime": true, "time": true, "math": true, "random": true,
					"pathlib": true, "io": true, "abc": true, "enum": true,
					"dataclasses": true, "functools": true, "itertools": true,
					"collections": true, "hashlib": true, "hmac": true,
					"base64": true, "uuid": true, "logging": true, "traceback": true,
				}
				if stdlibMods[mod] {
					continue
				}
				pkgSet[mod] = true
			}
		}
		var lines []string
		for mod := range pkgSet {
			if pinned, ok := pyVersions[mod]; ok {
				lines = append(lines, pinned)
			} else {
				lines = append(lines, mod)
			}
		}
		sort.Strings(lines)
		if len(lines) > 0 {
			if plan.createFile("requirements.txt", strings.Join(lines, "\n")+"\n", "text") {
				repairSummaries = append(repairSummaries, "Created missing requirements.txt by scanning Python imports")
			}
		}
	}

	if len(repairSummaries) == 0 {
		return nil, ""
	}
	summary := strings.Join(repairSummaries, "; ")
	return am.bundleFromPatchPlan(build.ID, files, plan, "missing_manifest_repair: "+summary), summary
}

// applyDeterministicMissingDeliverableRepair generates README.md and .env.example
// when they are missing. These files are critical for users to run the generated app.
func (am *AgentManager) applyDeterministicMissingDeliverableRepair(build *Build, readinessErrors []string) (*PatchBundle, string) {
	if build == nil {
		return nil, ""
	}
	needsReadme := false
	needsEnvExample := false
	for _, msg := range readinessErrors {
		if strings.HasPrefix(msg, "missing_deliverable: README") {
			needsReadme = true
		}
		if strings.HasPrefix(msg, "missing_deliverable: .env.example") {
			needsEnvExample = true
		}
	}
	if !needsReadme && !needsEnvExample {
		return nil, ""
	}

	build.mu.RLock()
	stack := build.TechStack
	desc := build.Description
	build.mu.RUnlock()
	existingFiles, plan := am.buildGeneratedFilePatchPlan(build)

	var repairSummaries []string

	// --- Generate README.md ---
	if needsReadme {
		fe, be, db := "", "", ""
		fePort, bePort := 5173, 3001
		if stack != nil {
			fe = stack.Frontend
			be = stack.Backend
			db = stack.Database
			if fe != "" {
				fePort = canonicalFrontendPort(fe)
			}
			if be != "" {
				bePort = canonicalBackendPort(be)
			}
		}

		var sb strings.Builder
		// App name: first sentence of description, or "App"
		appName := "App"
		if idx := strings.IndexAny(desc, ".!?\n"); idx > 0 && idx < 60 {
			appName = strings.TrimSpace(desc[:idx])
		} else if len(desc) > 5 && len(desc) < 60 {
			appName = strings.TrimSpace(desc)
		}

		sb.WriteString(fmt.Sprintf("# %s\n\n", appName))
		sb.WriteString("## Tech Stack\n")
		if fe != "" {
			sb.WriteString(fmt.Sprintf("- Frontend: %s (dev server port %d)\n", fe, fePort))
		}
		if be != "" {
			sb.WriteString(fmt.Sprintf("- Backend: %s (API port %d)\n", be, bePort))
		}
		if db != "" {
			sb.WriteString(fmt.Sprintf("- Database: %s\n", db))
		}

		sb.WriteString("\n## Setup\n\n")

		if be != "" && fe != "" {
			sb.WriteString("### Install Dependencies\n```bash\n")
			sb.WriteString("# Frontend\ncd frontend && npm install\n\n")
			switch strings.ToLower(strings.TrimSpace(be)) {
			case "express", "express.js", "node.js", "node":
				sb.WriteString("# Backend\ncd backend && npm install\n")
			case "go", "golang":
				sb.WriteString("# Backend\ncd backend && go mod download\n")
			case "python", "fastapi":
				sb.WriteString("# Backend\ncd backend && pip install -r requirements.txt\n")
			}
			sb.WriteString("```\n\n")
		} else if fe != "" {
			sb.WriteString("### Install Dependencies\n```bash\nnpm install\n```\n\n")
		} else if be != "" {
			switch strings.ToLower(strings.TrimSpace(be)) {
			case "express", "express.js", "node.js", "node":
				sb.WriteString("### Install Dependencies\n```bash\nnpm install\n```\n\n")
			case "go", "golang":
				sb.WriteString("### Install Dependencies\n```bash\ngo mod download\n```\n\n")
			case "python", "fastapi":
				sb.WriteString("### Install Dependencies\n```bash\npip install -r requirements.txt\n```\n\n")
			}
		}

		sb.WriteString("### Environment Variables\n")
		sb.WriteString("Copy `.env.example` to `.env` and fill in your values:\n```bash\ncp .env.example .env\n```\n\n")

		sb.WriteString("### Run\n```bash\n")
		if be != "" && fe != "" {
			sb.WriteString("# Terminal 1 — Backend\n")
			switch strings.ToLower(strings.TrimSpace(be)) {
			case "express", "express.js", "node.js", "node":
				sb.WriteString("cd backend && npm run dev\n\n")
			case "go", "golang":
				sb.WriteString("cd backend && go run main.go\n\n")
			case "python", "fastapi":
				sb.WriteString("cd backend && uvicorn main:app --reload\n\n")
			}
			sb.WriteString("# Terminal 2 — Frontend\ncd frontend && npm run dev\n")
		} else if fe != "" {
			sb.WriteString("npm run dev\n")
		} else if be != "" {
			switch strings.ToLower(strings.TrimSpace(be)) {
			case "express", "express.js", "node.js", "node":
				sb.WriteString("npm run dev\n")
			case "go", "golang":
				sb.WriteString("go run main.go\n")
			case "python", "fastapi":
				sb.WriteString("uvicorn main:app --reload\n")
			}
		}
		sb.WriteString("```\n\n")

		if fe != "" {
			sb.WriteString(fmt.Sprintf("Open http://localhost:%d\n", fePort))
		}

		if plan.createFile("README.md", sb.String(), "markdown") {
			repairSummaries = append(repairSummaries, "generated README.md")
		}
	}

	// --- Generate .env.example ---
	if needsEnvExample {
		// Scan all generated files for environment variable references.
		envVarSet := map[string]string{}
		processEnvRe := regexp.MustCompile(`process\.env\.([A-Z][A-Z0-9_]+)`)
		osGetenvRe := regexp.MustCompile(`os\.(?:Getenv|environ\.get)\(\s*["']([A-Z][A-Z0-9_]+)["']`)
		viteEnvRe := regexp.MustCompile(`import\.meta\.env\.(VITE_[A-Z][A-Z0-9_]+)`)

		for _, f := range existingFiles {
			for _, m := range processEnvRe.FindAllStringSubmatch(f.Content, -1) {
				envVarSet[m[1]] = ""
			}
			for _, m := range osGetenvRe.FindAllStringSubmatch(f.Content, -1) {
				envVarSet[m[1]] = ""
			}
			for _, m := range viteEnvRe.FindAllStringSubmatch(f.Content, -1) {
				envVarSet[m[1]] = ""
			}
		}

		// Add canonical vars based on stack.
		if stack != nil {
			if stack.Database != "" {
				envVarSet["DATABASE_URL"] = "postgresql://postgres:password@localhost:5432/app"
			}
			if stack.Backend != "" {
				envVarSet["PORT"] = fmt.Sprintf("%d", canonicalBackendPort(stack.Backend))
			}
			if stack.Frontend != "" && stack.Backend != "" {
				envVarSet["VITE_API_URL"] = fmt.Sprintf("http://localhost:%d", canonicalBackendPort(stack.Backend))
			}
		}

		if len(envVarSet) > 0 {
			// Provide sensible example values for known variable names.
			knownExamples := map[string]string{
				"DATABASE_URL":    "postgresql://postgres:password@localhost:5432/app",
				"PORT":            "3001",
				"JWT_SECRET":      "your-secret-key-change-in-production",
				"SECRET_KEY":      "your-secret-key-change-in-production",
				"SECRET":          "your-secret-key-change-in-production",
				"NODE_ENV":        "development",
				"ALLOWED_ORIGINS": "http://localhost:5173",
				"REDIS_URL":       "redis://localhost:6379",
				"MONGO_URI":       "mongodb://localhost:27017/app",
			}

			var envLines []string
			// Sort for deterministic output.
			keys := make([]string, 0, len(envVarSet))
			for k := range envVarSet {
				keys = append(keys, k)
			}
			sort.Strings(keys)
			for _, k := range keys {
				v := envVarSet[k]
				if v == "" {
					if example, ok := knownExamples[k]; ok {
						v = example
					} else if strings.HasSuffix(k, "_URL") {
						v = "http://localhost:3001"
					} else if strings.HasSuffix(k, "_KEY") || strings.HasSuffix(k, "_SECRET") || strings.HasSuffix(k, "_TOKEN") {
						v = "your-value-here"
					} else {
						v = "your-value-here"
					}
				}
				envLines = append(envLines, fmt.Sprintf("%s=%s", k, v))
			}

			if plan.createFile(".env.example", strings.Join(envLines, "\n")+"\n", "dotenv") {
				repairSummaries = append(repairSummaries, "generated .env.example")
			}
		}
	}

	if len(repairSummaries) == 0 {
		return nil, ""
	}
	summary := strings.Join(repairSummaries, "; ")
	return am.bundleFromPatchPlan(build.ID, existingFiles, plan, "deliverable_repair: "+summary), summary
}

func buildRequestsFrontendSurface(build *Build) bool {
	if build == nil {
		return false
	}
	if buildUsesFrontendPreviewOnlyDelivery(build) {
		return true
	}
	if build.TechStack != nil && strings.TrimSpace(build.TechStack.Frontend) != "" {
		return true
	}
	if build.Plan != nil && strings.TrimSpace(build.Plan.TechStack.Frontend) != "" {
		return true
	}
	if restore := build.SnapshotState.RestoreContext; restore != nil && restore.Plan != nil && strings.TrimSpace(restore.Plan.TechStack.Frontend) != "" {
		return true
	}
	return false
}

func generatedFilesContainFrontendPreviewEntrypoint(files []GeneratedFile) bool {
	if len(files) == 0 {
		return false
	}
	candidates := map[string]bool{
		"index.html":        true,
		"public/index.html": true,
		"src/main.tsx":      true,
		"src/main.ts":       true,
		"src/main.jsx":      true,
		"src/main.js":       true,
		"src/index.tsx":     true,
		"src/index.ts":      true,
		"src/index.jsx":     true,
		"src/index.js":      true,
		"app/page.tsx":      true,
		"app/page.jsx":      true,
		"pages/index.tsx":   true,
		"pages/index.jsx":   true,
	}
	for _, file := range files {
		path := sanitizeFilePath(file.Path)
		if path == "" || !candidates[path] {
			continue
		}
		if strings.TrimSpace(file.Content) != "" {
			return true
		}
	}
	return false
}

func generatedBackendFileLooksRunnableServer(path string, content string) bool {
	if strings.TrimSpace(path) == "" || strings.TrimSpace(content) == "" {
		return false
	}
	lowerPath := strings.ToLower(strings.TrimSpace(path))
	lowerContent := strings.ToLower(content)
	switch filepath.Ext(lowerPath) {
	case ".ts", ".js", ".tsx", ".jsx":
		return strings.Contains(lowerContent, "express") ||
			strings.Contains(lowerContent, "fastify") ||
			strings.Contains(lowerContent, "koa") ||
			strings.Contains(lowerContent, "hapi") ||
			strings.Contains(lowerContent, ".listen(") ||
			strings.Contains(lowerContent, "app.listen(") ||
			strings.Contains(lowerContent, "server.listen(")
	case ".go":
		return strings.Contains(lowerContent, "func main(") &&
			(strings.Contains(lowerContent, "listenandserve") || strings.Contains(lowerContent, "net/http"))
	case ".py":
		return strings.Contains(lowerContent, "fastapi") ||
			strings.Contains(lowerContent, "flask") ||
			strings.Contains(lowerContent, "uvicorn.run(") ||
			strings.Contains(lowerContent, "app.run(")
	default:
		return false
	}
}

func detectGeneratedBackendEntryForFrontendShell(files []GeneratedFile) string {
	if len(files) == 0 {
		return ""
	}
	candidates := []string{
		"server/index.ts", "server/index.js",
		"server/main.ts", "server/main.js",
		"server.ts", "server.js",
		"src/server.ts", "src/server.js",
		"src/app.ts", "src/app.js",
		"app.ts", "app.js",
		"index.ts", "index.js",
		"main.go", "main.py", "app.py", "server.py",
	}
	contentByPath := make(map[string]string, len(files))
	for _, file := range files {
		path := sanitizeFilePath(file.Path)
		if path == "" {
			continue
		}
		contentByPath[path] = file.Content
	}
	for _, candidate := range candidates {
		if content, ok := contentByPath[candidate]; ok && generatedBackendFileLooksRunnableServer(candidate, content) {
			return candidate
		}
	}
	for _, file := range files {
		path := sanitizeFilePath(file.Path)
		if path == "" || !pathLooksLikeGeneratedBackendCode(path) {
			continue
		}
		if generatedBackendFileLooksRunnableServer(path, file.Content) {
			return path
		}
	}
	return ""
}

func repairNeedsFrontendShell(readinessErrors []string) bool {
	for _, msg := range readinessErrors {
		lower := strings.ToLower(strings.TrimSpace(msg))
		if strings.Contains(lower, "no recognized frontend entry point found") ||
			strings.Contains(lower, "missing entry point file for this frontend application") {
			return true
		}
	}
	return false
}

func repairNeedsScaffoldReplacement(readinessErrors []string) bool {
	for _, msg := range readinessErrors {
		if strings.Contains(strings.ToLower(msg), "deterministic scaffold placeholder content") {
			return true
		}
	}
	return false
}

func isDeterministicGeneratedPlaceholderModule(path string, content string) bool {
	path = strings.ToLower(strings.TrimSpace(sanitizeFilePath(path)))
	if path == "" || isTestFile(path) {
		return false
	}
	switch strings.ToLower(filepath.Ext(path)) {
	case ".ts", ".tsx", ".js", ".jsx":
	default:
		return false
	}

	lower := strings.ToLower(content)
	if !strings.Contains(lower, "placeholderprops") || !strings.Contains(lower, "record<string, unknown>") {
		return false
	}
	if !strings.Contains(lower, " placeholder") && !strings.Contains(lower, "generatedplaceholder") {
		return false
	}

	return strings.Contains(lower, "border-dashed") ||
		strings.Contains(lower, "generatedplaceholder") ||
		strings.Contains(lower, "react.fc<placeholderprops>") ||
		strings.Contains(lower, "export const ") && strings.Contains(lower, " = generatedplaceholder")
}

func isGeneratedFrontendSkeletonShellModule(path string, content string) bool {
	path = strings.ToLower(strings.TrimSpace(sanitizeFilePath(path)))
	if path == "" || isTestFile(path) {
		return false
	}
	switch strings.ToLower(filepath.Ext(path)) {
	case ".tsx", ".jsx":
	default:
		return false
	}

	lower := strings.ToLower(content)
	pulseCount := strings.Count(lower, "animate-pulse")
	loadingCount := strings.Count(lower, "loading...")
	disabledCount := strings.Count(lower, " disabled") + strings.Count(lower, "aria-disabled") + strings.Count(lower, "disabled={true}")
	hasShellNaming := strings.Contains(lower, "page shells") ||
		strings.Contains(lower, "function dashboardshell") ||
		strings.Contains(lower, "function kanbanshell") ||
		strings.Contains(lower, "function newjobshell") ||
		strings.Contains(lower, "function settingsshell") ||
		strings.Contains(lower, "function notfoundshell")
	hasFormShell := strings.Contains(lower, "building estimate") ||
		strings.Contains(lower, "resetting data") ||
		strings.Contains(lower, "placeholder=\"loading...\"")

	return hasShellNaming && pulseCount >= 1 && (disabledCount >= 3 || loadingCount >= 3 || hasFormShell)
}

func isGeneratedFrontendFuturePatchShellModule(path string, content string) bool {
	path = strings.ToLower(strings.TrimSpace(sanitizeFilePath(path)))
	if path == "" || isTestFile(path) {
		return false
	}
	switch strings.ToLower(filepath.Ext(path)) {
	case ".ts", ".tsx", ".js", ".jsx":
	default:
		return false
	}

	lower := strings.ToLower(content)
	if strings.Contains(lower, "future patches") ||
		strings.Contains(lower, "real ui screens will be routed here") ||
		strings.Contains(lower, "real ui screens will be added") ||
		strings.Contains(lower, "routes will be added later") {
		return true
	}

	return strings.Contains(lower, "<routes") &&
		strings.Contains(lower, "<navigate") &&
		strings.Contains(lower, "appshell") &&
		!strings.Contains(lower, "open jobs") &&
		!strings.Contains(lower, "launch estimate swarm") &&
		!strings.Contains(lower, "pending estimate")
}

func deterministicScaffoldPlaceholderPaths(files []GeneratedFile) []string {
	seen := map[string]bool{}
	paths := make([]string, 0)
	for _, file := range files {
		path := sanitizeFilePath(strings.TrimSpace(file.Path))
		if path == "" || seen[path] || (!isDeterministicGeneratedPlaceholderModule(path, file.Content) && !isGeneratedFrontendSkeletonShellModule(path, file.Content) && !isGeneratedFrontendFuturePatchShellModule(path, file.Content)) {
			continue
		}
		seen[path] = true
		paths = append(paths, path)
	}
	sort.Strings(paths)
	return paths
}

func synthesizedFrontendShellAppName(description string) string {
	desc := strings.TrimSpace(description)
	if desc == "" {
		return "Generated App"
	}
	reCalled := regexp.MustCompile(`(?i)\bcalled\s+([A-Za-z0-9][A-Za-z0-9 _-]{1,48})`)
	if match := reCalled.FindStringSubmatch(desc); len(match) == 2 {
		name := strings.TrimSpace(match[1])
		name = strings.Trim(name, `"'.,;:()[]{} `)
		if name != "" {
			return name
		}
	}
	fields := strings.Fields(desc)
	if len(fields) == 0 {
		return "Generated App"
	}
	if len(fields) > 4 {
		fields = fields[:4]
	}
	name := strings.Join(fields, " ")
	name = strings.Trim(name, `"'.,;:()[]{} `)
	if name == "" {
		return "Generated App"
	}
	return name
}

func synthesizedFrontendShellSummary(description string) string {
	desc := strings.TrimSpace(description)
	if desc == "" {
		return "A preview-ready frontend shell was synthesized because the generated output only contained backend runtime files."
	}
	if len(desc) > 220 {
		desc = strings.TrimSpace(desc[:220]) + "..."
	}
	return desc
}

func syntheticBackendRuntimeCommand(entry string) string {
	entry = sanitizeFilePath(entry)
	if entry == "" {
		return ""
	}
	switch strings.ToLower(filepath.Ext(entry)) {
	case ".ts", ".tsx":
		return "tsx " + entry
	case ".js", ".jsx", ".mjs", ".cjs":
		return "node " + entry
	case ".go":
		dir := filepath.Dir(entry)
		if dir == "." || dir == "" {
			return "go run ."
		}
		return "go run ./" + filepath.ToSlash(dir)
	case ".py":
		return "python3 " + entry
	default:
		return ""
	}
}

func ensureManifestObjectSection(manifest map[string]any, key string) map[string]any {
	if manifest == nil {
		return nil
	}
	if existing, ok := manifest[key].(map[string]any); ok && existing != nil {
		return existing
	}
	section := map[string]any{}
	manifest[key] = section
	return section
}

func pathLooksLikeGeneratedBackendCode(path string) bool {
	path = strings.ToLower(filepath.ToSlash(strings.TrimSpace(path)))
	if path == "" {
		return false
	}
	if strings.HasPrefix(path, "server/") ||
		strings.HasPrefix(path, "api/") ||
		strings.HasPrefix(path, "backend/") ||
		strings.HasPrefix(path, "apps/api/") ||
		strings.HasPrefix(path, "apps/server/") {
		return true
	}
	switch path {
	case "server.ts", "server.js", "app.ts", "app.js", "index.ts", "index.js", "main.go", "main.py", "server.py", "app.py":
		return true
	}
	return strings.Contains(path, "/server.") || strings.Contains(path, "/api.")
}

func patchManifestForSyntheticFrontendShell(content string, backendEntry string) (string, []string, bool) {
	manifest := map[string]any{}
	if strings.TrimSpace(content) != "" {
		if err := json.Unmarshal([]byte(content), &manifest); err != nil {
			return content, nil, false
		}
		if manifest == nil {
			manifest = map[string]any{}
		}
	}

	changes := make([]string, 0, 12)
	if _, ok := manifest["private"]; !ok {
		manifest["private"] = true
		changes = append(changes, "set private=true")
	}
	if name, _ := manifest["name"].(string); strings.TrimSpace(name) == "" {
		manifest["name"] = "apex-build-preview"
		changes = append(changes, `set name="apex-build-preview"`)
	}

	deps := ensureManifestObjectSection(manifest, "dependencies")
	devDeps := ensureManifestObjectSection(manifest, "devDependencies")
	scripts := ensureManifestObjectSection(manifest, "scripts")

	ensureDep := func(section map[string]any, pkg string) {
		if section == nil {
			return
		}
		if _, exists := section[pkg]; exists {
			return
		}
		section[pkg] = dependencyVersionHint(pkg)
		target := "dependencies"
		if dependencyShouldBeDev(pkg) {
			target = "devDependencies"
		}
		changes = append(changes, fmt.Sprintf("added %s to %s", pkg, target))
	}

	for _, pkg := range []string{"react", "react-dom"} {
		ensureDep(deps, pkg)
	}
	for _, pkg := range []string{"typescript", "vite", "@vitejs/plugin-react", "@types/react", "@types/react-dom", "@types/node", "tailwindcss", "postcss", "autoprefixer"} {
		ensureDep(devDeps, pkg)
	}
	for _, pkg := range shadcnCoreDeps() {
		ensureDep(deps, pkg)
	}
	for _, pkg := range shadcnPackageDeps() {
		ensureDep(devDeps, pkg)
	}

	preserveAndSetScript := func(name, desired, preserveAlias string, preserveWhen func(string) bool) {
		existing, _ := scripts[name].(string)
		trimmed := strings.TrimSpace(existing)
		if trimmed != "" && preserveWhen(trimmed) {
			if preserveAlias != "" {
				if alias, _ := scripts[preserveAlias].(string); strings.TrimSpace(alias) == "" {
					scripts[preserveAlias] = trimmed
					changes = append(changes, fmt.Sprintf("preserved %s as %s", name, preserveAlias))
				}
			}
		}
		if trimmed != desired {
			scripts[name] = desired
			changes = append(changes, fmt.Sprintf("set %s=%q", name, desired))
		}
	}

	usesViteScript := func(script string) bool {
		return strings.Contains(strings.ToLower(strings.TrimSpace(script)), "vite")
	}
	preserveAndSetScript("build", "vite build", "build:backend", func(script string) bool {
		return script != "" && !usesViteScript(script)
	})
	preserveAndSetScript("dev", "vite", "dev:backend", func(script string) bool {
		return script != "" && !usesViteScript(script)
	})
	if previewScript, _ := scripts["preview"].(string); strings.TrimSpace(previewScript) == "" {
		scripts["preview"] = "vite preview"
		changes = append(changes, `set preview="vite preview"`)
	}

	backendCmd := syntheticBackendRuntimeCommand(backendEntry)
	if backendCmd != "" {
		switch strings.ToLower(filepath.Ext(backendEntry)) {
		case ".ts", ".tsx":
			ensureDep(devDeps, "tsx")
		}
		if startScript, _ := scripts["start"].(string); strings.TrimSpace(startScript) == "" {
			scripts["start"] = backendCmd
			changes = append(changes, fmt.Sprintf("set start=%q", backendCmd))
		}
		if backendScript, _ := scripts["start:backend"].(string); strings.TrimSpace(backendScript) == "" {
			scripts["start:backend"] = backendCmd
			changes = append(changes, fmt.Sprintf("set start:backend=%q", backendCmd))
		}
	}

	if len(changes) == 0 {
		return content, nil, false
	}
	updated, err := json.MarshalIndent(manifest, "", "  ")
	if err != nil {
		return content, nil, false
	}
	return string(updated), dedupeStrings(changes), true
}

